INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(1, 'javascript', 'JavaScript Fundamentals', 'Web Development', 'beginner', 'JavaScript', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>JavaScript — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">JavaScript</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"js\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">JavaScript</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"js\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"js\">\r\n      <div class=\"topic-item active\" data-topic=\"js-1\"><span class=\"topic-check\"></span>Apa itu JavaScript?</div>\r\n      <div class=\"topic-item\" data-topic=\"js-2\"><span class=\"topic-check\"></span>Variabel & Tipe Data</div>\r\n      <div class=\"topic-item\" data-topic=\"js-3\"><span class=\"topic-check\"></span>Fungsi & Kondisi</div>\r\n      <div class=\"topic-item\" data-topic=\"js-4\"><span class=\"topic-check\"></span>DOM: Mengubah Halaman</div>\r\n      <div class=\"topic-item\" data-topic=\"js-5\"><span class=\"topic-check\"></span>Array & Method</div>\r\n      <div class=\"topic-item\" data-topic=\"js-6\"><span class=\"topic-check\"></span>Object & JSON</div>\r\n      <div class=\"topic-item\" data-topic=\"js-7\"><span class=\"topic-check\"></span>Event & Interaksi</div>\r\n      <div class=\"topic-item\" data-topic=\"js-8\"><span class=\"topic-check\"></span>Async & Fetch</div>\r\n      <div class=\"topic-item\" data-topic=\"js-9\"><span class=\"topic-check\"></span>Module & Import</div>\r\n      <div class=\"topic-item\" data-topic=\"js-10\"><span class=\"topic-check\"></span>Array Destructure & Spread</div>\r\n      <div class=\"topic-item\" data-topic=\"js-11\"><span class=\"topic-check\"></span>Class & Prototype</div>\r\n      <div class=\"topic-item\" data-topic=\"js-12\"><span class=\"topic-check\"></span>Modern ES6+ Recap</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= JAVASCRIPT ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"js\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 01 · BAHASA SISI KLIEN</div>\r\n        <h1 class=\"lang-title\">JavaScript</h1>\r\n        <p class=\"lang-desc\">Bahasa yang membuat halaman web bisa bergerak, merespons klik, dan berubah tanpa harus reload. Ini bahasa yang sama yang menjalankan tombol \"play\" di kartu kode pada modul ini.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">JS</div>\r\n    </div>\r\n\r\n    <!-- JS Topic 1 -->\r\n    <article class=\"topic-section active\" data-topic=\"js-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu JavaScript?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>JavaScript adalah bahasa pemrograman yang berjalan langsung di <strong>browser</strong>. Kalau HTML adalah kerangka halaman dan CSS adalah tampilannya, JavaScript adalah yang membuat halaman itu <strong>bisa berinteraksi</strong> — menanggapi klik, mengisi form, menampilkan notifikasi, atau memuat data baru tanpa reload.</p>\r\n        <p>Kode JavaScript bisa ditulis langsung di dalam file HTML menggunakan tag <code>&lt;script&gt;</code>.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.js</div>\r\n          <button class=\"run-btn\" data-run=\"js1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Halo, LearnBase!\"</span>);\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Calon Developer\"</span>;\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">`Selamat belajar, </span><span class=\"tok-fn\">${nama}</span><span class=\"tok-str\">!`</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js1\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Coba klik \"Jalankan\" di setiap kartu kode pada modul ini untuk melihat simulasi hasilnya — ini membantu kamu membaca alur program sebelum mencobanya di editor sungguhan.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-2\">Lanjut: Variabel & Tipe Data →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 2 -->\r\n    <article class=\"topic-section\" data-topic=\"js-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe Data</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Variabel adalah tempat menyimpan nilai. JavaScript punya tiga cara mendeklarasikan variabel:</p>\r\n        <ul>\r\n          <li><code>let</code> — nilainya boleh diubah lagi nanti</li>\r\n          <li><code>const</code> — nilainya tetap, tidak boleh diubah</li>\r\n          <li><code>var</code> — versi lama, jarang dipakai di kode modern</li>\r\n        </ul>\r\n        <p>Tipe data dasarnya ada <strong>string</strong> (teks), <strong>number</strong> (angka), <strong>boolean</strong> (benar/salah), dan <strong>array</strong> (daftar nilai).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>variabel.js</div>\r\n          <button class=\"run-btn\" data-run=\"js2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">let</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">namaModul</span> = <span class=\"tok-str\">\"JavaScript Dasar\"</span>;\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>;\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">topik</span> = [<span class=\"tok-str\">\"variabel\"</span>, <span class=\"tok-str\">\"fungsi\"</span>, <span class=\"tok-str\">\"DOM\"</span>];\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">namaModul</span>, <span class=\"tok-var\">lulus</span>, <span class=\"tok-var\">topik</span>.<span class=\"tok-var\">length</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js2\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Pakai <code>const</code> sebagai default. Ganti ke <code>let</code> hanya kalau nilainya memang akan berubah — ini kebiasaan yang dipakai di kode JavaScript modern.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Manakah deklarasi yang TIDAK BISA diubah nilainya setelah dibuat?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">let skor = 10;</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">const skor = 10;</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">var skor = 10;</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-3\">Lanjut: Fungsi & Kondisi →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 3 -->\r\n    <article class=\"topic-section\" data-topic=\"js-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & Kondisi</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Fungsi</strong> adalah blok kode yang bisa dipanggil berulang kali. <strong>Kondisi</strong> (<code>if/else</code>) dipakai untuk membuat program mengambil keputusan berdasarkan suatu nilai.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>fungsi.js</div>\r\n          <button class=\"run-btn\" data-run=\"js3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">function</span> <span class=\"tok-fn\">cekProgres</span>(<span class=\"tok-var\">persen</span>) {\r\n  <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">persen</span> === <span class=\"tok-num\">100</span>) {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"Modul selesai! 🎉\"</span>;\r\n  } <span class=\"tok-kw\">else</span> <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">persen</span> >= <span class=\"tok-num\">50</span>) {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"Sudah lewat separuh jalan\"</span>;\r\n  }\r\n  <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"Baru mulai, terus lanjut!\"</span>;\r\n}\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-fn\">cekProgres</span>(<span class=\"tok-num\">75</span>));</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js3\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Pola seperti <code>cekProgres()</code> di atas cocok dipakai untuk menampilkan pesan motivasi otomatis di halaman dashboard LearnBase berdasarkan progres belajar pengguna.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-4\">Lanjut: DOM →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 4 -->\r\n    <article class=\"topic-section\" data-topic=\"js-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">DOM: Mengubah Halaman</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>DOM</strong> (Document Object Model) adalah representasi halaman HTML yang bisa diakses dan diubah lewat JavaScript. Dengan DOM, kita bisa mengganti teks, menambah elemen, atau merespons klik tombol — inilah dasar dari semua interaktivitas di LearnBase, termasuk tombol \"Jalankan\" yang kamu klik di modul ini.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>dom.js</div>\r\n          <button class=\"run-btn\" data-run=\"js4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">tombol</span> = <span class=\"tok-fn\">document</span>.<span class=\"tok-fn\">querySelector</span>(<span class=\"tok-str\">\"#mulaiBelajar\"</span>);\r\n<span class=\"tok-var\">tombol</span>.<span class=\"tok-fn\">addEventListener</span>(<span class=\"tok-str\">\"click\"</span>, () => {\r\n  <span class=\"tok-fn\">document</span>.<span class=\"tok-fn\">querySelector</span>(<span class=\"tok-str\">\"#status\"</span>).<span class=\"tok-var\">textContent</span> = <span class=\"tok-str\">\"Modul dimulai!\"</span>;\r\n});</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (simulasi setelah tombol diklik)</div>\r\n          <div class=\"output-content\" id=\"out-js4\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Method apa yang dipakai untuk mendengarkan event klik pada elemen?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">querySelector()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">addEventListener()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">getElementById()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-5\">Lanjut: Array & Method →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 5 -->\r\n    <article class=\"topic-section\" data-topic=\"js-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Array & Method</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Array</strong> adalah struktur data untuk menyimpan banyak nilai dalam satu variabel. JavaScript punya banyak method bawaan untuk memanipulasi array — seperti <code>push()</code>, <code>map()</code>, <code>filter()</code>, dan <code>reduce()</code>. Method ini membuat kode lebih ringkas dan mudah dibaca.</p>\r\n        <p>Method seperti <code>map()</code> dan <code>filter()</code> termasuk dalam kategori <em>higher-order functions</em> — fungsi yang menerima fungsi lain sebagai argumen. Pola ini sangat umum di kode JS modern.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>array.js</div>\r\n          <button class=\"run-btn\" data-run=\"js5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">angka</span> = [<span class=\"tok-num\">4</span>, <span class=\"tok-num\">9</span>, <span class=\"tok-num\">16</span>, <span class=\"tok-num\">25</span>];\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">akar</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">map</span>(<span class=\"tok-var\">n</span> => <span class=\"tok-fn\">Math</span>.<span class=\"tok-fn\">sqrt</span>(<span class=\"tok-var\">n</span>));\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Akar:\"</span>, <span class=\"tok-var\">akar</span>);\r\n\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">genap</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">filter</span>(<span class=\"tok-var\">n</span> => <span class=\"tok-var\">n</span> % <span class=\"tok-num\">2</span> === <span class=\"tok-num\">0</span>);\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Genap:\"</span>, <span class=\"tok-var\">genap</span>);\r\n\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">total</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">reduce</span>((<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span>) => <span class=\"tok-var\">a</span> + <span class=\"tok-var\">b</span>, <span class=\"tok-num\">0</span>);\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Total:\"</span>, <span class=\"tok-var\">total</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js5\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Method <code>map()</code>, <code>filter()</code>, dan <code>reduce()</code> adalah tiga serangkai method array yang paling sering dipakai di JavaScript modern. Kuasai ketiganya dan kamu sudah menguasai 70% operasi data di JS!</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Method array mana yang dipakai untuk membuat array baru dari hasil transformasi setiap elemen?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">filter()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">map()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">reduce()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-6\">Lanjut: Object & JSON →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 6 -->\r\n    <article class=\"topic-section\" data-topic=\"js-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Object & JSON</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Object</strong> di JavaScript menyimpan data dalam pasangan <em>key-value</em>. Ini mirip dengan kamus — setiap nilai punya label unik. Object sangat berguna untuk merepresentasikan entitas nyata seperti pengguna, produk, atau modul pembelajaran.</p>\r\n        <p><strong>JSON</strong> (JavaScript Object Notation) adalah format data yang diturunkan dari object JavaScript, tapi berupa teks. JSON dipakai untuk mengirim data antara server dan browser — misalnya data profil pengguna atau daftar modul di LearnBase.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>object.js</div>\r\n          <button class=\"run-btn\" data-run=\"js6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">pengguna</span> = {\r\n  <span class=\"tok-var\">nama</span>: <span class=\"tok-str\">\"Budi\"</span>,\r\n  <span class=\"tok-var\">usia</span>: <span class=\"tok-num\">21</span>,\r\n  <span class=\"tok-var\">modulSelesai</span>: [<span class=\"tok-str\">\"HTML\"</span>, <span class=\"tok-str\">\"CSS\"</span>]\r\n};\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">pengguna</span>.<span class=\"tok-var\">nama</span>, <span class=\"tok-str\">\"-\"</span>, <span class=\"tok-var\">pengguna</span>.<span class=\"tok-var\">modulSelesai</span>.<span class=\"tok-var\">length</span> + <span class=\"tok-str\">\" modul\"</span>);\r\n\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">json</span> = <span class=\"tok-fn\">JSON</span>.<span class=\"tok-fn\">stringify</span>(<span class=\"tok-var\">pengguna</span>);\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"JSON:\"</span>, <span class=\"tok-var\">json</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js6\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> JSON adalah format universal — hampir semua bahasa pemrograman punya cara membaca (<em>parse</em>) dan menulis (<em>stringify</em>) JSON. Di JavaScript caranya pakai <code>JSON.parse()</code> dan <code>JSON.stringify()</code>.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-7\">Lanjut: Event & Interaksi →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 7 -->\r\n    <article class=\"topic-section\" data-topic=\"js-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Event & Interaksi</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Event</strong> adalah aksi yang terjadi di halaman web — klik tombol, gerakan mouse, penekanan keyboard, atau pengisian form. JavaScript bisa <em>mendengarkan</em> event-event ini dan menjalankan kode sebagai respons. Inilah inti dari interaktivitas web.</p>\r\n        <p>Dengan <code>addEventListener()</code>, kita bisa memasang banyak pendengar event pada satu elemen, atau menghapusnya saat tidak diperlukan lagi.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>event.js</div>\r\n          <button class=\"run-btn\" data-run=\"js7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">form</span> = <span class=\"tok-fn\">document</span>.<span class=\"tok-fn\">querySelector</span>(<span class=\"tok-str\">\"#formLogin\"</span>);\r\n<span class=\"tok-var\">form</span>.<span class=\"tok-fn\">addEventListener</span>(<span class=\"tok-str\">\"submit\"</span>, (<span class=\"tok-var\">e</span>) => {\r\n  <span class=\"tok-var\">e</span>.<span class=\"tok-fn\">preventDefault</span>();\r\n  <span class=\"tok-kw\">const</span> <span class=\"tok-var\">email</span> = <span class=\"tok-fn\">document</span>.<span class=\"tok-fn\">getElementById</span>(<span class=\"tok-str\">\"email\"</span>).<span class=\"tok-var\">value</span>;\r\n  <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Login dengan:\"</span>, <span class=\"tok-var\">email</span>);\r\n});\r\n\r\n<span class=\"tok-cm\">// event mouse</span>\r\n<span class=\"tok-fn\">document</span>.<span class=\"tok-fn\">querySelector</span>(<span class=\"tok-str\">\"#tombol\"</span>)\r\n  .<span class=\"tok-fn\">addEventListener</span>(<span class=\"tok-str\">\"click\"</span>, () => {\r\n  <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Tombol diklik!\"</span>);\r\n});</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (simulasi setelah event terjadi)</div>\r\n          <div class=\"output-content\" id=\"out-js7\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>e.preventDefault()</code> menghentikan perilaku bawaan browser — sangat berguna saat menangani form agar halaman tidak reload saat data dikirim.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-8\">Lanjut: Async & Fetch →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 8 -->\r\n    <article class=\"topic-section\" data-topic=\"js-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Async & Fetch</h2>\r\n      <div class=\"topic-body\">\r\n        <p>JavaScript bersifat <strong>single-threaded</strong>, tapi bisa menangani operasi yang memakan waktu (seperti mengambil data dari server) tanpa membuat halaman <em>freeze</em>. Ini dilakukan dengan kode <strong>asinkron</strong> menggunakan <code>async/await</code> atau <code>Promise</code>.</p>\r\n        <p><code>fetch()</code> adalah method bawaan untuk meminta data dari server. Hasilnya berupa Promise yang bisa ditunggu dengan <code>await</code>. Di LearnBase, ini dipakai untuk memuat daftar modul atau data progres belajar dari server.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>async.js</div>\r\n          <button class=\"run-btn\" data-run=\"js8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">async</span> <span class=\"tok-kw\">function</span> <span class=\"tok-fn\">ambilModul</span>() {\r\n  <span class=\"tok-kw\">try</span> {\r\n    <span class=\"tok-kw\">const</span> <span class=\"tok-var\">res</span> = <span class=\"tok-kw\">await</span> <span class=\"tok-fn\">fetch</span>(<span class=\"tok-str\">\"/api/modul\"</span>);\r\n    <span class=\"tok-kw\">const</span> <span class=\"tok-var\">data</span> = <span class=\"tok-kw\">await</span> <span class=\"tok-var\">res</span>.<span class=\"tok-fn\">json</span>();\r\n    <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Modul tersedia:\"</span>, <span class=\"tok-var\">data</span>.<span class=\"tok-var\">length</span>);\r\n  } <span class=\"tok-kw\">catch</span> (<span class=\"tok-var\">err</span>) {\r\n    <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">error</span>(<span class=\"tok-str\">\"Gagal memuat:\"</span>, <span class=\"tok-var\">err</span>);\r\n  }\r\n}\r\n<span class=\"tok-fn\">ambilModul</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js8\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Selalu bungkus kode <code>await fetch()</code> dalam <code>try/catch</code>. Koneksi internet bisa terputus kapan saja — <em>error handling</em> yang baik membuat aplikasi tidak tiba-tiba crash.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Kata kunci apa yang dipakai untuk menunggu hasil Promise di JavaScript modern?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">wait()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">await</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">then()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-9\">Lanjut: Module & Import →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"js-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Module & Import</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Modul adalah cara JavaScript modern membagi kode ke dalam file-file terpisah. Dengan <strong>ES Module</strong> (ESM), kamu bisa <code>export</code> fungsi atau variabel dari satu file, lalu <code>import</code> di file lain. Hasilnya kode lebih rapi, mudah diuji, dan bisa dipakai ulang.</p>\r\n        <p>Di LearnBase, tiap fitur besar (daftar modul, progres belajar, login) bisa ditulis di file masing-masing lalu digabung dengan <code>import</code>. Browser modern mendukung ESM lewat atribut <code>type=\"module\"</code> di tag <code>&lt;script&gt;</code>.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>modul.js</div>\r\n          <button class=\"run-btn\" data-run=\"js9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// math.js — export fungsi</span>\r\n<span class=\"tok-kw\">export</span> <span class=\"tok-kw\">function</span> <span class=\"tok-fn\">kali</span>(<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span>) {\r\n  <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> * <span class=\"tok-var\">b</span>;\r\n}\r\n\r\n<span class=\"tok-cm\">// main.js — import & gunakan</span>\r\n<span class=\"tok-kw\">import</span> { <span class=\"tok-var\">kali</span> } <span class=\"tok-kw\">from</span> <span class=\"tok-str\">\"./math.js\"</span>;\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"5 x 7 =\"</span>, <span class=\"tok-fn\">kali</span>(<span class=\"tok-num\">5</span>, <span class=\"tok-num\">7</span>));</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js9\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> ES Module berbeda dengan CommonJS (require/module.exports) yang dipakai di Node.js. Di browser, <code>&lt;script type=\"module\"&gt;</code> diperlukan agar <code>import</code>/<code>export</code> berfungsi.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Kata kunci apa yang dipakai untuk mengambil fungsi dari modul lain?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">require</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">import</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">include</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-10\">Lanjut: Array Destructure & Spread →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"js-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Array Destructure & Spread</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Destructuring</strong> adalah sintaks ES6 untuk membongkar nilai dari array atau object ke variabel terpisah. Alih-alih menulis <code>arr[0]</code>, <code>arr[1]</code> satu per satu, kamu bisa tulis <code>const [a, b] = arr</code> — lebih cepat dan ekspresif.</p>\r\n        <p><strong>Spread operator</strong> (<code>...</code>) menyebarkan (<em>spread</em>) elemen array atau properti object. Spread berguna untuk menggabungkan array, menyalin object, atau mengirim argumen ke fungsi tanpa menulis satu per satu.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>spread.js</div>\r\n          <button class=\"run-btn\" data-run=\"js10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// Destructuring array</span>\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">warna</span> = [<span class=\"tok-str\">\"merah\"</span>, <span class=\"tok-str\">\"hijau\"</span>, <span class=\"tok-str\">\"biru\"</span>];\r\n<span class=\"tok-kw\">const</span> [<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span>, <span class=\"tok-var\">c</span>] = <span class=\"tok-var\">warna</span>;\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span>, <span class=\"tok-var\">c</span>);\r\n\r\n<span class=\"tok-cm\">// Spread array</span>\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">angka1</span> = [<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">3</span>];\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">angka2</span> = [<span class=\"tok-num\">4</span>, <span class=\"tok-num\">5</span>];\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">gabung</span> = [...<span class=\"tok-var\">angka1</span>, ...<span class=\"tok-var\">angka2</span>];\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Gabung:\"</span>, <span class=\"tok-var\">gabung</span>);\r\n\r\n<span class=\"tok-cm\">// Spread object</span>\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">dasar</span> = { <span class=\"tok-var\">nama</span>: <span class=\"tok-str\">\"Budi\"</span> };\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">lengkap</span> = { ...<span class=\"tok-var\">dasar</span>, <span class=\"tok-var\">skor</span>: <span class=\"tok-num\">88</span> };\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">lengkap</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js10\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Spread operator membuat <em>shallow copy</em> — untuk array/object bertingkat, salinan masih merujuk ke referensi yang sama. Gunakan structuredClone() untuk <em>deep copy</em>.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-11\">Lanjut: Class & Prototype →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"js-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Class & Prototype</h2>\r\n      <div class=\"topic-body\">\r\n        <p>JavaScript menggunakan <strong>prototype-based inheritance</strong>, bukan <em>class-based</em> seperti Java atau C++. Setiap objek memiliki properti internal <code>[[Prototype]]</code> yang bisa merujuk ke objek lain — jika sebuah properti tidak ditemukan di objek itu sendiri, JavaScript akan mencarinya ke <em>prototype chain</em>.</p>\r\n        <p>Di ES6, JavaScript memperkenalkan sintaks <code>class</code> yang membuat pola pewarisan ini lebih mirip dengan bahasa OOP tradisional. Namun di balik layar, <code>class</code> tetaplah prototype — sintaksnya saja yang lebih rapi dan mudah dipahami.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>class.js</div>\r\n          <button class=\"run-btn\" data-run=\"js11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// Definisi class (ES6)</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-fn\">Modul</span> {\r\n  <span class=\"tok-fn\">constructor</span>(<span class=\"tok-var\">judul</span>, <span class=\"tok-var\">durasi</span>) {\r\n    <span class=\"tok-kw\">this</span>.<span class=\"tok-var\">judul</span> = <span class=\"tok-var\">judul</span>;\r\n    <span class=\"tok-kw\">this</span>.<span class=\"tok-var\">durasi</span> = <span class=\"tok-var\">durasi</span>;\r\n  }\r\n  <span class=\"tok-fn\">ringkasan</span>() {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-str\">`</span><span class=\"tok-fn\">${this.judul}</span><span class=\"tok-str\"> — </span><span class=\"tok-fn\">${this.durasi}</span><span class=\"tok-str\"> menit`</span>;\r\n  }\r\n}\r\n\r\n<span class=\"tok-cm\">// Pewarisan via extends</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-fn\">ModulVideo</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-fn\">Modul</span> {\r\n  <span class=\"tok-fn\">ringkasan</span>() {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"[Video] \"</span> + <span class=\"tok-kw\">super</span>.<span class=\"tok-fn\">ringkasan</span>();\r\n  }\r\n}\r\n\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">m</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">ModulVideo</span>(<span class=\"tok-str\">\"Class & Prototype\"</span>, <span class=\"tok-num\">30</span>);\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">m</span>.<span class=\"tok-fn\">ringkasan</span>());\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">m</span> <span class=\"tok-kw\">instanceof</span> <span class=\"tok-fn\">Modul</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js11\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Keyword <code>class</code> di ES6 adalah <em>syntactic sugar</em> di atas prototype. Buktinya: <code>typeof Modul</code> tetap menghasilkan <code>\"function\"</code>, bukan <code>\"class\"</code> — karena class di JavaScript sebenarnya adalah function constructor dengan prototype.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Kata kunci apa yang digunakan untuk mewarisi class di JavaScript?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">inherit</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">extends</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">implements</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"js-12\">Lanjut: Modern ES6+ Recap →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- JS Topic 12 (Final) -->\r\n    <article class=\"topic-section\" data-topic=\"js-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Modern ES6+ Recap</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Selamat! Kamu telah menyelesaikan 11 topik JavaScript. Di sesi akhir ini, kita rekap fitur-fitur <strong>ES6+</strong> yang paling sering dipakai di dunia kerja: <code>let/const</code>, arrow function, destructuring, spread/rest, template literal, class, module, Promise, dan async/await.</p>\r\n        <p>Fitur-fitur ini bukan sekadar sintaks baru — mereka mengubah cara kita berpikir tentang kode. <code>const</code> dan <code>let</code> menggantikan <code>var</code> sepenuhnya. Arrow function membuat callback lebih pendek. Template literal membuat penggabungan string tidak lagi merepotkan.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>es6-recap.js</div>\r\n          <button class=\"run-btn\" data-run=\"js12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// Recap: fitur ES6+ dalam satu fungsi</span>\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">buatKartu</span> = (<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">nilai</span>, ...<span class=\"tok-var\">modul</span>) => {\r\n  <span class=\"tok-kw\">return</span> <span class=\"tok-str\">`<strong>${nama}</strong> — ${nilai} poin\r\n  <span class=\"tok-kw\">Modul</span>: ${modul.<span class=\"tok-fn\">join</span>(<span class=\"tok-str\">\", \"</span>)}`</span>;\r\n};\r\n\r\n<span class=\"tok-kw\">const</span> <span class=\"tok-var\">output</span> = <span class=\"tok-fn\">buatKartu</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">92</span>,\r\n  <span class=\"tok-str\">\"JS\"</span>, <span class=\"tok-str\">\"PHP\"</span>, <span class=\"tok-str\">\"Python\"</span>);\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">output</span>);\r\n\r\n<span class=\"tok-cm\">// Destructuring & default parameter</span>\r\n<span class=\"tok-kw\">const</span> { <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">0</span> } = { <span class=\"tok-var\">nama</span>: <span class=\"tok-str\">\"Siti\"</span> };\r\n<span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">`</span><span class=\"tok-fn\">${nama}</span><span class=\"tok-str\">: </span><span class=\"tok-fn\">${skor}</span><span class=\"tok-str\">`</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (console)</div>\r\n          <div class=\"output-content\" id=\"out-js12\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> ES6+ bukan sekadar fitur baru — ini adalah <em>best practice</em> modern. Jika kamu melihat kode JavaScript di GitHub atau di kerja, 90% sudah menggunakan sintaks ES6+. Biasakan menulis <code>const</code>/<code>let</code> dan arrow function sejak sekarang.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword mana yang digunakan untuk mendeklarasikan konstanta di ES6?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">var</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">const</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">let</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"js-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'js\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  // persist: true -> juga kirim ke server (dipakai saat user benar-benar menyelesaikan topik)\r\n  // persist: false -> cuma update UI (dipakai saat memuat progres lama dari server)\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'js-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#6B4FD8', NULL, '2026-07-03 13:09:45', '2026-07-04 19:19:23');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(2, 'php', 'PHP Essentials', 'Server-Side', 'beginner', 'PHP', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>PHP — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">PHP</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"php\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">PHP</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"php\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"php\">\r\n      <div class=\"topic-item active\" data-topic=\"php-1\"><span class=\"topic-check\"></span>Apa itu PHP?</div>\r\n      <div class=\"topic-item\" data-topic=\"php-2\"><span class=\"topic-check\"></span>Variabel & Echo</div>\r\n      <div class=\"topic-item\" data-topic=\"php-3\"><span class=\"topic-check\"></span>Kondisi & Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"php-4\"><span class=\"topic-check\"></span>Form & Superglobal</div>\r\n      <div class=\"topic-item\" data-topic=\"php-5\"><span class=\"topic-check\"></span>Fungsi & Array</div>\r\n      <div class=\"topic-item\" data-topic=\"php-6\"><span class=\"topic-check\"></span>Session & Cookie</div>\r\n      <div class=\"topic-item\" data-topic=\"php-7\"><span class=\"topic-check\"></span>Database MySQL</div>\r\n      <div class=\"topic-item\" data-topic=\"php-8\"><span class=\"topic-check\"></span>File & Upload</div>\r\n      <div class=\"topic-item\" data-topic=\"php-9\"><span class=\"topic-check\"></span>Namespace & Autoload</div>\r\n      <div class=\"topic-item\" data-topic=\"php-10\"><span class=\"topic-check\"></span>Error & Exception</div>\r\n      <div class=\"topic-item\" data-topic=\"php-11\"><span class=\"topic-check\"></span>OOP di PHP</div>\r\n      <div class=\"topic-item\" data-topic=\"php-12\"><span class=\"topic-check\"></span>Keamanan Web</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= PHP ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"php\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 02 · BAHASA SISI SERVER</div>\r\n        <h1 class=\"lang-title\">PHP</h1>\r\n        <p class=\"lang-desc\">Bahasa yang berjalan di server, dipakai untuk mengolah data sebelum dikirim ke browser — cocok untuk fitur login, transaksi modul, dan koneksi ke database di LearnBase.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">PHP</div>\r\n    </div>\r\n\r\n    <!-- PHP Topic 1 -->\r\n    <article class=\"topic-section active\" data-topic=\"php-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu PHP?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP adalah bahasa yang dijalankan di <strong>server</strong>, bukan di browser. Saat pengguna membuka halaman, server menjalankan kode PHP terlebih dahulu, baru hasilnya (berupa HTML) dikirim ke browser. Ini sebabnya PHP cocok untuk hal-hal yang butuh data rahasia atau database, seperti login pengguna atau status pembelian modul.</p>\r\n        <p>File PHP berakhiran <code>.php</code> dan kode PHP ditulis di antara tag <code>&lt;?php ... ?&gt;</code>.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.php</div>\r\n          <button class=\"run-btn\" data-run=\"php1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n  <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"Halo dari server LearnBase!\"</span>;\r\n  <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"&lt;br&gt;Halaman ini dirender oleh PHP.\"</span>;\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php1\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Karena PHP berjalan di server, kode PHP tidak akan pernah terlihat oleh pengguna lewat \"Inspect Element\" — yang mereka lihat hanya HTML hasil akhirnya.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-2\">Lanjut: Variabel & Echo →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 2 -->\r\n    <article class=\"topic-section\" data-topic=\"php-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Echo</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Di PHP, semua nama variabel diawali tanda <code>$</code>. Tidak perlu menulis tipe data — PHP akan menebaknya otomatis. Perintah <code>echo</code> dipakai untuk menampilkan teks ke halaman.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>variabel.php</div>\r\n          <button class=\"run-btn\" data-run=\"php2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n  <span class=\"tok-var\">$namaModul</span> = <span class=\"tok-str\">\"PHP Dasar\"</span>;\r\n  <span class=\"tok-var\">$jumlahPeserta</span> = <span class=\"tok-num\">128</span>;\r\n  <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"Modul: $namaModul, Peserta: $jumlahPeserta\"</span>;\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php2\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Saat nama variabel ditulis langsung di dalam tanda kutip dua (<code>\"...\"</code>), PHP otomatis menggantinya dengan nilainya. Ini disebut <em>string interpolation</em>.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Bagaimana cara menulis nama variabel yang benar di PHP?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">var skor = 10;</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">$skor = 10;</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">skor := 10;</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-3\">Lanjut: Kondisi & Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 3 -->\r\n    <article class=\"topic-section\" data-topic=\"php-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP mendukung <code>if/else</code> seperti bahasa lain, dan perulangan dengan <code>for</code> atau <code>foreach</code> — sangat umum dipakai untuk menampilkan daftar data dari database, misalnya daftar modul yang dimiliki pengguna.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>perulangan.php</div>\r\n          <button class=\"run-btn\" data-run=\"php3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n  <span class=\"tok-var\">$modul</span> = [<span class=\"tok-str\">\"HTML Dasar\"</span>, <span class=\"tok-str\">\"CSS Dasar\"</span>, <span class=\"tok-str\">\"JS Dasar\"</span>];\r\n  <span class=\"tok-kw\">foreach</span> (<span class=\"tok-var\">$modul</span> <span class=\"tok-kw\">as</span> <span class=\"tok-var\">$judul</span>) {\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"- $judul&lt;br&gt;\"</span>;\r\n  }\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php3\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-4\">Lanjut: Form & Superglobal →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 4 -->\r\n    <article class=\"topic-section\" data-topic=\"php-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Form & Superglobal</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP punya variabel khusus yang disebut <strong>superglobal</strong>, seperti <code>$_POST</code> dan <code>$_GET</code>, untuk menangkap data yang dikirim dari form HTML. Ini dasar dari fitur login/sign up di LearnBase: form di frontend mengirim data, lalu PHP di server menerima dan memprosesnya.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>login.php</div>\r\n          <button class=\"run-btn\" data-run=\"php4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n  <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">$_SERVER</span>[<span class=\"tok-str\">\'REQUEST_METHOD\'</span>] === <span class=\"tok-str\">\'POST\'</span>) {\r\n    <span class=\"tok-var\">$email</span> = <span class=\"tok-var\">$_POST</span>[<span class=\"tok-str\">\'email\'</span>];\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"Mencoba login dengan: $email\"</span>;\r\n  }\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (simulasi setelah form dikirim)</div>\r\n          <div class=\"output-content\" id=\"out-php4\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan keamanan:</strong> Pada implementasi nyata di LearnBase, data dari <code>$_POST</code> harus selalu divalidasi dan password harus di-hash (misalnya dengan <code>password_hash()</code>) sebelum disimpan — jangan pernah simpan password apa adanya.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-5\">Lanjut: Fungsi & Array →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 5 -->\r\n    <article class=\"topic-section\" data-topic=\"php-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & Array</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Fungsi</strong> di PHP bisa didefinisikan dengan kata kunci <code>function</code>. Fungsi membantu kamu menulis kode yang bisa dipakai ulang — misalnya untuk memvalidasi input form atau menghitung skor rata-rata pengguna.</p>\r\n        <p><strong>Array</strong> di PHP bisa berupa array numerik (indeks angka) atau array asosiatif (indeks string). <code>foreach</code> adalah cara paling umum untuk menelusuri array — seperti menampilkan daftar modul dari database.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>fungsi_array.php</div>\r\n          <button class=\"run-btn\" data-run=\"php5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-kw\">function</span> <span class=\"tok-fn\">rataNilai</span>(<span class=\"tok-var\">$nilai</span>) {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-fn\">array_sum</span>(<span class=\"tok-var\">$nilai</span>) / <span class=\"tok-fn\">count</span>(<span class=\"tok-var\">$nilai</span>);\r\n}\r\n\r\n<span class=\"tok-var\">$skor</span> = [<span class=\"tok-num\">85</span>, <span class=\"tok-num\">92</span>, <span class=\"tok-num\">78</span>];\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"Rata-rata: \"</span> . <span class=\"tok-fn\">rataNilai</span>(<span class=\"tok-var\">$skor</span>);\r\n\r\n<span class=\"tok-var\">$profil</span> = [<span class=\"tok-str\">\"nama\"</span> => <span class=\"tok-str\">\"Ani\"</span>, <span class=\"tok-str\">\"skor\"</span> => <span class=\"tok-num\">92</span>];\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"&lt;br&gt;{$profil[\'nama\']}: {$profil[\'skor\']}\"</span>;\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php5\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Di PHP, titik (<code>.</code>) dipakai untuk menggabungkan string — berbeda dengan JavaScript yang pakai <code>+</code>. Ini sering disebut <em>string concatenation</em>.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-6\">Lanjut: Session & Cookie →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 6 -->\r\n    <article class=\"topic-section\" data-topic=\"php-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Session & Cookie</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Session</strong> dan <strong>Cookie</strong> adalah cara PHP mengingat data antar halaman — misalnya status login pengguna. Cookie disimpan di browser pengguna, sedangkan session disimpan di server dan hanya ID-nya yang dikirim ke browser.</p>\r\n        <p>Session sangat penting untuk fitur login di LearnBase: setelah pengguna berhasil login, data sesi menyimpan informasi pengguna selama mereka menjelajah halaman.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>session.php</div>\r\n          <button class=\"run-btn\" data-run=\"php6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-fn\">session_start</span>();\r\n\r\n<span class=\"tok-cm\">// menyimpan data login ke session</span>\r\n<span class=\"tok-var\">$_SESSION</span>[<span class=\"tok-str\">\'user_id\'</span>] = <span class=\"tok-num\">42</span>;\r\n<span class=\"tok-var\">$_SESSION</span>[<span class=\"tok-str\">\'role\'</span>] = <span class=\"tok-str\">\'siswa\'</span>;\r\n\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"User ID: \"</span> . <span class=\"tok-var\">$_SESSION</span>[<span class=\"tok-str\">\'user_id\'</span>];\r\n\r\n<span class=\"tok-cm\">// menyimpan cookie yang berlaku 7 hari</span>\r\n<span class=\"tok-fn\">setcookie</span>(<span class=\"tok-str\">\"preferensi_tema\"</span>, <span class=\"tok-str\">\"gelap\"</span>, <span class=\"tok-fn\">time</span>() + <span class=\"tok-num\">604800</span>);\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php6\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan keamanan:</strong> Jangan pernah menyimpan password di session atau cookie. Simpan hanya ID pengguna, dan gunakan <code>session_regenerate_id()</code> setelah login untuk mencegah <em>session fixation</em>.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-7\">Lanjut: Database MySQL →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 7 -->\r\n    <article class=\"topic-section\" data-topic=\"php-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Database MySQL</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP bisa terhubung ke database <strong>MySQL</strong> menggunakan <strong>PDO</strong> (PHP Data Objects) — sebuah antarmuka yang aman dan konsisten untuk berbagai jenis database. PDO mendukung <em>prepared statements</em> yang melindungi dari serangan SQL Injection.</p>\r\n        <p>Koneksi database adalah inti dari fitur penyimpanan data di LearnBase — menyimpan akun pengguna, progres modul, dan nilai kuis.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>database.php</div>\r\n          <button class=\"run-btn\" data-run=\"php7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-var\">$dsn</span> = <span class=\"tok-str\">\"mysql:host=localhost;dbname=learnbase\"</span>;\r\n<span class=\"tok-var\">$db</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">PDO</span>(<span class=\"tok-var\">$dsn</span>, <span class=\"tok-str\">\"root\"</span>, <span class=\"tok-str\">\"\"</span>);\r\n\r\n<span class=\"tok-var\">$stmt</span> = <span class=\"tok-var\">$db</span>-><span class=\"tok-fn\">prepare</span>(\r\n  <span class=\"tok-str\">\"SELECT * FROM modul WHERE tingkat = ?\"</span>\r\n);\r\n<span class=\"tok-var\">$stmt</span>-><span class=\"tok-fn\">execute</span>([<span class=\"tok-str\">\"pemula\"</span>]);\r\n<span class=\"tok-var\">$modul</span> = <span class=\"tok-var\">$stmt</span>-><span class=\"tok-fn\">fetchAll</span>();\r\n\r\n<span class=\"tok-kw\">foreach</span> (<span class=\"tok-var\">$modul</span> <span class=\"tok-kw\">as</span> <span class=\"tok-var\">$m</span>) {\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-var\">$m</span>[<span class=\"tok-str\">\'judul\'</span>] . <span class=\"tok-str\">\"&lt;br&gt;\"</span>;\r\n}\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php7\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Selalu gunakan <em>prepared statements</em> (seperti contoh di atas) saat mengirim data dari pengguna ke database. Ini adalah pertahanan terbaik terhadap SQL Injection.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Ekstensi PHP mana yang paling aman untuk koneksi database?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">mysql_connect()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">PDO</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">mysqli</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-8\">Lanjut: File & Upload →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 8 -->\r\n    <article class=\"topic-section\" data-topic=\"php-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">File & Upload</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP punya fungsi bawaan untuk menangani <strong>unggah file</strong> lewat form HTML. File yang dikirim bisa berupa gambar, dokumen, atau PDF — misalnya foto profil atau tugas siswa. File tersebut akan disimpan di direktori di server.</p>\r\n        <p>Fungsi <code>move_uploaded_file()</code> memindahkan file dari folder sementara ke lokasi permanen. Pastikan untuk selalu memvalidasi tipe dan ukuran file sebelum menyimpannya.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>upload.php</div>\r\n          <button class=\"run-btn\" data-run=\"php8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-kw\">if</span> (<span class=\"tok-var\">$_SERVER</span>[<span class=\"tok-str\">\'REQUEST_METHOD\'</span>] === <span class=\"tok-str\">\'POST\'</span>) {\r\n    <span class=\"tok-var\">$targetDir</span> = <span class=\"tok-str\">\"uploads/\"</span>;\r\n    <span class=\"tok-var\">$file</span> = <span class=\"tok-var\">$_FILES</span>[<span class=\"tok-str\">\'tugas\'</span>];\r\n\r\n    <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">$file</span>[<span class=\"tok-str\">\'size\'</span>] &lt; <span class=\"tok-num\">2000000</span>) {\r\n        <span class=\"tok-fn\">move_uploaded_file</span>(\r\n            <span class=\"tok-var\">$file</span>[<span class=\"tok-str\">\'tmp_name\'</span>],\r\n            <span class=\"tok-var\">$targetDir</span> . <span class=\"tok-fn\">basename</span>(<span class=\"tok-var\">$file</span>[<span class=\"tok-str\">\'name\'</span>])\r\n        );\r\n        <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"File berhasil diunggah!\"</span>;\r\n    }\r\n}\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (simulasi setelah upload)</div>\r\n          <div class=\"output-content\" id=\"out-php8\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan keamanan:</strong> Batasi tipe file yang bisa diunggah (misalnya hanya <code>.jpg</code>, <code>.png</code>, <code>.pdf</code>) dan jangan percaya ekstensi file dari nama asli — periksa juga <code>mime_content_type()</code> untuk memastikan.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-9\">Lanjut: Namespace & Autoload →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"php-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Namespace & Autoload</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Namespace</strong> adalah cara PHP mengelompokkan kode agar tidak terjadi benturan nama antar class atau fungsi — mirip seperti folder di sistem operasi. Dengan namespace, kamu bisa punya dua class <code>User</code> dari bagian aplikasi berbeda tanpa konflik.</p>\r\n        <p><strong>Autoload</strong> (dengan <code>spl_autoload_register()</code>) memuat file class secara otomatis saat class pertama kali dipanggil — tidak perlu menulis <code>require_once</code> satu per satu. Ini adalah fondasi dari framework modern seperti Laravel.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>namespace.php</div>\r\n          <button class=\"run-btn\" data-run=\"php9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-cm\">// Models/User.php</span>\r\n<span class=\"tok-kw\">namespace</span> <span class=\"tok-var\">Models</span>;\r\n\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">User</span> {\r\n    <span class=\"tok-kw\">public function</span> <span class=\"tok-fn\">getNama</span>() {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"Budi dari Models\"</span>;\r\n    }\r\n}\r\n\r\n<span class=\"tok-cm\">// index.php - autoload & panggil</span>\r\n<span class=\"tok-fn\">spl_autoload_register</span>(<span class=\"tok-kw\">function</span>(<span class=\"tok-var\">$class</span>) {\r\n    <span class=\"tok-kw\">require_once</span> <span class=\"tok-str\">__DIR__</span> . <span class=\"tok-str\">\"/\"</span> . <span class=\"tok-fn\">str_replace</span>(<span class=\"tok-str\">\"\\\\\"</span>, <span class=\"tok-str\">\"/\"</span>, <span class=\"tok-var\">$class</span>) . <span class=\"tok-str\">\".php\"</span>;\r\n});\r\n\r\n<span class=\"tok-kw\">use</span> <span class=\"tok-var\">Models</span>\\<span class=\"tok-var\">User</span>;\r\n<span class=\"tok-var\">$user</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-var\">User</span>();\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-var\">$user</span>-><span class=\"tok-fn\">getNama</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>__DIR__</code> adalah konstanta ajaib PHP yang berisi path direktori file saat ini — sangat berguna untuk menentukan lokasi file yang akan di-load.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-10\">Lanjut: Error & Exception →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"php-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Error & Exception</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP punya dua mekanisme penanganan masalah: <strong>error</strong> (kesalahan bawaan PHP, seperti file tidak ditemukan) dan <strong>exception</strong> (kesalahan yang sengaja dilempar kode dengan <code>throw</code>). Dalam PHP modern, error pun bisa ditangani dengan <code>try/catch</code> berkat <em>Error class</em> yang dijadikan <em>Throwable</em>.</p>\r\n        <p>Blok <code>try/catch/finally</code> memungkinkan kamu menangkap kesalahan, menanganinya dengan anggun, dan tetap menjalankan kode pembersihan (di <code>finally</code>) — penting untuk aplikasi seperti LearnBase agar tidak tiba-tiba menampilkan layar putih ke pengguna.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>exception.php</div>\r\n          <button class=\"run-btn\" data-run=\"php10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-kw\">function</span> <span class=\"tok-fn\">bagi</span>(<span class=\"tok-var\">$a</span>, <span class=\"tok-var\">$b</span>) {\r\n    <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">$b</span> == <span class=\"tok-num\">0</span>) {\r\n        <span class=\"tok-kw\">throw new</span> <span class=\"tok-fn\">InvalidArgumentException</span>(<span class=\"tok-str\">\"Pembagi tidak boleh 0!\"</span>);\r\n    }\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-var\">$a</span> / <span class=\"tok-var\">$b</span>;\r\n}\r\n\r\n<span class=\"tok-kw\">try</span> {\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-fn\">bagi</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">0</span>);\r\n} <span class=\"tok-kw\">catch</span> (<span class=\"tok-var\">InvalidArgumentException</span> <span class=\"tok-var\">$e</span>) {\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"Terjadi error: \"</span> . <span class=\"tok-var\">$e</span>-><span class=\"tok-fn\">getMessage</span>();\r\n} <span class=\"tok-kw\">finally</span> {\r\n    <span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"&lt;br&gt;Blok finally selalu dijalankan.\"</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Tangkap exception dari yang paling spesifik ke paling umum. <code>InvalidArgumentException</code> ditangkap dulu sebelum <code>Exception</code> — ini memastikan pesan error yang ditampilkan lebih relevan.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Blok mana yang tetap dijalankan meskipun terjadi exception?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">finally</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">catch</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">throw</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-11\">Lanjut: OOP di PHP →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"php-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">OOP di PHP</h2>\r\n      <div class=\"topic-body\">\r\n        <p>PHP mendukung <strong>OOP (Object-Oriented Programming)</strong> secara penuh — kamu bisa mendefinisikan <strong>class</strong>, membuat <strong>object</strong>, dan menggunakan pilar-pilar OOP seperti <strong>inheritance</strong> (pewarisan), <strong>encapsulation</strong> (pembungkusan data), dan <strong>polymorphism</strong> (banyak bentuk). Class di PHP didefinisikan dengan kata kunci <code>class</code>.</p>\r\n        <p><strong>Constructor</strong> (<code>__construct()</code>) adalah method khusus yang otomatis dipanggil saat object dibuat. <strong>Access modifier</strong> (<code>public</code>, <code>protected</code>, <code>private</code>) mengontrol siapa yang bisa mengakses properti atau method dari luar class.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>oop.php</div>\r\n          <button class=\"run-btn\" data-run=\"php11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18<br>19<br>20<br>21</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Modul</span> {\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-var\">$judul</span>;\r\n    <span class=\"tok-kw\">private</span> <span class=\"tok-var\">$nilai</span>;\r\n\r\n    <span class=\"tok-kw\">public function</span> <span class=\"tok-fn\">__construct</span>(<span class=\"tok-var\">$judul</span>, <span class=\"tok-var\">$nilai</span>) {\r\n        <span class=\"tok-var\">$this</span>-><span class=\"tok-var\">judul</span> = <span class=\"tok-var\">$judul</span>;\r\n        <span class=\"tok-var\">$this</span>-><span class=\"tok-var\">nilai</span> = <span class=\"tok-var\">$nilai</span>;\r\n    }\r\n\r\n    <span class=\"tok-kw\">public function</span> <span class=\"tok-fn\">getNilai</span>() {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-var\">$this</span>-><span class=\"tok-var\">nilai</span>;\r\n    }\r\n}\r\n\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">ModulPremium</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-var\">Modul</span> {\r\n    <span class=\"tok-kw\">public function</span> <span class=\"tok-fn\">getNilai</span>() {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"[PREMIUM] \"</span> . <span class=\"tok-kw\">parent</span>::<span class=\"tok-fn\">getNilai</span>();\r\n    }\r\n}\r\n\r\n<span class=\"tok-var\">$m</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">ModulPremium</span>(<span class=\"tok-str\">\"OOP PHP\"</span>, <span class=\"tok-num\">95</span>);\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-var\">$m</span>-><span class=\"tok-var\">judul</span> . <span class=\"tok-str\">\" - \"</span> . <span class=\"tok-var\">$m</span>-><span class=\"tok-fn\">getNilai</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (hasil render ke browser)</div>\r\n          <div class=\"output-content\" id=\"out-php11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Gunakan <code>parent::</code> untuk memanggil method milik class induk dari dalam class anak. Ini sering dipakai saat metode anak ingin menambahkan perilaku baru tanpa mengulang seluruh logika induk.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Kata kunci apa yang digunakan untuk mewarisi class?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">implements</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">extends</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">inherit</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"php-12\">Lanjut: Keamanan Web →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PHP Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"php-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Keamanan Web</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Keamanan adalah aspek krusial dalam pengembangan web. PHP memiliki banyak fitur bawaan untuk melindungi aplikasi dari serangan umum seperti <strong>SQL Injection</strong>, <strong>XSS (Cross-Site Scripting)</strong>, dan <strong>CSRF (Cross-Site Request Forgery)</strong>. Memahami dasar-dasar ini penting sebelum meluncurkan aplikasi seperti LearnBase ke publik.</p>\r\n        <p>Prinsip utamanya: jangan pernah percaya input dari pengguna. Selalu validasi, sanitasi, dan gunakan fungsi keamanan bawaan PHP.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>keamanan.php</div>\r\n          <button class=\"run-btn\" data-run=\"php12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18<br>19</div>\r\n          <div class=\"code-content\"><span class=\"tok-php\">&lt;?php</span>\r\n<span class=\"tok-cm\">// 1. Cegah SQL Injection — pakai prepared statement</span>\r\n<span class=\"tok-var\">$stmt</span> = <span class=\"tok-var\">$db</span>-><span class=\"tok-fn\">prepare</span>(<span class=\"tok-str\">\"SELECT * FROM users WHERE email = ?\"</span>);\r\n<span class=\"tok-var\">$stmt</span>-><span class=\"tok-fn\">execute</span>([<span class=\"tok-var\">$_POST</span>[<span class=\"tok-str\">\'email\'</span>]]);\r\n\r\n<span class=\"tok-cm\">// 2. Cegah XSS — escape output ke HTML</span>\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-fn\">htmlspecialchars</span>(<span class=\"tok-var\">$nama</span>, <span class=\"tok-no\">ENT_QUOTES</span>, <span class=\"tok-str\">\'UTF-8\'</span>);\r\n\r\n<span class=\"tok-cm\">// 3. Hash password — jangan simpan plain text!</span>\r\n<span class=\"tok-var\">$hash</span> = <span class=\"tok-fn\">password_hash</span>(<span class=\"tok-var\">$_POST</span>[<span class=\"tok-str\">\'password\'</span>], <span class=\"tok-no\">PASSWORD_BCRYPT</span>);\r\n\r\n<span class=\"tok-cm\">// 4. Token CSRF untuk form</span>\r\n<span class=\"tok-var\">$_SESSION</span>[<span class=\"tok-str\">\'csrf_token\'</span>] = <span class=\"tok-fn\">bin2hex</span>(<span class=\"tok-fn\">random_bytes</span>(<span class=\"tok-num\">32</span>));\r\n<span class=\"tok-fn\">echo</span> <span class=\"tok-str\">\"&lt;input type=\'hidden\' name=\'csrf\' value=\'{$_SESSION[\'csrf_token\']}\'&gt;\"</span>;\r\n<span class=\"tok-php\">?&gt;</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (tidak ada output — kode pertahanan)</div>\r\n          <div class=\"output-content\" id=\"out-php12\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan penting:</strong> Untuk aplikasi nyata di LearnBase, selalu aktifkan HTTPS, atur <code>secure</code> dan <code>httponly</code> pada cookie, serta gunakan Content Security Policy (CSP) di header HTTP. Keamanan adalah proses berkelanjutan, bukan fitur satu kali.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"php-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'php\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'php-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#264DE4', NULL, '2026-07-03 13:09:45', '2026-07-04 16:43:56');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(3, 'python', 'Python Programming', 'General Purpose', 'beginner', 'Python', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>Python — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">Python</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"py\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">Python</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"py\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"py\">\r\n      <div class=\"topic-item active\" data-topic=\"py-1\"><span class=\"topic-check\"></span>Apa itu Python?</div>\r\n      <div class=\"topic-item\" data-topic=\"py-2\"><span class=\"topic-check\"></span>Variabel & Tipe Data</div>\r\n      <div class=\"topic-item\" data-topic=\"py-3\"><span class=\"topic-check\"></span>Kondisi & Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"py-4\"><span class=\"topic-check\"></span>Fungsi & List</div>\r\n      <div class=\"topic-item\" data-topic=\"py-5\"><span class=\"topic-check\"></span>Dictionary & Tuple</div>\r\n      <div class=\"topic-item\" data-topic=\"py-6\"><span class=\"topic-check\"></span>String & Formatting</div>\r\n      <div class=\"topic-item\" data-topic=\"py-7\"><span class=\"topic-check\"></span>File I/O</div>\r\n      <div class=\"topic-item\" data-topic=\"py-8\"><span class=\"topic-check\"></span>Module & Library</div>\r\n      <div class=\"topic-item\" data-topic=\"py-9\"><span class=\"topic-check\"></span>Exception Handling</div>\r\n      <div class=\"topic-item\" data-topic=\"py-10\"><span class=\"topic-check\"></span>List Comprehension</div>\r\n      <div class=\"topic-item\" data-topic=\"py-11\"><span class=\"topic-check\"></span>pip & Virtual Env</div>\r\n      <div class=\"topic-item\" data-topic=\"py-12\"><span class=\"topic-check\"></span>Pengenalan OOP</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= PYTHON ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"py\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 03 · BAHASA UMUM & DATA</div>\r\n        <h1 class=\"lang-title\">Python</h1>\r\n        <p class=\"lang-desc\">Bahasa yang mudah dibaca, sering dipakai untuk mengolah data, membuat skrip otomatisasi, atau membangun API backend untuk platform seperti LearnBase.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">PY</div>\r\n    </div>\r\n\r\n    <!-- PY Topic 1 -->\r\n    <article class=\"topic-section active\" data-topic=\"py-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu Python?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Python dikenal karena sintaksnya yang bersih dan mudah dibaca — tidak ada kurung kurawal <code>{}</code>, cukup <strong>indentasi (spasi)</strong> untuk menandai blok kode. Python populer untuk data science, automasi, dan backend web (misalnya lewat framework Flask atau Django).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.py</div>\r\n          <button class=\"run-btn\" data-run=\"py1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Halo, LearnBase!\"</span>)\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Python siap mengolah data pembelajaranmu.\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py1\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Tidak ada titik koma di akhir baris Python — barisnya berakhir begitu saja di akhir baris, bukan dengan tanda baca seperti JavaScript atau PHP.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-2\">Lanjut: Variabel & Tipe Data →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 2 -->\r\n    <article class=\"topic-section\" data-topic=\"py-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe Data</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Variabel di Python dibuat langsung tanpa kata kunci khusus — cukup tulis nama dan nilainya. Tipe data dasarnya: <strong>str</strong> (teks), <strong>int</strong>/<strong>float</strong> (angka), <strong>bool</strong> (benar/salah), dan <strong>list</strong> (daftar nilai, ditulis dengan <code>[]</code>).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>variabel.py</div>\r\n          <button class=\"run-btn\" data-run=\"py2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">nama_modul</span> = <span class=\"tok-str\">\"Python Dasar\"</span>\r\n<span class=\"tok-var\">skor</span> = <span class=\"tok-num\">92</span>\r\n<span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-var\">nama_modul</span>, <span class=\"tok-str\">\"-\"</span>, <span class=\"tok-var\">lulus</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py2\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Apa yang menandai sebuah blok kode di Python (pengganti kurung kurawal)?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Titik koma ;</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Indentasi (spasi di awal baris)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Tanda kurung ()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-3\">Lanjut: Kondisi & Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 3 -->\r\n    <article class=\"topic-section\" data-topic=\"py-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Sama seperti bahasa lain, Python punya <code>if/elif/else</code> untuk kondisi, dan <code>for</code> untuk perulangan — biasanya dipakai untuk menelusuri list, misalnya daftar nilai siswa di LearnBase.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>perulangan.py</div>\r\n          <button class=\"run-btn\" data-run=\"py3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">nilai_siswa</span> = [<span class=\"tok-num\">88</span>, <span class=\"tok-num\">72</span>, <span class=\"tok-num\">95</span>]\r\n<span class=\"tok-kw\">for</span> <span class=\"tok-var\">nilai</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">nilai_siswa</span>:\r\n    <span class=\"tok-kw\">if</span> <span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">80</span>:\r\n        <span class=\"tok-fn\">print</span>(<span class=\"tok-var\">nilai</span>, <span class=\"tok-str\">\"- Sangat Baik\"</span>)\r\n    <span class=\"tok-kw\">else</span>: <span class=\"tok-fn\">print</span>(<span class=\"tok-var\">nilai</span>, <span class=\"tok-str\">\"- Cukup\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py3\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-4\">Lanjut: Fungsi & List →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 4 -->\r\n    <article class=\"topic-section\" data-topic=\"py-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & List</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Fungsi di Python dibuat dengan kata kunci <code>def</code>. Fungsi memudahkan kita menulis ulang logika yang sama — misalnya menghitung rata-rata nilai modul yang sudah diselesaikan pengguna.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>fungsi.py</div>\r\n          <button class=\"run-btn\" data-run=\"py4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">def</span> <span class=\"tok-fn\">rata_rata</span>(<span class=\"tok-var\">nilai</span>):\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-fn\">sum</span>(<span class=\"tok-var\">nilai</span>) / <span class=\"tok-fn\">len</span>(<span class=\"tok-var\">nilai</span>)\r\n\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-fn\">rata_rata</span>([<span class=\"tok-num\">88</span>, <span class=\"tok-num\">72</span>, <span class=\"tok-num\">95</span>]))</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py4\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Selamat, kamu sudah menyelesaikan dasar Python! Langkah berikutnya: coba gabungkan Python di backend untuk fitur nyata di LearnBase seperti sistem login atau pelacak progres modul.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-5\">Lanjut: Dictionary & Tuple →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 5 -->\r\n    <article class=\"topic-section\" data-topic=\"py-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Dictionary & Tuple</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Dictionary</strong> (<code>dict</code>) menyimpan data dalam pasangan <em>key-value</em>, mirip object di JavaScript. Sangat berguna untuk data terstruktur seperti profil pengguna. <strong>Tuple</strong> (<code>tuple</code>) mirip list tapi tidak bisa diubah (<em>immutable</em>) — cocok untuk data yang nilainya tetap.</p>\r\n        <p>Dictionary dan tuple sering dipakai bersama: tuple sebagai kunci dictionary, atau dictionary yang berisi tuple sebagai nilai.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>dict.py</div>\r\n          <button class=\"run-btn\" data-run=\"py5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">pengguna</span> = {\r\n    <span class=\"tok-str\">\"nama\"</span>: <span class=\"tok-str\">\"Citra\"</span>,\r\n    <span class=\"tok-str\">\"modul\"</span>: [<span class=\"tok-str\">\"HTML\"</span>, <span class=\"tok-str\">\"CSS\"</span>, <span class=\"tok-str\">\"JS\"</span>]\r\n}\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Nama: {pengguna[\'nama\']}\"</span>)\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Modul: {len(pengguna[\'modul\'])} buah\"</span>)\r\n\r\n<span class=\"tok-var\">koordinat</span> = (<span class=\"tok-num\">10</span>, <span class=\"tok-num\">20</span>)\r\n<span class=\"tok-var\">x</span>, <span class=\"tok-var\">y</span> = <span class=\"tok-var\">koordinat</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"x={x}, y={y}\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py5\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <em>Tuple unpacking</em> seperti <code>x, y = koordinat</code> adalah fitur keren Python yang membuat kode lebih ringkas. Bisa dipakai juga untuk menukar dua nilai: <code>a, b = b, a</code>!</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-6\">Lanjut: String & Formatting →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 6 -->\r\n    <article class=\"topic-section\" data-topic=\"py-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">String & Formatting</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Python punya banyak method bawaan untuk memanipulasi <strong>string</strong> — seperti <code>.upper()</code>, <code>.split()</code>, <code>.strip()</code>, dan <code>.replace()</code>. <strong>Formatting</strong> string bisa dilakukan dengan <em>f-strings</em> (ditandai huruf <code>f</code> sebelum kutip) — cara modern dan paling disarankan sejak Python 3.6.</p>\r\n        <p>Pemrosesan string sangat penting dalam automasi — membaca data dari file teks, memformat output, atau membersihkan input pengguna.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>string.py</div>\r\n          <button class=\"run-btn\" data-run=\"py6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">teks</span> = <span class=\"tok-str\">\"  halo, LearnBase!  \"</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-var\">teks</span>.<span class=\"tok-fn\">strip</span>().<span class=\"tok-fn\">upper</span>())\r\n\r\n<span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Budi\"</span>\r\n<span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"</span><span class=\"tok-var\">{nama}</span><span class=\"tok-str\"> mendapat skor </span><span class=\"tok-var\">{skor}</span><span class=\"tok-str\">\"</span>)\r\n\r\n<span class=\"tok-var\">kata</span> = <span class=\"tok-str\">\"python,js,php\"</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-var\">kata</span>.<span class=\"tok-fn\">split</span>(<span class=\"tok-str\">\",\"</span>))</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py6\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> String di Python bersifat <em>immutable</em> — method seperti <code>.upper()</code> atau <code>.strip()</code> tidak mengubah string asli, tapi mengembalikan string baru. Ini penting untuk diingat supaya tidak bingung saat hasilnya tidak seperti yang diharapkan.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Cara Python modern untuk memformat string adalah...</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">%s % nama</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">nama.format()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">f-string</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-7\">Lanjut: File I/O →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 7 -->\r\n    <article class=\"topic-section\" data-topic=\"py-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">File I/O</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Python bisa membaca dan menulis file dengan fungsi <code>open()</code>. Gunakan <em>context manager</em> (<code>with</code>) untuk memastikan file tertutup otomatis setelah selesai — ini praktik terbaik yang mencegah kebocoran memori.</p>\r\n        <p>File bisa dibaca sebagai teks atau biner, baris per baris, atau langsung seluruhnya. Mode yang umum: <code>\"r\"</code> (baca), <code>\"w\"</code> (tulis), <code>\"a\"</code> (tambah), dan <code>\"rb\"/\"wb\"</code> (biner).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>file.py</div>\r\n          <button class=\"run-btn\" data-run=\"py7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\"># Menulis file</span>\r\n<span class=\"tok-kw\">with</span> <span class=\"tok-fn\">open</span>(<span class=\"tok-str\">\"progres.txt\"</span>, <span class=\"tok-str\">\"w\"</span>) <span class=\"tok-kw\">as</span> <span class=\"tok-var\">f</span>:\r\n    <span class=\"tok-var\">f</span>.<span class=\"tok-fn\">write</span>(<span class=\"tok-str\">\"Modul JS: 75%\\n\"</span>)\r\n    <span class=\"tok-var\">f</span>.<span class=\"tok-fn\">write</span>(<span class=\"tok-str\">\"Modul PHP: 50%\"</span>)\r\n\r\n<span class=\"tok-cm\"># Membaca file</span>\r\n<span class=\"tok-kw\">with</span> <span class=\"tok-fn\">open</span>(<span class=\"tok-str\">\"progres.txt\"</span>, <span class=\"tok-str\">\"r\"</span>) <span class=\"tok-kw\">as</span> <span class=\"tok-var\">f</span>:\r\n    <span class=\"tok-kw\">for</span> <span class=\"tok-var\">baris</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">f</span>:\r\n        <span class=\"tok-fn\">print</span>(<span class=\"tok-var\">baris</span>.<span class=\"tok-fn\">strip</span>())</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py7\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Keyword <code>with</code> otomatis memanggil <code>f.close()</code> saat blok selesai — bahkan jika terjadi error. Ini adalah <em>context manager</em>, salah satu fitur Python yang paling sering dipakai dan paling elegan.</div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-8\">Lanjut: Module & Library →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 8 -->\r\n    <article class=\"topic-section\" data-topic=\"py-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Module & Library</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Salah satu kekuatan Python adalah ekosistem <strong>module</strong> dan <strong>library</strong>-nya. Module adalah file <code>.py</code> yang berisi fungsi siap pakai. Library adalah kumpulan module. Python punya <em>standard library</em> yang sangat kaya — cukup pakai <code>import</code> untuk menggunakannya.</p>\r\n        <p>Untuk library eksternal (seperti <code>requests</code> untuk HTTP atau <code>flask</code> untuk web), gunakan <code>pip install nama_library</code>. Di LearnBase, library seperti Flask bisa dipakai untuk membangun API backend.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>module.py</div>\r\n          <button class=\"run-btn\" data-run=\"py8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\"># Module bawaan Python</span>\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-var\">math</span>\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"π = {math.pi:.2f}\"</span>)\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Akar 144 = {math.sqrt(144)}\"</span>)\r\n\r\n<span class=\"tok-cm\"># Module tanggal dan waktu</span>\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-var\">datetime</span>\r\n<span class=\"tok-var\">hariIni</span> = <span class=\"tok-var\">datetime</span>.<span class=\"tok-var\">datetime</span>.<span class=\"tok-fn\">now</span>()\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Hari ini: {hariIni:%d-%m-%Y}\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py8\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Gunakan <code>pip list</code> untuk melihat library yang terinstall, dan <code>pip freeze > requirements.txt</code> untuk menyimpan daftar dependensi proyek — praktik standar di semua proyek Python profesional.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Perintah apa untuk menginstall library eksternal di Python?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">python install</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">pip install</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">npm install</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-9\">Lanjut: Exception Handling →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"py-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Exception Handling</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Error atau <strong>exception</strong> di Python ditangani dengan blok <code>try</code> / <code>except</code>. Ketika kode di dalam <code>try</code> mengalami error, eksekusi langsung loncat ke blok <code>except</code> — program tidak berhenti mendadak, dan kamu bisa memberi pesan yang informatif ke pengguna.</p>\r\n        <p>Python juga punya blok <code>else</code> (dijalankan kalau tidak ada error) dan <code>finally</code> (selalu dijalankan, cocok untuk pembersihan seperti menutup file).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>exception.py</div>\r\n          <button class=\"run-btn\" data-run=\"py9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">try</span>:\r\n    <span class=\"tok-var\">skor</span> = <span class=\"tok-fn\">int</span>(<span class=\"tok-fn\">input</span>(<span class=\"tok-str\">\"Masukkan skor: \"</span>))\r\n    <span class=\"tok-kw\">if</span> <span class=\"tok-var\">skor</span> &lt; <span class=\"tok-num\">0</span>:\r\n        <span class=\"tok-kw\">raise</span> <span class=\"tok-fn\">ValueError</span>(<span class=\"tok-str\">\"Skor tidak boleh negatif\"</span>)\r\n    <span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Skor valid: {skor}\"</span>)\r\n<span class=\"tok-kw\">except</span> <span class=\"tok-var\">ValueError</span> <span class=\"tok-kw\">as</span> <span class=\"tok-var\">e</span>:\r\n    <span class=\"tok-fn\">print</span>(<span class=\"tok-str\">f\"Error: {e}\"</span>)\r\n<span class=\"tok-kw\">except</span> <span class=\"tok-var\">Exception</span> <span class=\"tok-kw\">as</span> <span class=\"tok-var\">e</span>:\r\n    <span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Terjadi error tak terduga:\"</span>, <span class=\"tok-var\">e</span>)\r\n<span class=\"tok-kw\">finally</span>:\r\n    <span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Pemeriksaan skor selesai.\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py9\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Jangan menangkap semua exception dengan <code>except:</code> tanpa menyebut tipe errornya. Selalu tangkap exception spesifik (<code>ValueError</code>, <code>FileNotFoundError</code>, dll) agar bug tersembunyi tidak luput.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Blok mana di Python yang <em>selalu</em> dijalankan baik ada error maupun tidak?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">except</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">else</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">finally</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-10\">Lanjut: List Comprehension →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"py-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">List Comprehension</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>List comprehension</strong> adalah cara ringkas untuk membuat list baru dari iterable yang sudah ada — dalam satu baris kode. Ini adalah fitur Python yang sangat populer karena membuat kode lebih bersih tanpa <code>for</code> panjang.</p>\r\n        <p>Pola dasarnya: <code>[ekspresi for item in iterable if kondisi]</code>. Kamu bisa menyaring, memetakan, dan bahkan membuat nested comprehension.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>comprehension.py</div>\r\n          <button class=\"run-btn\" data-run=\"py10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">angka</span> = [<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">3</span>, <span class=\"tok-num\">4</span>, <span class=\"tok-num\">5</span>, <span class=\"tok-num\">6</span>]\r\n\r\n<span class=\"tok-cm\"># Kuadrat setiap bilangan genap</span>\r\n<span class=\"tok-var\">genap_kuadrat</span> = [<span class=\"tok-var\">n</span>**<span class=\"tok-num\">2</span> <span class=\"tok-kw\">for</span> <span class=\"tok-var\">n</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">angka</span> <span class=\"tok-kw\">if</span> <span class=\"tok-var\">n</span> % <span class=\"tok-num\">2</span> == <span class=\"tok-num\">0</span>]\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Genap kuadrat:\"</span>, <span class=\"tok-var\">genap_kuadrat</span>)\r\n\r\n<span class=\"tok-cm\"># Dictionary comprehension</span>\r\n<span class=\"tok-var\">kuadrat_dict</span> = {<span class=\"tok-var\">n</span>: <span class=\"tok-var\">n</span>**<span class=\"tok-num\">2</span> <span class=\"tok-kw\">for</span> <span class=\"tok-var\">n</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">angka</span>}\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-str\">\"Kuadrat dict:\"</span>, <span class=\"tok-var\">kuadrat_dict</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py10\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> List comprehension bisa dibaca seperti kalimat Inggris: <code>[n**2 for n in angka if n % 2 == 0]</code> artinya \"beri saya n kuadrat untuk setiap n di angka, jika n genap\". Komprehensi bersarang (<em>nested comprehension</em>) juga dimungkinkan, tapi jangan sampai barisnya terlalu panjang!</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Apa output dari <code>[x*2 for x in range(3)]</code>?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">[0, 1, 2]</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">[0, 2, 4]</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">[2, 4, 6]</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-11\">Lanjut: pip & Virtual Env →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"py-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">pip & Virtual Env</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>pip</strong> adalah package manager bawaan Python untuk menginstall library eksternal dari Python Package Index (PyPI). <strong>Virtual environment</strong> (venv) adalah lingkungan Python terisolasi per proyek — mencegah konflik versi library antar proyek. Keduanya adalah alat wajib dalam pengembangan Python profesional.</p>\r\n        <p>Virtual env dibuat dengan <code>python -m venv nama_env</code>, lalu diaktifkan. Semua <code>pip install</code> yang dijalankan setelahnya hanya berdampak di lingkungan tersebut — tidak mengganggu proyek lain.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>pip_venv.sh</div>\r\n          <button class=\"run-btn\" data-run=\"py11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\"># Buat virtual environment</span>\r\n$ <span class=\"tok-var\">python -m venv belajar_env</span>\r\n\r\n<span class=\"tok-cm\"># Aktifkan (Linux/macOS)</span>\r\n$ <span class=\"tok-var\">source belajar_env/bin/activate</span>\r\n\r\n<span class=\"tok-cm\"># Aktifkan (Windows)</span>\r\n$ <span class=\"tok-var\">belajar_env\\Scripts\\activate</span>\r\n\r\n<span class=\"tok-cm\"># Install library di dalam venv</span>\r\n$ <span class=\"tok-var\">pip install requests flask pandas</span>\r\n\r\n<span class=\"tok-cm\"># Keluar dari venv</span>\r\n$ <span class=\"tok-var\">deactivate</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py11\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Biasakan membuat <code>requirements.txt</code> di setiap proyek dengan menjalankan <code>pip freeze > requirements.txt</code>. File ini berisi daftar library dan versinya — siapa pun bisa mereproduksi environment dengan <code>pip install -r requirements.txt</code>.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Perintah apa untuk membuat virtual environment baru bernama <code>myenv</code>?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">pip create myenv</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">python -m venv myenv</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">virtual myenv</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"py-12\">Lanjut: Pengenalan OOP →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- PY Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"py-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Pengenalan OOP</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>OOP (Object-Oriented Programming)</strong> di Python menggunakan <code>class</code> untuk membuat cetak biru objek. Setiap class bisa punya <em>method</em> (fungsi di dalam class) dan <em>attribute</em> (data yang dimiliki objek). Constructor <code>__init__()</code> dijalankan saat objek dibuat.</p>\r\n        <p>Python mendukung pilar OOP: <strong>encapsulation</strong> (pembungkusan data), <strong>inheritance</strong> (pewarisan), dan <strong>polymorphism</strong> (banyak bentuk) — semuanya dengan sintaks yang lebih ringan dari Java.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>oop.py</div>\r\n          <button class=\"run-btn\" data-run=\"py12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span>:\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">__init__</span>(<span class=\"tok-kw\">self</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>):\r\n        <span class=\"tok-kw\">self</span>.<span class=\"tok-var\">nama</span> = <span class=\"tok-var\">nama</span>\r\n        <span class=\"tok-kw\">self</span>.<span class=\"tok-var\">skor</span> = <span class=\"tok-var\">skor</span>\r\n\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">tampil</span>(<span class=\"tok-kw\">self</span>):\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-str\">f\"</span><span class=\"tok-var\">{self.nama}</span><span class=\"tok-str\">: </span><span class=\"tok-var\">{self.skor}</span><span class=\"tok-str\">\"</span>\r\n\r\n<span class=\"tok-cm\"># Inheritance</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">SiswaAktif</span>(<span class=\"tok-var\">Siswa</span>):\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">tampil</span>(<span class=\"tok-kw\">self</span>):\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-str\">f\"⭐ {self.nama}: {self.skor}\"</span>\r\n\r\n<span class=\"tok-var\">s1</span> = <span class=\"tok-fn\">SiswaAktif</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">92</span>)\r\n<span class=\"tok-fn\">print</span>(<span class=\"tok-var\">s1</span>.<span class=\"tok-fn\">tampil</span>())</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-py12\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Method <code>__init__</code> adalah constructor Python — dijalankan otomatis saat objek dibuat. Parameter <code>self</code> merujuk pada objek itu sendiri, seperti <code>this</code> di Java/JS.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Kata kunci apa untuk membuat class di Python?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">struct</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">object</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">class</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"py-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'py\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'py-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#FFC93C', NULL, '2026-07-03 13:09:45', '2026-07-04 18:25:44');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(4, 'java', 'Java Programming', 'Enterprise', 'intermediate', 'Java', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>Java — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">Java</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"java\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">Java</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"java\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"java\">\r\n      <div class=\"topic-item active\" data-topic=\"java-1\"><span class=\"topic-check\"></span>Apa itu Java?</div>\r\n      <div class=\"topic-item\" data-topic=\"java-2\"><span class=\"topic-check\"></span>Variabel & Tipe Data</div>\r\n      <div class=\"topic-item\" data-topic=\"java-3\"><span class=\"topic-check\"></span>Kondisi & Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"java-4\"><span class=\"topic-check\"></span>Method & Class</div>\r\n      <div class=\"topic-item\" data-topic=\"java-5\"><span class=\"topic-check\"></span>Constructor & Object</div>\r\n      <div class=\"topic-item\" data-topic=\"java-6\"><span class=\"topic-check\"></span>Array & ArrayList</div>\r\n      <div class=\"topic-item\" data-topic=\"java-7\"><span class=\"topic-check\"></span>Inheritance</div>\r\n      <div class=\"topic-item\" data-topic=\"java-8\"><span class=\"topic-check\"></span>Exception Handling</div>\r\n      <div class=\"topic-item\" data-topic=\"java-9\"><span class=\"topic-check\"></span>Package & Import</div>\r\n      <div class=\"topic-item\" data-topic=\"java-10\"><span class=\"topic-check\"></span>Polymorphism</div>\r\n      <div class=\"topic-item\" data-topic=\"java-11\"><span class=\"topic-check\"></span>Abstract & Interface</div>\r\n      <div class=\"topic-item\" data-topic=\"java-12\"><span class=\"topic-check\"></span>File I/O</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= JAVA ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"java\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 04 · BAHASA OBJEK & ENTERPRISE</div>\r\n        <h1 class=\"lang-title\">Java</h1>\r\n        <p class=\"lang-desc\">Bahasa berorientasi objek yang tangguh dan portable — kodenya bisa jalan di mana saja berkat JVM. Banyak dipakai untuk aplikasi Android, backend enterprise, dan sistem seperti perbankan.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">JV</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"java-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu Java?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Java adalah bahasa yang menggunakan prinsip <strong>OOP (Object-Oriented Programming)</strong>. Setiap kode Java harus berada di dalam <strong>class</strong>. Program dikompilasi menjadi <em>bytecode</em> yang berjalan di atas JVM (Java Virtual Machine).</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Halo.java</div>\r\n          <button class=\"run-btn\" data-run=\"java1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Halo</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-var\">String</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Halo, \"</span> + <span class=\"tok-var\">nama</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Nama file harus sama persis dengan nama class utama — <code>Halo</code> harus di <code>Halo.java</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-2\">Lanjut: Variabel & Tipe Data →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe Data</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Java itu <strong>statically typed</strong> — setiap variabel harus dideklarasikan dengan tipe. Tipe primitif: <code>int</code>, <code>double</code>, <code>boolean</code>, <code>char</code>, plus tipe objek <code>String</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Variabel.java</div>\r\n          <button class=\"run-btn\" data-run=\"java2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n<span class=\"tok-var\">String</span> <span class=\"tok-var\">namaModul</span> = <span class=\"tok-str\">\"Java Dasar\"</span>;\r\n<span class=\"tok-kw\">boolean</span> <span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>;\r\n<span class=\"tok-kw\">double</span> <span class=\"tok-var\">rata</span> = <span class=\"tok-num\">85.5</span>;\r\n<span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-var\">namaModul</span> + <span class=\"tok-str\">\" - \"</span> + <span class=\"tok-var\">lulus</span>);\r\n<span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Rata: \"</span> + <span class=\"tok-var\">rata</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz singkat: Siapa yang menjalankan bytecode Java?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Browser</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">JVM (Java Virtual Machine)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Operating System</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-3\">Lanjut: Kondisi & Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Java punya <code>if/else</code>, <code>switch</code>, <code>for</code>, <code>while</code> — sintaksnya mirip JavaScript karena JS memang terinspirasi dari Java.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Kondisi.java</div>\r\n          <button class=\"run-btn\" data-run=\"java3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">nilai</span> = <span class=\"tok-num\">85</span>;\r\n<span class=\"tok-kw\">if</span> (<span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">90</span>) { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"A\"</span>); }\r\n<span class=\"tok-kw\">else if</span> (<span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">80</span>) { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"B\"</span>); }\r\n<span class=\"tok-kw\">else</span> { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"C\"</span>); }\r\n<span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">i</span> = <span class=\"tok-num\">1</span>; <span class=\"tok-var\">i</span> <= <span class=\"tok-num\">3</span>; <span class=\"tok-var\">i</span>++) {\r\n    <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Modul ke-\"</span> + <span class=\"tok-var\">i</span>);\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Kurung <code>()</code> di <code>if</code> wajib di Java. Kurung kurawal <code>{}</code> bisa dihilangkan untuk satu baris.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-4\">Lanjut: Method & Class →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Method & Class</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Class</strong> adalah cetak biru untuk objek. <strong>Method</strong> adalah fungsi dalam class. Method <code>main()</code> adalah titik masuk program Java.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Method.java</div>\r\n          <button class=\"run-btn\" data-run=\"java4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Method</span> {\r\n    <span class=\"tok-kw\">static void</span> <span class=\"tok-fn\">sapa</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">nama</span>) {\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Halo \"</span> + <span class=\"tok-var\">nama</span>);\r\n    }\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-fn\">sapa</span>(<span class=\"tok-str\">\"LearnBase\"</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>static</code> berarti method bisa dipanggil tanpa membuat objek. <code>void</code> berarti tidak mengembalikan nilai.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-5\">Lanjut: Constructor & Object →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Constructor & Object</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Constructor</strong> dipanggil saat <code>new</code> membuat objek. Namanya sama dengan class, tanpa tipe kembalian.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Mahasiswa.java</div>\r\n          <button class=\"run-btn\" data-run=\"java5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Mahasiswa</span> {\r\n    <span class=\"tok-var\">String</span> <span class=\"tok-var\">nama</span>; <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span>;\r\n    <span class=\"tok-fn\">Mahasiswa</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">nama</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span>) {\r\n        <span class=\"tok-kw\">this</span>.<span class=\"tok-var\">nama</span> = <span class=\"tok-var\">nama</span>; <span class=\"tok-kw\">this</span>.<span class=\"tok-var\">skor</span> = <span class=\"tok-var\">skor</span>;\r\n    }\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-var\">Mahasiswa</span> <span class=\"tok-var\">m</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Mahasiswa</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>);\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-var\">m</span>.<span class=\"tok-var\">nama</span> + <span class=\"tok-str\">\": \"</span> + <span class=\"tok-var\">m</span>.<span class=\"tok-var\">skor</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>this</code> merujuk ke objek saat ini, membedakan field dengan parameter yang namanya sama.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-6\">Lanjut: Array & ArrayList →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Array & ArrayList</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Array di Java ukurannya tetap. <strong>ArrayList</strong> dari <code>java.util</code> bisa berubah ukuran — pakai <code>add()</code>, <code>get()</code>, <code>size()</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>ArrayList.java</div>\r\n          <button class=\"run-btn\" data-run=\"java6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">import</span> <span class=\"tok-var\">java.util.ArrayList</span>;\r\n<span class=\"tok-kw\">public class</span> <span class=\"tok-var\">ArrayList</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-var\">ArrayList</span>&lt;<span class=\"tok-var\">String</span>&gt; <span class=\"tok-var\">modul</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-var\">ArrayList</span>&lt;&gt;();\r\n        <span class=\"tok-var\">modul</span>.<span class=\"tok-fn\">add</span>(<span class=\"tok-str\">\"Java Dasar\"</span>);\r\n        <span class=\"tok-var\">modul</span>.<span class=\"tok-fn\">add</span>(<span class=\"tok-str\">\"OOP\"</span>);\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-var\">modul</span>.<span class=\"tok-fn\">size</span>() + <span class=\"tok-str\">\" modul\"</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>ArrayList&lt;String&gt;</code> pakai <em>generic</em> — menentukan tipe data yang bisa disimpan, memberikan keamanan tipe.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-7\">Lanjut: Inheritance →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Inheritance</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Inheritance</strong> mewarisi field dan method dari class lain. Keyword <code>extends</code> untuk menunjukkan class induk — pilar utama OOP.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Turunan.java</div>\r\n          <button class=\"run-btn\" data-run=\"java7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Pengguna</span> {\r\n    <span class=\"tok-var\">String</span> <span class=\"tok-var\">email</span>;\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">login</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Login: \"</span> + <span class=\"tok-var\">email</span>); }\r\n}\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-var\">Pengguna</span> {\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Pakai <code>@Override</code> di atas method yang ditimpa — membantu kompiler memeriksa apakah method induk benar-benar ada.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-8\">Lanjut: Exception Handling →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Exception Handling</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Exception</strong> adalah error saat program berjalan. Java mewajibkan penanganan exception dengan <code>try/catch</code> untuk mencegah crash.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Exception.java</div>\r\n          <button class=\"run-btn\" data-run=\"java8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Exception</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-kw\">try</span> {\r\n            <span class=\"tok-kw\">int</span> <span class=\"tok-var\">hasil</span> = <span class=\"tok-num\">10</span> / <span class=\"tok-num\">0</span>;\r\n        } <span class=\"tok-kw\">catch</span> (<span class=\"tok-var\">ArithmeticException</span> <span class=\"tok-var\">e</span>) {\r\n            <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Error: \"</span> + <span class=\"tok-var\">e</span>.<span class=\"tok-fn\">getMessage</span>());\r\n        }\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword apa untuk mewarisi class di Java?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">implements</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">extends</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">inherit</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-9\">Lanjut: Package & Import →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"java-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Package & Import</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Package</strong> adalah folder logis untuk mengelompokkan class Java. <strong>Import</strong> digunakan untuk memanggil class dari package lain tanpa menulis nama lengkapnya. Deklarasi <code>package</code> harus berada di baris pertama file, sedangkan <code>import</code> ditulis setelahnya.</p>\r\n        <p>Penulisan package menggunakan notasi <strong>hierarki titik</strong> — misalnya <code>com.learnbase.model</code>. Package membantu menghindari konflik nama dan memudahkan organisasi kode pada proyek besar.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Paket.java</div>\r\n          <button class=\"run-btn\" data-run=\"java9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">package</span> <span class=\"tok-var\">belajar</span>;\r\n\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-var\">java.util.Scanner</span>;\r\n\r\n<span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Paket</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-var\">Scanner</span> <span class=\"tok-var\">sc</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Scanner</span>(<span class=\"tok-str\">\"LearnBase\"</span>);\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Package: belajar\"</span>);\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Data: \"</span> + <span class=\"tok-var\">sc</span>.<span class=\"tok-fn\">next</span>());\r\n        <span class=\"tok-var\">sc</span>.<span class=\"tok-fn\">close</span>();\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>package</code> adalah baris <em>pertama</em> yang wajib ditulis jika menggunakan package. <code>import</code> ditulis setelah <code>package</code>. Gunakan wildcard <code>import java.util.*;</code> untuk mengimpor semua class dalam satu package, tapi sebaiknya hindari di kode produksi agar lebih eksplisit.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-10\">Lanjut: Polymorphism →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Java Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"java-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Polymorphism</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Polymorphism</strong> berarti \"banyak bentuk\" — satu method bisa memiliki perilaku berbeda tergantung objek yang memanggilnya. Di Java, ini diwujudkan melalui <em>method overloading</em> (compile-time) dan <em>method overriding</em> (runtime).</p>\r\n        <p><em>Overloading</em>: beberapa method dengan nama sama tapi parameter berbeda dalam satu class. <em>Overriding</em>: subclass menulis ulang method dari superclass. Polymorphism memungkinkan kode lebih fleksibel dan mudah diperluas.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Polymorphism.java</div>\r\n          <button class=\"run-btn\" data-run=\"java10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Hewan</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">suara</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"...\"</span>); }\r\n}\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Kucing</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-var\">Hewan</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">suara</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Meow!\"</span>); }\r\n}\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Anjing</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-var\">Hewan</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">suara</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Guk!\"</span>); }\r\n}\r\n\r\n<span class=\"tok-kw\">public class</span> <span class=\"tok-var\">Polymorphism</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) {\r\n        <span class=\"tok-var\">Hewan</span> <span class=\"tok-var\">h</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Kucing</span>();\r\n        <span class=\"tok-var\">h</span>.<span class=\"tok-fn\">suara</span>(); <span class=\"tok-cm\">// Meow!</span>\r\n        <span class=\"tok-var\">h</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Anjing</span>();\r\n        <span class=\"tok-var\">h</span>.<span class=\"tok-fn\">suara</span>(); <span class=\"tok-cm\">// Guk!</span>\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Polimorfisme runtime terjadi karena method dipanggil berdasarkan tipe objek asli (<em>runtime type</em>), bukan tipe referensi (<em>compile-time type</em>). Inilah inti dari dynamic binding.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-11\">Lanjut: Abstract & Interface →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Java Topic 11 (Abstract & Interface) -->\r\n    <article class=\"topic-section\" data-topic=\"java-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Abstract & Interface</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Abstract class</strong> adalah class yang tidak bisa diinstansiasi langsung — fungsinya sebagai kerangka dasar (blueprint) untuk subclass. Method abstract hanya deklarasi tanpa implementasi; subclass <em>wajib</em> meng-override method tersebut.</p>\r\n        <p><strong>Interface</strong> adalah kontrak penuh — semua method di interface otomatis <code>public abstract</code> (sebelum Java 8). Sebuah class bisa <code>implements</code> lebih dari satu interface, berbeda dengan <code>extends</code> yang hanya satu. Interface di Java 8+ juga bisa memiliki <code>default method</code> dengan implementasi bawaan.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>AbstractInterface.java</div>\r\n          <button class=\"run-btn\" data-run=\"java11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18<br>19<br>20<br>21</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// Abstract class sebagai kerangka</span>\r\n<span class=\"tok-kw\">abstract class</span> <span class=\"tok-var\">Kendaraan</span> {\r\n    <span class=\"tok-var\">String</span> <span class=\"tok-var\">warna</span>;\r\n    <span class=\"tok-fn\">Kendaraan</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">warna</span>) { <span class=\"tok-kw\">this</span>.<span class=\"tok-var\">warna</span> = <span class=\"tok-var\">warna</span>; }\r\n    <span class=\"tok-kw\">abstract void</span> <span class=\"tok-fn\">bergerak</span>();\r\n}\r\n<span class=\"tok-cm\">// Interface sebagai kontrak</span>\r\n<span class=\"tok-kw\">interface</span> <span class=\"tok-var\">Mesin</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">hidupkan</span>();\r\n}\r\n<span class=\"tok-kw\">interface</span> <span class=\"tok-var\">GPS</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">arahkan</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">tujuan</span>);\r\n}\r\n<span class=\"tok-cm\">// extends 1 abstract + implements banyak interface</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Mobil</span> <span class=\"tok-kw\">extends</span> <span class=\"tok-var\">Kendaraan</span> <span class=\"tok-kw\">implements</span> <span class=\"tok-var\">Mesin</span>, <span class=\"tok-var\">GPS</span> {\r\n    <span class=\"tok-fn\">Mobil</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">w</span>) { <span class=\"tok-kw\">super</span>(<span class=\"tok-var\">w</span>); }\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">bergerak</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Mobil \"</span> + <span class=\"tok-var\">warna</span> + <span class=\"tok-str\">\" bergerak\"</span>); }\r\n    <span class=\"tok-kw\">public void</span> <span class=\"tok-fn\">hidupkan</span>() { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Mesin hidup\"</span>); }\r\n    <span class=\"tok-kw\">public void</span> <span class=\"tok-fn\">arahkan</span>(<span class=\"tok-var\">String</span> <span class=\"tok-var\">t</span>) { <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Arah: \"</span> + <span class=\"tok-var\">t</span>); }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Abstract class vs Interface — pakai abstract class jika ada kesamaan <em>state</em> (field/constructor). Pakai interface untuk kontrak perilaku yang bisa diterapkan ke class manapun tanpa peduli hierarki.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"java-12\">Lanjut: File I/O →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Java Topic 12: File I/O -->\r\n    <article class=\"topic-section\" data-topic=\"java-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">File I/O</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>File I/O</strong> di Java menggunakan class dari package <code>java.io</code> dan <code>java.nio.file</code>. <code>FileReader</code>/<code>FileWriter</code> untuk teks, <code>BufferedReader</code>/<code>BufferedWriter</code> untuk efisiensi, dan <code>Files</code> (NIO) untuk kemudahan modern. Java 8+ juga punya <strong>Stream API</strong> (<code>Files.lines()</code>) untuk membaca file secara <em>lazy</em>.</p>\r\n        <p>File I/O penting untuk menyimpan progres belajar, membaca konfigurasi, atau menulis log. Di LearnBase, data peserta disimpan ke file CSV agar bisa diolah nanti.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>FileIO.java</div>\r\n          <button class=\"run-btn\" data-run=\"java12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">import</span> <span class=\"tok-var\">java.nio.file.*</span>;\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-var\">java.util.List</span>;\r\n\r\n<span class=\"tok-kw\">public class</span> <span class=\"tok-var\">FileIO</span> {\r\n    <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">main</span>(<span class=\"tok-var\">String[]</span> <span class=\"tok-var\">args</span>) <span class=\"tok-kw\">throws</span> <span class=\"tok-var\">Exception</span> {\r\n        <span class=\"tok-var\">Path</span> <span class=\"tok-var\">file</span> = <span class=\"tok-var\">Files</span>.<span class=\"tok-fn\">writeString</span>(\r\n            <span class=\"tok-var\">Paths</span>.<span class=\"tok-fn\">get</span>(<span class=\"tok-str\">\"data.txt\"</span>),\r\n            <span class=\"tok-str\">\"LearnBase: modul Java\\n\"</span>\r\n        );\r\n        <span class=\"tok-var\">List</span>&lt;<span class=\"tok-var\">String</span>&gt; <span class=\"tok-var\">baris</span> = <span class=\"tok-var\">Files</span>.<span class=\"tok-fn\">readAllLines</span>(<span class=\"tok-var\">file</span>);\r\n        <span class=\"tok-var\">System</span>.<span class=\"tok-var\">out</span>.<span class=\"tok-fn\">println</span>(<span class=\"tok-str\">\"Isi file: \"</span> + <span class=\"tok-var\">baris</span>.<span class=\"tok-fn\">get</span>(<span class=\"tok-num\">0</span>));\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-java12\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>Files.writeString()</code> dan <code>Files.readAllLines()</code> dari NIO adalah cara paling simpel untuk File I/O di Java modern. Untuk file besar, gunakan <code>Files.lines()</code> yang membaca <em>lazy stream</em> — tidak semua isi dimuat ke memori sekaligus.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Class dari NIO mana yang digunakan untuk membaca semua baris file sekaligus?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">FileReader</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Files</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">BufferedReader</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"java-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'java\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  function setActiveTopic(topicId) {\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'java-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#0E6853', NULL, '2026-07-03 13:09:45', '2026-07-04 16:43:56');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(5, 'cpp', 'C++ Mastery', 'Systems & Performance', 'advanced', 'C++', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>C++ — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">C++</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"cpp\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">C++</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"cpp\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"cpp\">\r\n      <div class=\"topic-item active\" data-topic=\"cpp-1\"><span class=\"topic-check\"></span>Apa itu C++?</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-2\"><span class=\"topic-check\"></span>Variabel & Tipe</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-3\"><span class=\"topic-check\"></span>Kondisi & Switch</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-4\"><span class=\"topic-check\"></span>Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-5\"><span class=\"topic-check\"></span>Array & String</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-6\"><span class=\"topic-check\"></span>Fungsi & Overloading</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-7\"><span class=\"topic-check\"></span>Pointer & Reference</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-8\"><span class=\"topic-check\"></span>Struct & Class</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-9\"><span class=\"topic-check\"></span>Inheritance</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-10\"><span class=\"topic-check\"></span>Templates</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-11\"><span class=\"topic-check\"></span>STL</div>\r\n      <div class=\"topic-item\" data-topic=\"cpp-12\"><span class=\"topic-check\"></span>File Stream</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= C++ ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"cpp\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 05 · BAHASA SISTEM & PERFORMA</div>\r\n        <h1 class=\"lang-title\">C++</h1>\r\n        <p class=\"lang-desc\">Turunan dari C dengan OOP. C++ memberi kendali penuh atas memori — cocok untuk game, sistem operasi, dan aplikasi yang butuh kecepatan tinggi.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">C++</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"cpp-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu C++?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C++ dikembangkan oleh Bjarne Stroustrup sebagai pengembangan dari C dengan OOP. Dikenal karena <strong>performa tinggi</strong> dan kendali penuh atas memori — dipakai di game engine, browser, dan sistem embedded.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Halo, LearnBase!\"</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>#include &lt;iostream&gt;</code> untuk library input-output. <code>cout</code> untuk cetak, <code>endl</code> untuk baris baru.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-2\">Lanjut: Variabel & Tipe →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C++ punya tipe <code>int</code>, <code>float</code>, <code>double</code>, <code>char</code>, <code>bool</code>, dan <code>string</code> dari STL yang lebih mudah dipakai daripada array char di C.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>variabel.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;string&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n    <span class=\"tok-var\">string</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Java Dasar\"</span>;\r\n    <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-var\">nama</span> &lt;&lt; <span class=\"tok-str\">\": \"</span> &lt;&lt; <span class=\"tok-var\">skor</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>string</code> di C++ adalah objek — punya method seperti <code>.length()</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-3\">Lanjut: Kondisi & Switch →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Switch</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C++ pakai <code>if/else</code> dan <code>switch</code>. <code>switch</code> efisien untuk banyak kondisi tetap.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>kondisi.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">nilai</span> = <span class=\"tok-num\">85</span>;\r\n<span class=\"tok-kw\">if</span> (<span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">80</span>) { <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Baik\"</span>; }\r\n<span class=\"tok-kw\">else</span> { <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Cukup\"</span>; }\r\n<span class=\"tok-kw\">switch</span> (<span class=\"tok-var\">nilai</span> / <span class=\"tok-num\">10</span>) {\r\n    <span class=\"tok-kw\">case</span> <span class=\"tok-num\">8</span>: <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\" (A)\"</span>; <span class=\"tok-kw\">break</span>;\r\n    <span class=\"tok-kw\">default</span>: <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\" (B)\"</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Jangan lupa <code>break</code> di setiap <code>case</code> — tanpa itu eksekusi lanjut ke case berikutnya (<em>fall-through</em>).</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-4\">Lanjut: Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Tiga jenis perulangan: <code>for</code>, <code>while</code>, <code>do-while</code>. C++11 juga punya <em>range-based for</em>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>loop.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">arr</span>[] = {<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">3</span>};\r\n<span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">i</span> = <span class=\"tok-num\">0</span>; <span class=\"tok-var\">i</span> &lt; <span class=\"tok-num\">3</span>; <span class=\"tok-var\">i</span>++) {\r\n    <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Modul ke-\"</span> &lt;&lt; <span class=\"tok-var\">arr</span>[<span class=\"tok-var\">i</span>] &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <em>Range-based for</em>: <code>for (int x : arr)</code> — mirip foreach di PHP.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-5\">Lanjut: Array & String →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Array & String</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Array bisa statis atau dinamis. Lebih baik pakai <code>std::string</code> daripada <code>char[]</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>array.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">angka</span>[] = {<span class=\"tok-num\">10</span>, <span class=\"tok-num\">20</span>, <span class=\"tok-num\">30</span>};\r\n<span class=\"tok-var\">string</span> <span class=\"tok-var\">teks</span> = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Panjang: \"</span> &lt;&lt; <span class=\"tok-var\">teks</span>.<span class=\"tok-fn\">length</span>() &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Jumlah: \"</span> &lt;&lt; <span class=\"tok-var\">angka</span>[<span class=\"tok-num\">0</span>] + <span class=\"tok-var\">angka</span>[<span class=\"tok-num\">2</span>];</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>std::vector</code> lebih fleksibel dari array biasa — ukurannya bisa berubah.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-6\">Lanjut: Fungsi & Overloading →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & Overloading</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Function overloading</strong> — membuat fungsi dengan nama sama tapi parameter berbeda. Kompiler memilih yang tepat.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>overload.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-fn\">tambah</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">b</span>) { <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> + <span class=\"tok-var\">b</span>; }\r\n<span class=\"tok-kw\">double</span> <span class=\"tok-fn\">tambah</span>(<span class=\"tok-kw\">double</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">double</span> <span class=\"tok-var\">b</span>) { <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> + <span class=\"tok-var\">b</span>; }\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-fn\">tambah</span>(<span class=\"tok-num\">3</span>, <span class=\"tok-num\">4</span>) &lt;&lt; <span class=\"tok-str\">\" \"</span> &lt;&lt; <span class=\"tok-fn\">tambah</span>(<span class=\"tok-num\">2.5</span>, <span class=\"tok-num\">3.1</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Overloading (parameter beda) berbeda dengan override (class induk-anak).</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-7\">Lanjut: Pointer & Reference →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Pointer & Reference</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Pointer</strong> (<code>*</code>) menyimpan alamat memori. <strong>Reference</strong> (<code>&amp;</code>) adalah alias ke variabel. Pointer bisa diubah alamatnya, reference tidak.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>pointer.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">nilai</span> = <span class=\"tok-num\">42</span>;\r\n<span class=\"tok-kw\">int</span>* <span class=\"tok-var\">ptr</span> = &amp;<span class=\"tok-var\">nilai</span>;\r\n<span class=\"tok-kw\">int</span>&amp; <span class=\"tok-var\">ref</span> = <span class=\"tok-var\">nilai</span>;\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Pointer: \"</span> &lt;&lt; *<span class=\"tok-var\">ptr</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Reference: \"</span> &lt;&lt; <span class=\"tok-var\">ref</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Di C++ modern, pakai <em>smart pointer</em> (<code>unique_ptr</code>, <code>shared_ptr</code>) — memori dibersihkan otomatis.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-8\">Lanjut: Struct & Class →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cpp-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Struct & Class</h2>\r\n      <div class=\"topic-body\">\r\n        <p><code>struct</code> dan <code>class</code> hampir sama — bedanya akses default: <code>struct</code> = <code>public</code>, <code>class</code> = <code>private</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>class.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span> {\r\n    <span class=\"tok-kw\">public</span>:\r\n        <span class=\"tok-var\">string</span> <span class=\"tok-var\">nama</span>; <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span>;\r\n        <span class=\"tok-fn\">Siswa</span>(<span class=\"tok-var\">string</span> <span class=\"tok-var\">n</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">s</span>) { <span class=\"tok-var\">nama</span> = <span class=\"tok-var\">n</span>; <span class=\"tok-var\">skor</span> = <span class=\"tok-var\">s</span>; }\r\n};\r\n<span class=\"tok-var\">Siswa</span> <span class=\"tok-var\">s</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>);\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-var\">s</span>.<span class=\"tok-var\">nama</span> &lt;&lt; <span class=\"tok-str\">\": \"</span> &lt;&lt; <span class=\"tok-var\">s</span>.<span class=\"tok-var\">skor</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Perbedaan struct vs class di C++?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Default akses: struct public, class private</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">struct tidak bisa punya method</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">class tidak punya data member</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-9\">Lanjut: Inheritance →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C++ Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"cpp-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Inheritance</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Inheritance</strong> memungkinkan sebuah class mewarisi properti dan method dari class lain. Class induk disebut <em>base class</em>, class turunan disebut <em>derived class</em>. C++ mendukung <strong>multiple inheritance</strong> — satu class bisa mewarisi lebih dari satu class induk.</p>\r\n        <p>Gunakan notasi <code>class Turunan : akses Induk</code>. Akses <code>public</code> mempertahankan akses asli, <code>protected</code> menurunkan semua ke protected, <code>private</code> menyembunyikan semuanya. Virtual inheritance menyelesaikan masalah <em>diamond problem</em> pada multiple inheritance.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>inheritance.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;string&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Materi</span> {\r\n<span class=\"tok-kw\">public</span>:\r\n    <span class=\"tok-var\">string</span> <span class=\"tok-var\">judul</span>;\r\n    <span class=\"tok-fn\">Materi</span>(<span class=\"tok-var\">string</span> <span class=\"tok-var\">j</span>) { <span class=\"tok-var\">judul</span> = <span class=\"tok-var\">j</span>; }\r\n    <span class=\"tok-kw\">virtual void</span> <span class=\"tok-fn\">cetak</span>() {\r\n        <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Materi: \"</span> &lt;&lt; <span class=\"tok-var\">judul</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    }\r\n};\r\n\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Video</span> : <span class=\"tok-kw\">public</span> <span class=\"tok-var\">Materi</span> {\r\n<span class=\"tok-kw\">public</span>:\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">durasi</span>;\r\n    <span class=\"tok-fn\">Video</span>(<span class=\"tok-var\">string</span> <span class=\"tok-var\">j</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">d</span>) : <span class=\"tok-fn\">Materi</span>(<span class=\"tok-var\">j</span>) { <span class=\"tok-var\">durasi</span> = <span class=\"tok-var\">d</span>; }\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">cetak</span>() <span class=\"tok-kw\">override</span> {\r\n        <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"[Video] \"</span> &lt;&lt; <span class=\"tok-var\">judul</span> &lt;&lt; <span class=\"tok-str\">\" (\"</span> &lt;&lt; <span class=\"tok-var\">durasi</span> &lt;&lt; <span class=\"tok-str\">\" menit)\"</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    }\r\n};\r\n\r\n<span class=\"tok-var\">Video</span> <span class=\"tok-var\">v</span>(<span class=\"tok-str\">\"Templates C++\"</span>, <span class=\"tok-num\">15</span>);\r\n<span class=\"tok-var\">v</span>.<span class=\"tok-fn\">cetak</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Gunakan <code>virtual</code> untuk method yang bisa di-<em>override</em>. Keyword <code>override</code> (C++11) membantu kompiler memeriksa apakah method benar-benar menimpa method induk.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword untuk menandai method yang bisa di-override di class turunan?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\"><code>virtual</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>overridable</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>inherit</code></button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-10\">Lanjut: Templates →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C++ Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"cpp-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Templates</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Templates</strong> adalah fitur yang memungkinkan kita menulis kode <em>generik</em> — satu fungsi atau class bisa bekerja dengan berbagai tipe data tanpa menulis ulang. C++ template adalah dasar dari <strong>generic programming</strong> dan digunakan luas di STL (Standard Template Library).</p>\r\n        <p>Ada dua jenis template: <strong>function template</strong> untuk fungsi generik, dan <strong>class template</strong> untuk class generik. Template diproses saat kompilasi (<em>compile-time polymorphism</em>) — tidak ada overhead runtime. Kamu bisa juga menspesialisasikan template untuk tipe tertentu (<em>template specialization</em>).</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>template.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;string&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n\r\n<span class=\"tok-cm\">// Function template</span>\r\n<span class=\"tok-kw\">template</span> &lt;<span class=\"tok-kw\">typename</span> <span class=\"tok-var\">T</span>&gt;\r\n<span class=\"tok-var\">T</span> <span class=\"tok-fn\">maks</span>(<span class=\"tok-var\">T</span> <span class=\"tok-var\">a</span>, <span class=\"tok-var\">T</span> <span class=\"tok-var\">b</span>) {\r\n    <span class=\"tok-kw\">return</span> (<span class=\"tok-var\">a</span> &gt; <span class=\"tok-var\">b</span>) ? <span class=\"tok-var\">a</span> : <span class=\"tok-var\">b</span>;\r\n}\r\n\r\n<span class=\"tok-cm\">// Class template</span>\r\n<span class=\"tok-kw\">template</span> &lt;<span class=\"tok-kw\">typename</span> <span class=\"tok-var\">T</span>&gt;\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Kotak</span> {\r\n<span class=\"tok-kw\">public</span>:\r\n    <span class=\"tok-var\">T</span> <span class=\"tok-var\">isi</span>;\r\n    <span class=\"tok-fn\">Kotak</span>(<span class=\"tok-var\">T</span> <span class=\"tok-var\">i</span>) { <span class=\"tok-var\">isi</span> = <span class=\"tok-var\">i</span>; }\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">tampil</span>() {\r\n        <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-str\">\"Isi: \"</span> &lt;&lt; <span class=\"tok-var\">isi</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    }\r\n};\r\n\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-fn\">maks</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">25</span>) &lt;&lt; <span class=\"tok-str\">\" \"</span>;\r\n<span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-fn\">maks</span>(<span class=\"tok-num\">3.14</span>, <span class=\"tok-num\">2.71</span>) &lt;&lt; <span class=\"tok-str\">\" \"</span>;\r\n<span class=\"tok-var\">Kotak</span>&lt;<span class=\"tok-kw\">int</span>&gt; <span class=\"tok-var\">k1</span>(<span class=\"tok-num\">42</span>);\r\n<span class=\"tok-var\">Kotak</span>&lt;<span class=\"tok-var\">string</span>&gt; <span class=\"tok-var\">k2</span>(<span class=\"tok-str\">\"Hello\"</span>);\r\n<span class=\"tok-var\">k1</span>.<span class=\"tok-fn\">tampil</span>(); <span class=\"tok-var\">k2</span>.<span class=\"tok-fn\">tampil</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Template berbeda dengan <em>generics</em> di Java/C#. Di C++, template diinstansiasi saat kompilasi (bukan runtime), sehingga setiap tipe menghasilkan kode terpisah. Ini disebut <strong>zero-cost abstraction</strong> — tidak ada overhead abstraksi.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-11\">Lanjut: STL →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C++ Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"cpp-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">STL</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>STL (Standard Template Library)</strong> adalah kumpulan template class dan function siap pakai untuk C++. Komponen utamanya: <strong>Container</strong> (vector, map, set), <strong>Iterator</strong>, dan <strong>Algorithm</strong> (sort, find). STL menghemat waktu dan sudah teruji performanya.</p>\r\n        <p>Container yang paling populer: <code>vector</code> (array dinamis), <code>map</code> (key-value), <code>set</code> (himpunan unik). Semua container bisa diakses dengan iterator — pointer generik yang menunjuk ke elemen container. Fungsi algoritma seperti <code>sort()</code> dan <code>find()</code> bekerja di container mana pun yang punya iterator.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>stl.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;vector&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;algorithm&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-var\">vector</span>&lt;<span class=\"tok-kw\">int</span>&gt; <span class=\"tok-var\">angka</span> = {<span class=\"tok-num\">5</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">8</span>, <span class=\"tok-num\">1</span>};\r\n    <span class=\"tok-fn\">sort</span>(<span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">begin</span>(), <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">end</span>());\r\n\r\n    <span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">x</span> : <span class=\"tok-var\">angka</span>) {\r\n        <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-var\">x</span> &lt;&lt; <span class=\"tok-str\">\" \"</span>;\r\n    }\r\n    <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>vector</code> adalah container serbaguna — gunakan <code>push_back()</code> untuk menambah elemen, <code>size()</code> untuk ukuran, <code>sort()</code> dari <code>&lt;algorithm&gt;</code> untuk mengurutkan.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Header untuk vector di C++ STL?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\"><code>#include &lt;vector&gt;</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>#include &lt;list&gt;</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>#include &lt;array&gt;</code></button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cpp-12\">Lanjut: File Stream →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C++ Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"cpp-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">File Stream</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>File stream</strong> memungkinkan program C++ membaca dan menulis file eksternal. Tiga class utama: <code>ofstream</code> (output file), <code>ifstream</code> (input file), <code>fstream</code> (input/output). Semua ada di header <code>&lt;fstream&gt;</code>.</p>\r\n        <p>Membuka file dengan <code>.open()</code> atau langsung di konstruktor. Menulis dengan operator <code>&lt;&lt;</code> seperti <code>cout</code>. Membaca dengan <code>&gt;&gt;</code> atau <code>getline()</code>. Selalu tutup file dengan <code>.close()</code> setelah selesai — menjamin data tersimpan dan sumber daya dilepaskan.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>filestream.cpp</div>\r\n          <button class=\"run-btn\" data-run=\"cpp12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18<br>19</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;iostream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;fstream&gt;</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;string&gt;</span>\r\n<span class=\"tok-kw\">using namespace</span> <span class=\"tok-var\">std</span>;\r\n\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-cm\">// Menulis ke file</span>\r\n    <span class=\"tok-var\">ofstream</span> <span class=\"tok-var\">out</span>(<span class=\"tok-str\">\"nilai.txt\"</span>);\r\n    <span class=\"tok-var\">out</span> &lt;&lt; <span class=\"tok-str\">\"C++: 87\"</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    <span class=\"tok-var\">out</span> &lt;&lt; <span class=\"tok-str\">\"Java: 92\"</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    <span class=\"tok-var\">out</span>.<span class=\"tok-fn\">close</span>();\r\n\r\n    <span class=\"tok-cm\">// Membaca dari file</span>\r\n    <span class=\"tok-var\">ifstream</span> <span class=\"tok-var\">in</span>(<span class=\"tok-str\">\"nilai.txt\"</span>);\r\n    <span class=\"tok-var\">string</span> <span class=\"tok-var\">baris</span>;\r\n    <span class=\"tok-kw\">while</span> (<span class=\"tok-fn\">getline</span>(<span class=\"tok-var\">in</span>, <span class=\"tok-var\">baris</span>)) {\r\n        <span class=\"tok-var\">cout</span> &lt;&lt; <span class=\"tok-var\">baris</span> &lt;&lt; <span class=\"tok-var\">endl</span>;\r\n    }\r\n    <span class=\"tok-var\">in</span>.<span class=\"tok-fn\">close</span>();\r\n\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cpp12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Selain <code>&lt;&lt;</code>/<code>&gt;&gt;</code>, kamu bisa baca file per baris dengan <code>getline(stream, variabel)</code>. Jangan lupa <code>.close()</code> — ini menjamin buffer ditulis ke disk.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Header apa untuk file stream di C++?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\"><code>#include &lt;fstream&gt;</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>#include &lt;file&gt;</code></button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\"><code>#include &lt;stream&gt;</code></button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cpp-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'cpp\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  function setActiveTopic(topicId) {\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'cpp-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#3A3A3A', NULL, '2026-07-03 13:09:45', '2026-07-04 16:43:56');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(6, 'c', 'C Language', 'Classic Systems', 'intermediate', 'C', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>C — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">C</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"c\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">C</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"c\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"c\">\r\n      <div class=\"topic-item active\" data-topic=\"c-1\"><span class=\"topic-check\"></span>Apa itu C?</div>\r\n      <div class=\"topic-item\" data-topic=\"c-2\"><span class=\"topic-check\"></span>Variabel & Tipe</div>\r\n      <div class=\"topic-item\" data-topic=\"c-3\"><span class=\"topic-check\"></span>Input & Output</div>\r\n      <div class=\"topic-item\" data-topic=\"c-4\"><span class=\"topic-check\"></span>Kondisi & Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"c-5\"><span class=\"topic-check\"></span>Array & String</div>\r\n      <div class=\"topic-item\" data-topic=\"c-6\"><span class=\"topic-check\"></span>Fungsi & Header</div>\r\n      <div class=\"topic-item\" data-topic=\"c-7\"><span class=\"topic-check\"></span>Pointer</div>\r\n      <div class=\"topic-item\" data-topic=\"c-8\"><span class=\"topic-check\"></span>Struct & File</div>\r\n      <div class=\"topic-item\" data-topic=\"c-9\"><span class=\"topic-check\"></span>Memory Allocation</div>\r\n      <div class=\"topic-item\" data-topic=\"c-10\"><span class=\"topic-check\"></span>Multi-file Project</div>\r\n      <div class=\"topic-item\" data-topic=\"c-11\"><span class=\"topic-check\"></span>Preprocessor</div>\r\n      <div class=\"topic-item\" data-topic=\"c-12\"><span class=\"topic-check\"></span>Makefile & Build</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= C ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"c\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 06 · BAHASA SISTEM KLASIK</div>\r\n        <h1 class=\"lang-title\">C</h1>\r\n        <p class=\"lang-desc\">Fondasi dari banyak bahasa modern. C memberi kendali penuh atas memori dan hardware — dipakai untuk kernel Linux, sistem embedded, dan firmware.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">C</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"c-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu C?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C diciptakan Dennis Ritchie di Bell Labs (1972). Fondasi UNIX, Linux, Windows — banyak bahasa (C++, Java, JS) terpengaruh sintaksnya. C dikenal <strong>kecepatan</strong> dan <strong>kendali memori penuh</strong>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.c</div>\r\n          <button class=\"run-btn\" data-run=\"c1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;stdio.h&gt;</span>\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Halo, LearnBase!\\\\n\"</span>);\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>#include &lt;stdio.h&gt;</code> untuk input-output standar. <code>printf()</code> mencetak teks — <code>\\\\n</code> baris baru.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-2\">Lanjut: Variabel & Tipe →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Tipe dasar: <code>int</code>, <code>float</code>/<code>double</code>, <code>char</code>, <code>void</code>. Semua harus dideklarasikan dengan tipe sebelum dipakai.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>variabel.c</div>\r\n          <button class=\"run-btn\" data-run=\"c2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n<span class=\"tok-kw\">float</span> <span class=\"tok-var\">rata</span> = <span class=\"tok-num\">85.5</span>;\r\n<span class=\"tok-kw\">char</span> <span class=\"tok-var\">grade</span> = <span class=\"tok-str\">\'B\'</span>;\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Skor: %d\\\\n\"</span>, <span class=\"tok-var\">skor</span>);\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Grade: %c, Rata: %.1f\"</span>, <span class=\"tok-var\">grade</span>, <span class=\"tok-var\">rata</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>%d</code>, <code>%c</code>, <code>%f</code> adalah <em>format specifier</em> — diganti nilai variabel setelah string.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Fungsi output di C?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">console.log()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">printf()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">print()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-3\">Lanjut: Input & Output →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Input & Output</h2>\r\n      <div class=\"topic-body\">\r\n        <p><code>scanf()</code> membaca input dari pengguna. Format specifier sama dengan <code>printf()</code> — jangan lupa <code>&amp;</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>input.c</div>\r\n          <button class=\"run-btn\" data-run=\"c3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">usia</span>;\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Masukkan usia: \"</span>);\r\n<span class=\"tok-fn\">scanf</span>(<span class=\"tok-str\">\"%d\"</span>, &amp;<span class=\"tok-var\">usia</span>);\r\n<span class=\"tok-kw\">if</span> (<span class=\"tok-var\">usia</span> >= <span class=\"tok-num\">17</span>) {\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Boleh daftar\\\\n\"</span>);\r\n} <span class=\"tok-kw\">else</span> { <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Belum cukup\"</span>); }</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal - input: 20)</div>\r\n          <div class=\"output-content\" id=\"out-c3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>&amp;usia</code> = alamat memori variabel, supaya <code>scanf()</code> bisa mengisi nilainya.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-4\">Lanjut: Kondisi & Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C punya <code>if/else</code>, <code>switch</code>, <code>for</code>, <code>while</code>, <code>do-while</code> — sintaks yang diadopsi C++, Java, JavaScript.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>loop.c</div>\r\n          <button class=\"run-btn\" data-run=\"c4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">i</span> = <span class=\"tok-num\">1</span>; <span class=\"tok-var\">i</span> <= <span class=\"tok-num\">3</span>; <span class=\"tok-var\">i</span>++) {\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Modul %d\\\\n\"</span>, <span class=\"tok-var\">i</span>);\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Di C99, variabel loop bisa dideklarasikan di dalam <code>for</code>. Sebelumnya harus di luar.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-5\">Lanjut: Array & String →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Array & String</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Array menyimpan nilai sejenis berurutan. String = array <code>char</code> diakhiri <code>\\\\0</code>. Fungsi di <code>&lt;string.h&gt;</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>string.c</div>\r\n          <button class=\"run-btn\" data-run=\"c5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">char</span> <span class=\"tok-var\">nama</span>[] = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-var\">arr</span>[] = {<span class=\"tok-num\">10</span>, <span class=\"tok-num\">20</span>, <span class=\"tok-num\">30</span>};\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Nama: %s\\\\n\"</span>, <span class=\"tok-var\">nama</span>);\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Total: %d\"</span>, <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">0</span>] + <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">2</span>]);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>strlen()</code>, <code>strcpy()</code>, <code>strcmp()</code> — ada di <code>&lt;string.h&gt;</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-6\">Lanjut: Fungsi & Header →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & Header</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Fungsi punya tipe kembalian, nama, parameter. File header (<code>.h</code>) berisi deklarasi untuk modularitas.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>fungsi.c</div>\r\n          <button class=\"run-btn\" data-run=\"c6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-fn\">kuadrat</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">x</span>) { <span class=\"tok-kw\">return</span> <span class=\"tok-var\">x</span> * <span class=\"tok-var\">x</span>; }\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Kuadrat: %d\\\\n\"</span>, <span class=\"tok-fn\">kuadrat</span>(<span class=\"tok-num\">5</span>));\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <em>Function prototype</em> diperlukan jika fungsi dipanggil sebelum didefinisikan — biasanya di file header.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-7\">Lanjut: Pointer →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Pointer</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Pointer</strong> menyimpan alamat memori. <code>*</code> untuk deklarasi, <code>&amp;</code> untuk ambil alamat. Memungkinkan pass-by-reference dan alokasi dinamis.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>pointer.c</div>\r\n          <button class=\"run-btn\" data-run=\"c7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">void</span> <span class=\"tok-fn\">ubahNilai</span>(<span class=\"tok-kw\">int</span>* <span class=\"tok-var\">p</span>) { *<span class=\"tok-var\">p</span> = <span class=\"tok-num\">100</span>; }\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">x</span> = <span class=\"tok-num\">10</span>;\r\n    <span class=\"tok-fn\">ubahNilai</span>(&amp;<span class=\"tok-var\">x</span>);\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"x = %d\\\\n\"</span>, <span class=\"tok-var\">x</span>);\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Pointer = \"alamat rumah\", <code>&amp;x</code> = cari alamat x, <code>*ptr</code> = kunjungi rumah itu.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-8\">Lanjut: Struct & File →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"c-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Struct & File</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Struct</strong> mengelompokkan variabel dengan tipe berbeda. File I/O: <code>fopen()</code>, <code>fprintf()</code>, <code>fclose()</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>struct.c</div>\r\n          <button class=\"run-btn\" data-run=\"c8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">struct</span> <span class=\"tok-var\">Siswa</span> {\r\n    <span class=\"tok-kw\">char</span> <span class=\"tok-var\">nama</span>[<span class=\"tok-num\">50</span>]; <span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span>;\r\n};\r\n<span class=\"tok-kw\">struct</span> <span class=\"tok-var\">Siswa</span> <span class=\"tok-var\">s</span> = {<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>};\r\n<span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"%s: %d\"</span>, <span class=\"tok-var\">s</span>.<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">s</span>.<span class=\"tok-var\">skor</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Tipe data string di C?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">string</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">char[] (array of char)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">str</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-9\">Lanjut: Memory Allocation →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"c-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Memory Allocation</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Alokasi memori dinamis</strong> di C menggunakan fungsi <code>malloc()</code>, <code>calloc()</code>, <code>realloc()</code>, dan <code>free()</code> dari <code>&lt;stdlib.h&gt;</code>. Memori dialokasikan di <em>heap</em> saat program berjalan — berbeda dengan array biasa yang ukurannya tetap. Setiap <code>malloc()</code> harus diimbangi <code>free()</code> untuk mencegah <em>memory leak</em>.</p>\r\n        <p>Alokasi dinamis berguna ketika ukuran data tidak diketahui saat program ditulis — misalnya membaca daftar pengguna dari file, atau membuat struktur data seperti linked list. Pointer yang dikembalikan <code>malloc()</code> bisa diperlakukan seperti array biasa dengan indeks <code>[ ]</code>.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>malloc.c</div>\r\n          <button class=\"run-btn\" data-run=\"c9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;stdio.h&gt;</span>\r\n  <span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;stdlib.h&gt;</span>\r\n\r\n  <span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n      <span class=\"tok-kw\">int</span> *<span class=\"tok-var\">arr</span>;\r\n      <span class=\"tok-var\">arr</span> = (<span class=\"tok-kw\">int</span>*)<span class=\"tok-fn\">malloc</span>(<span class=\"tok-num\">5</span> * <span class=\"tok-kw\">sizeof</span>(<span class=\"tok-kw\">int</span>));\r\n      <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">0</span>] = <span class=\"tok-num\">10</span>; <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">1</span>] = <span class=\"tok-num\">20</span>;\r\n      <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">2</span>] = <span class=\"tok-num\">30</span>; <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">3</span>] = <span class=\"tok-num\">40</span>;\r\n      <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">4</span>] = <span class=\"tok-num\">50</span>;\r\n      <span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">i</span> = <span class=\"tok-num\">0</span>; <span class=\"tok-var\">i</span> &lt; <span class=\"tok-num\">5</span>; <span class=\"tok-var\">i</span>++)\r\n          <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"%d \"</span>, <span class=\"tok-var\">arr</span>[<span class=\"tok-var\">i</span>]);\r\n      <span class=\"tok-fn\">free</span>(<span class=\"tok-var\">arr</span>);\r\n      <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n  }</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c9\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Setiap <code>malloc()</code> harus dipasangkan dengan <code>free()</code> — jika tidak, memori akan bocor (<em>memory leak</em>). Gunakan tools seperti Valgrind untuk mendeteksi kebocoran memori. Untuk array nol, <code>calloc()</code> otomatis menginisialisasi semua elemen ke 0.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Fungsi apa yang dipakai untuk membebaskan memori dinamis di C?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">free()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">delete()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">release()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-10\">Lanjut: Multi-file Project →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"c-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Multi-file Project</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Proyek C yang sesungguhnya terdiri dari banyak file: file <strong>header</strong> (<code>.h</code>) berisi deklarasi fungsi, tipe, dan konstanta; file <strong>sumber</strong> (<code>.c</code>) berisi implementasi. Ini disebut <em>modular programming</em> — setiap file punya tanggung jawab yang jelas.</p>\r\n        <p>Direktori proyek tipikal: <code>src/</code> untuk <code>.c</code>, <code>include/</code> untuk <code>.h</code>. Gunakan <em>include guard</em> (<code>#ifndef</code>) di header agar tidak di-<code>#include</code> dua kali. Kompilasi semua <code>.c</code> bersama: <code>gcc main.c math.c -o program</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>math.h</div>\r\n          <button class=\"run-btn\" data-run=\"c10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// math.h — header file</span>\r\n<span class=\"tok-kw\">#ifndef</span> <span class=\"tok-var\">MATH_H</span>\r\n<span class=\"tok-kw\">#define</span> <span class=\"tok-var\">MATH_H</span>\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">tambah</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">b</span>);\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">kali</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">b</span>);\r\n<span class=\"tok-kw\">double</span> <span class=\"tok-fn\">rata</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">arr</span>[], <span class=\"tok-kw\">int</span> <span class=\"tok-var\">n</span>);\r\n<span class=\"tok-kw\">#endif</span>\r\n<span class=\"tok-cm\">// math.c — implementation</span>\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">tambah</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">b</span>) { <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> + <span class=\"tok-var\">b</span>; }\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">kali</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">a</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">b</span>) { <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> * <span class=\"tok-var\">b</span>; }\r\n<span class=\"tok-kw\">double</span> <span class=\"tok-fn\">rata</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">arr</span>[], <span class=\"tok-kw\">int</span> <span class=\"tok-var\">n</span>) {\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">sum</span> = <span class=\"tok-num\">0</span>;\r\n    <span class=\"tok-kw\">for</span> (<span class=\"tok-kw\">int</span> <span class=\"tok-var\">i</span> = <span class=\"tok-num\">0</span>; <span class=\"tok-var\">i</span> &lt; <span class=\"tok-var\">n</span>; <span class=\"tok-var\">i</span>++) { <span class=\"tok-var\">sum</span> += <span class=\"tok-var\">arr</span>[<span class=\"tok-var\">i</span>]; }\r\n    <span class=\"tok-kw\">return</span> (<span class=\"tok-kw\">double</span>)<span class=\"tok-var\">sum</span> / <span class=\"tok-var\">n</span>;\r\n}\r\n<span class=\"tok-cm\">// main.c — program utama</span>\r\n<span class=\"tok-kw\">#include</span> <span class=\"tok-str\">\"math.h\"</span>\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">data</span>[] = {<span class=\"tok-num\">80</span>, <span class=\"tok-num\">90</span>, <span class=\"tok-num\">100</span>};\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"3+4=%d\\\\n\"</span>, <span class=\"tok-fn\">tambah</span>(<span class=\"tok-num\">3</span>, <span class=\"tok-num\">4</span>));\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Rata: %.1f\\\\n\"</span>, <span class=\"tok-fn\">rata</span>(<span class=\"tok-var\">data</span>, <span class=\"tok-num\">3</span>));\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <em>Include guard</em> <code>#ifndef</code>/<code>#define</code>/<code>#endif</code> mencegah file header di-<code>#include</code> berulang. File header kustom pakai tanda kutip <code>#include \"math.h\"</code>, bukan <code>&lt;&gt;</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-11\">Lanjut: Preprocessor →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"c-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Preprocessor</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Preprocessor</strong> dijalankan sebelum kompilasi — semua yang diawali <code>#</code> diproses lebih dulu. <code>#define</code> untuk konstanta dan makro, <code>#include</code> untuk menyisipkan file, <code>#if</code>/<code>#ifdef</code> untuk kompilasi bersyarat.</p>\r\n        <p>Preprocessor bisa membuat kode lebih fleksibel: <code>#ifdef DEBUG</code> menyalakan log hanya di mode debugging, <code>#define</code> makro seperti fungsi tanpa overhead panggilan fungsi.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>preproc.c</div>\r\n          <button class=\"run-btn\" data-run=\"c11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">#include</span> <span class=\"tok-str\">&lt;stdio.h&gt;</span>\r\n<span class=\"tok-kw\">#define</span> <span class=\"tok-var\">PI</span> <span class=\"tok-num\">3.14159</span>\r\n<span class=\"tok-kw\">#define</span> <span class=\"tok-var\">LUAS_LINGKARAN</span>(<span class=\"tok-var\">r</span>) (PI * (<span class=\"tok-var\">r</span>) * (<span class=\"tok-var\">r</span>))\r\n<span class=\"tok-kw\">#define</span> <span class=\"tok-var\">DEBUG</span>\r\n<span class=\"tok-kw\">int</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">float</span> <span class=\"tok-var\">r</span> = <span class=\"tok-num\">7</span>;\r\n    <span class=\"tok-kw\">float</span> <span class=\"tok-var\">luas</span> = <span class=\"tok-fn\">LUAS_LINGKARAN</span>(<span class=\"tok-var\">r</span>);\r\n    <span class=\"tok-kw\">#ifdef</span> <span class=\"tok-var\">DEBUG</span>\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"r=%.2f\\\\n\"</span>, <span class=\"tok-var\">r</span>);\r\n    <span class=\"tok-kw\">#endif</span>\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Luas: %.4f\\\\n\"</span>, <span class=\"tok-var\">luas</span>);\r\n    <span class=\"tok-kw\">#if</span> <span class=\"tok-fn\">LUAS_LINGKARAN</span>(<span class=\"tok-num\">7</span>) > <span class=\"tok-num\">150</span>\r\n    <span class=\"tok-fn\">printf</span>(<span class=\"tok-str\">\"Lingkaran besar!\\\\n\"</span>);\r\n    <span class=\"tok-kw\">#endif</span>\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>;\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout warning\"><strong>Peringatan:</strong> Makro preprocessor bukan fungsi — <code>#define KALI(a,b) a*b</code> akan gagal untuk <code>KALI(1+2, 3+4)</code>. Selalu bungkus parameter makro dalam tanda kurung: <code>#define KALI(a,b) ((a)*(b))</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"c-12\">Lanjut: Makefile & Build →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"c-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Makefile & Build</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Make</strong> adalah <em>build automation tool</em> yang menjalankan perintah kompilasi secara otomatis berdasarkan file <strong>Makefile</strong>. Makefile berisi <em>target</em>, <em>dependency</em>, dan <em>recipe</em> — cukup ketik <code>make</code> dan seluruh proyek dikompilasi.</p>\r\n        <p>Dengan Make, kamu tidak perlu mengetik ulang perintah <code>gcc</code> panjang. Cukup sekali tulis aturan di Makefile, lalu <code>make</code> mengerjakan sisanya — hanya file yang berubah yang dikompilasi ulang (<em>incremental build</em>).</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Makefile</div>\r\n          <button class=\"run-btn\" data-run=\"c12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\"># Makefile — build otomatis</span>\r\n<span class=\"tok-var\">CC</span> = gcc\r\n<span class=\"tok-var\">CFLAGS</span> = -Wall -Wextra\r\n<span class=\"tok-var\">TARGET</span> = program\r\n<span class=\"tok-var\">OBJS</span> = main.o math.o utils.o\r\n<span class=\"tok-var\">$(TARGET)</span>: <span class=\"tok-var\">$(OBJS)</span>\r\n    $(CC) $(CFLAGS) -o $@ $^\r\n%.o: %.c\r\n    $(CC) $(CFLAGS) -c $&lt;\r\n.PHONY: clean\r\nclean:\r\n    rm -f $(OBJS) $(TARGET)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-c12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Variable <code>$@</code> = nama target, <code>$^</code> = semua dependency, <code>$&lt;</code> = dependency pertama. <code>.PHONY</code> memberitahu Make bahwa target bukan file sungguhan. Jalankan <code>make clean</code> untuk hapus file objek.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"c-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'c\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  function setActiveTopic(topicId) {\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'c-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#FF5B35', NULL, '2026-07-03 13:09:45', '2026-07-04 18:25:44');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(7, 'csharp', 'C# & .NET', '.NET / Microsoft', 'intermediate', 'C#', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>C# — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">C#</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"cs\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">C#</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"cs\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"cs\">\r\n      <div class=\"topic-item active\" data-topic=\"cs-1\"><span class=\"topic-check\"></span>Apa itu C#?</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-2\"><span class=\"topic-check\"></span>Variabel & Tipe</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-3\"><span class=\"topic-check\"></span>Kondisi & Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-4\"><span class=\"topic-check\"></span>Method & Class</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-5\"><span class=\"topic-check\"></span>Property & Constructor</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-6\"><span class=\"topic-check\"></span>Array & List</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-7\"><span class=\"topic-check\"></span>Inheritance</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-8\"><span class=\"topic-check\"></span>LINQ & Lambda</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-9\"><span class=\"topic-check\"></span>Namespace & Using</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-10\"><span class=\"topic-check\"></span>Interface</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-11\"><span class=\"topic-check\"></span>Delegates & Events</div>\r\n      <div class=\"topic-item\" data-topic=\"cs-12\"><span class=\"topic-check\"></span>Async &amp; Await</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= C# ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"cs\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 07 · BAHASA .NET & MICROSOFT</div>\r\n        <h1 class=\"lang-title\">C#</h1>\r\n        <p class=\"lang-desc\">Bahasa modern dari Microsoft untuk ekosistem .NET — dipakai untuk aplikasi Windows, game Unity, backend web (ASP.NET), dan mobile (Xamarin).</p>\r\n      </div>\r\n      <div class=\"lang-badge\">C#</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"cs-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu C#?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C# (dibaca \"C sharp\") dikembangkan Microsoft sebagai pesaing Java. Berjalan di platform .NET, menggabungkan kekuatan C++ dengan kemudahan pengembangan. Banyak dipakai untuk <strong>game (Unity)</strong>, <strong>aplikasi enterprise</strong>, dan <strong>API backend</strong>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Program.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">using</span> <span class=\"tok-var\">System</span>;\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Program</span> {\r\n    <span class=\"tok-kw\">static void</span> <span class=\"tok-fn\">Main</span>() {\r\n        <span class=\"tok-var\">string</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"Halo, {nama}\"</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Method <code>Main()</code> (huruf besar) adalah titik masuk — berbeda dengan Java yang <code>main()</code> (huruf kecil).</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-2\">Lanjut: Variabel & Tipe →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C# punya tipe <code>int</code>, <code>double</code>, <code>bool</code>, <code>char</code>, <code>string</code>, dan <code>var</code> (tipe otomatis). Mendukung <em>nullable types</em> dengan <code>?</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Var.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n<span class=\"tok-var\">string</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"C# Dasar\"</span>;\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>;\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"{nama}: {lulus}\"</span>);\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-str\">\"Tipe: \"</span> + <span class=\"tok-var\">lulus</span>.<span class=\"tok-fn\">GetType</span>());</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>var</code> di C# adalah <em>type inference</em> — kompiler menentukan tipe dari nilainya, bukan <em>dynamic typing</em> seperti JavaScript.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-3\">Lanjut: Kondisi & Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C# punya <code>if</code>, <code>switch</code>, <code>for</code>, <code>foreach</code>, <code>while</code>. <code>foreach</code> sangat umum untuk array dan koleksi.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Loop.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">int</span>[] <span class=\"tok-var\">skor</span> = { <span class=\"tok-num\">88</span>, <span class=\"tok-num\">72</span>, <span class=\"tok-num\">95</span> };\r\n<span class=\"tok-kw\">foreach</span> (<span class=\"tok-kw\">var</span> <span class=\"tok-var\">s</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">skor</span>) {\r\n    <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">s</span> >= <span class=\"tok-num\">80</span>) {\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"{s} - Baik\"</span>);\r\n    } <span class=\"tok-kw\">else</span> {\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"{s} - Cukup\"</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>switch</code> di C# punya pattern matching — bisa <code>case &gt;= 80:</code> tanpa fall-through default.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-4\">Lanjut: Method & Class →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Method & Class</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C# mendukung OOP penuh. <strong>Method</strong> dalam class — <strong>access modifiers</strong>: <code>public</code>, <code>private</code>, <code>protected</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Method.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Helper</span> {\r\n    <span class=\"tok-kw\">public static</span> <span class=\"tok-kw\">int</span> <span class=\"tok-fn\">Kuadrat</span>(<span class=\"tok-kw\">int</span> <span class=\"tok-var\">x</span>) {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-var\">x</span> * <span class=\"tok-var\">x</span>;\r\n    }\r\n}\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-var\">Helper</span>.<span class=\"tok-fn\">Kuadrat</span>(<span class=\"tok-num\">5</span>));</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Method <code>Main</code> adalah <code>static</code> — milik class, bukan instance. Program bisa jalan tanpa membuat objek.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-5\">Lanjut: Property & Constructor →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Property & Constructor</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Property</strong> (<code>{ get; set; }</code>) adalah cara aman mengakses data class — alternatif getter/setter Java. <strong>Constructor</strong> sama seperti Java, dipanggil saat <code>new</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Properti.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span> {\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-var\">string</span> <span class=\"tok-var\">Nama</span> { <span class=\"tok-kw\">get</span>; <span class=\"tok-kw\">set</span>; }\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-kw\">int</span> <span class=\"tok-var\">Skor</span> { <span class=\"tok-kw\">get</span>; <span class=\"tok-kw\">set</span>; }\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-fn\">Siswa</span>(<span class=\"tok-var\">string</span> <span class=\"tok-var\">n</span>, <span class=\"tok-kw\">int</span> <span class=\"tok-var\">s</span>) {\r\n        <span class=\"tok-var\">Nama</span> = <span class=\"tok-var\">n</span>; <span class=\"tok-var\">Skor</span> = <span class=\"tok-var\">s</span>;\r\n    }\r\n}\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">s</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Siswa</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>);\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"{s.Nama}: {s.Skor}\"</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> C# bisa pakai <em>auto-property</em> (<code>{ get; set; }</code>) — compiler otomatis membuat field privat di belakangnya.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-6\">Lanjut: Array & List →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Array & List</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Array C# mirip Java. <code>List&lt;T&gt;</code> dari <code>System.Collections.Generic</code> adalah versi dinamis — pakai <code>Add()</code>, <code>Remove()</code>, <code>Count</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>List.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">using</span> <span class=\"tok-var\">System.Collections.Generic</span>;\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">modul</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-var\">List</span>&lt;<span class=\"tok-var\">string</span>&gt;() {\r\n    <span class=\"tok-str\">\"C# Dasar\"</span>, <span class=\"tok-str\">\"OOP\"</span>, <span class=\"tok-str\">\"LINQ\"</span>\r\n};\r\n<span class=\"tok-var\">modul</span>.<span class=\"tok-fn\">Add</span>(<span class=\"tok-str\">\"ASP.NET\"</span>);\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"{modul.Count} modul\"</span>);\r\n<span class=\"tok-kw\">foreach</span> (<span class=\"tok-kw\">var</span> <span class=\"tok-var\">m</span> <span class=\"tok-kw\">in</span> <span class=\"tok-var\">modul</span>) {\r\n    <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-var\">m</span>);\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Properti <code>Count</code> (bukan <code>length</code> atau <code>size()</code>) untuk jumlah elemen List.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-7\">Lanjut: Inheritance →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Inheritance</h2>\r\n      <div class=\"topic-body\">\r\n        <p>C# pakai <code>:</code> untuk inheritance (bukan <code>extends</code>). Keyword <code>virtual</code> dan <code>override</code> untuk method yang bisa ditimpa.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Turunan.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Pengguna</span> {\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-var\">string</span> <span class=\"tok-var\">Email</span> { <span class=\"tok-kw\">get</span>; <span class=\"tok-kw\">set</span>; }\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-kw\">virtual void</span> <span class=\"tok-fn\">Login</span>() {\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"Login: {Email}\"</span>);\r\n    }\r\n}\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span> : <span class=\"tok-var\">Pengguna</span> {\r\n    <span class=\"tok-kw\">public</span> <span class=\"tok-kw\">int</span> <span class=\"tok-var\">Skor</span> { <span class=\"tok-kw\">get</span>; <span class=\"tok-kw\">set</span>; }\r\n    <span class=\"tok-kw\">public override void</span> <span class=\"tok-fn\">Login</span>() {\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"Siswa {Email} login\"</span>);\r\n    }\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>virtual</code> di class induk + <code>override</code> di class anak — wajib jika ingin menimpa method.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-8\">Lanjut: LINQ & Lambda →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"cs-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">LINQ & Lambda</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>LINQ</strong> (Language Integrated Query) memungkinkan query data dengan sintaks mirip SQL. <strong>Lambda</strong> (<code>=&gt;</code>) untuk fungsi anonim pendek — mirip arrow function JavaScript.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Linq.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">using</span> <span class=\"tok-var\">System.Linq</span>;\r\n<span class=\"tok-kw\">int</span>[] <span class=\"tok-var\">angka</span> = { <span class=\"tok-num\">4</span>, <span class=\"tok-num\">9</span>, <span class=\"tok-num\">16</span>, <span class=\"tok-num\">25</span> };\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">genap</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">Where</span>(<span class=\"tok-var\">n</span> => <span class=\"tok-var\">n</span> % <span class=\"tok-num\">2</span> == <span class=\"tok-num\">0</span>);\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">kuadrat</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">Select</span>(<span class=\"tok-var\">n</span> => <span class=\"tok-var\">n</span> * <span class=\"tok-var\">n</span>);\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-str\">\"Genap: \"</span> + <span class=\"tok-var\">string</span>.<span class=\"tok-fn\">Join</span>(<span class=\"tok-str\">\", \"</span>, <span class=\"tok-var\">genap</span>));\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-str\">\"Kuadrat: \"</span> + <span class=\"tok-var\">string</span>.<span class=\"tok-fn\">Join</span>(<span class=\"tok-str\">\", \"</span>, <span class=\"tok-var\">kuadrat</span>));</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword inheritance di C#?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">extends</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">: (titik dua)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">inherits</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-9\">Lanjut: Namespace & Using →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- CS Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"cs-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Namespace & Using</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Namespace</strong> adalah wadah logis untuk mengorganisir kode C# — mirip <em>package</em> di Java atau <em>module</em> di Python. Namespace mencegah konflik nama antar class dan membuat kode lebih terstruktur, terutama pada proyek besar.</p>\r\n        <p>Keyword <code>using</code> digunakan untuk mengimpor namespace lain sehingga kamu bisa menggunakan class tanpa menulis nama namespace lengkapnya setiap saat. C# juga mendukung <strong>alias</strong> dengan <code>using Alias = Namespace.Class;</code> untuk menghindari ambiguitas.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Namespace.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">using</span> <span class=\"tok-var\">System</span>;\r\n<span class=\"tok-kw\">using</span> <span class=\"tok-var\">Belajar</span> = <span class=\"tok-var\">LearnBase.Modul</span>;\r\n\r\n<span class=\"tok-kw\">namespace</span> <span class=\"tok-var\">LearnBase</span> {\r\n    <span class=\"tok-kw\">class</span> <span class=\"tok-var\">Modul</span> {\r\n        <span class=\"tok-kw\">public static void</span> <span class=\"tok-fn\">Tampil</span>() {\r\n            <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-str\">\"Modul: Namespace & Using\"</span>);\r\n        }\r\n    }\r\n}\r\n\r\n<span class=\"tok-var\">Belajar</span>.<span class=\"tok-fn\">Tampil</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs9\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Gunakan <em>namespace-based naming</em> seperti <code>Perusahaan.Proyek.Modul</code> untuk proyek besar. C# 10 memperkenalkan <em>file-scoped namespace</em> dengan sintaks <code>namespace X.Y.Z;</code> (pakai titik koma, tanpa kurung kurawal) — lebih bersih untuk file yang hanya berisi satu namespace.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword apa untuk mengimpor namespace di C#?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">import</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">using</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">include</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-10\">Lanjut: Interface →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C# Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"cs-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Interface</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Interface</strong> di C# adalah kontrak yang berisi deklarasi method, property, atau event tanpa implementasi. Class yang mengimplementasi interface wajib menyediakan implementasi untuk semua anggotanya. C# menggunakan <code>:</code> untuk implementasi interface — sama seperti inheritance.</p>\r\n        <p>Interface memungkinkan <strong>polymorphism</strong> dan <strong>loose coupling</strong>. Sebuah class bisa mengimplementasi banyak interface sekaligus. Mulai C# 8.0, interface bisa punya <em>default implementation</em> — method tidak wajib di-override.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Interface.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">interface</span> <span class=\"tok-var\">IKendaraan</span> {\r\n    <span class=\"tok-kw\">void</span> <span class=\"tok-fn\">Bergerak</span>();\r\n    <span class=\"tok-kw\">int</span> <span class=\"tok-var\">KecepatanMaks</span> { <span class=\"tok-kw\">get</span>; }\r\n}\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Mobil</span> : <span class=\"tok-var\">IKendaraan</span> {\r\n    <span class=\"tok-kw\">public int</span> <span class=\"tok-var\">KecepatanMaks</span> => <span class=\"tok-num\">200</span>;\r\n    <span class=\"tok-kw\">public void</span> <span class=\"tok-fn\">Bergerak</span>() {\r\n        <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-str\">\"Mobil melaju\"</span>);\r\n    }\r\n}\r\n<span class=\"tok-var\">IKendaraan</span> <span class=\"tok-var\">k</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Mobil</span>();\r\n<span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>($<span class=\"tok-str\">\"Kecepatan: {k.KecepatanMaks}\"</span>);\r\n<span class=\"tok-var\">k</span>.<span class=\"tok-fn\">Bergerak</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Konvensi penamaan interface di C# pakai awalan <code>I</code> (kapital) — seperti <code>IDisposable</code>, <code>IComparable</code>. Ini membantu membedakan interface dari class.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-11\">Lanjut: Delegates & Events →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C# Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"cs-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Delegates & Events</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Delegate</strong> adalah tipe yang mereferensikan method — mirip function pointer di C++ yang aman tipe. <strong>Event</strong> adalah delegate khusus yang dipakai untuk pola publisher-subscriber — elemen utama dalam pemrograman event-driven di C#.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Event.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">public delegate void</span> <span class=\"tok-var\">Handler</span>(<span class=\"tok-var\">string</span> <span class=\"tok-var\">msg</span>);\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Publisher</span> {\r\n    <span class=\"tok-kw\">public event</span> <span class=\"tok-var\">Handler</span> <span class=\"tok-var\">OnNotify</span>;\r\n    <span class=\"tok-kw\">public void</span> <span class=\"tok-fn\">Kirim</span>() {\r\n        <span class=\"tok-var\">OnNotify</span>?.<span class=\"tok-fn\">Invoke</span>(<span class=\"tok-str\">\"Event dipicu!\"</span>);\r\n    }\r\n}\r\n<span class=\"tok-kw\">var</span> <span class=\"tok-var\">p</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">Publisher</span>();\r\n<span class=\"tok-var\">p</span>.<span class=\"tok-var\">OnNotify</span> += <span class=\"tok-var\">msg</span> => <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-var\">msg</span>);\r\n<span class=\"tok-var\">p</span>.<span class=\"tok-fn\">Kirim</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Operator <code>?.</code> (null-conditional) sebelum <code>Invoke</code> aman jika tidak ada subscriber. <code>+=</code> untuk mendaftarkan method ke event, <code>-=</code> untuk menghapus.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"cs-12\">Lanjut: Async & Await →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- C# Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"cs-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Async & Await</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>async/await</strong> di C# mempermudah penulisan kode asinkron — seperti operasi file, HTTP request, atau query database. Method <code>async</code> mengembalikan <code>Task</code> atau <code>Task&lt;T&gt;</code>. <code>await</code> menunggu hasil tanpa memblokir thread utama.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Async.cs</div>\r\n          <button class=\"run-btn\" data-run=\"cs12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">using</span> <span class=\"tok-var\">System.Net.Http</span>;\r\n<span class=\"tok-kw\">async</span> <span class=\"tok-var\">Task</span> <span class=\"tok-fn\">AmbilData</span>() {\r\n    <span class=\"tok-kw\">var</span> <span class=\"tok-var\">client</span> = <span class=\"tok-kw\">new</span> <span class=\"tok-fn\">HttpClient</span>();\r\n    <span class=\"tok-var\">string</span> <span class=\"tok-var\">hasil</span> = <span class=\"tok-kw\">await</span> <span class=\"tok-var\">client</span>.<span class=\"tok-fn\">GetStringAsync</span>(<span class=\"tok-str\">\"https://api.learnbase.com\"</span>);\r\n    <span class=\"tok-var\">Console</span>.<span class=\"tok-fn\">WriteLine</span>(<span class=\"tok-var\">hasil</span>);\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-cs12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Method async sebaiknya diakhiri akhiran <code>Async</code> (contoh: <code>GetDataAsync</code>) — ini konvensi standar .NET untuk membedakan method async dari synchronous.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Kata kunci untuk method asinkron di C#?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">async</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">await</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Task</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"cs-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'cs\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  function setActiveTopic(topicId) {\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'cs-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#264DE4', NULL, '2026-07-03 13:09:45', '2026-07-04 19:19:23');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(8, 'go', 'Go (Golang)', 'Cloud & Concurrency', 'intermediate', 'Go', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>Go — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">Go</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"go\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">Go</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"go\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"go\">\r\n      <div class=\"topic-item active\" data-topic=\"go-1\"><span class=\"topic-check\"></span>Apa itu Go?</div>\r\n      <div class=\"topic-item\" data-topic=\"go-2\"><span class=\"topic-check\"></span>Variabel & Tipe</div>\r\n      <div class=\"topic-item\" data-topic=\"go-3\"><span class=\"topic-check\"></span>Kondisi & Switch</div>\r\n      <div class=\"topic-item\" data-topic=\"go-4\"><span class=\"topic-check\"></span>Perulangan & Range</div>\r\n      <div class=\"topic-item\" data-topic=\"go-5\"><span class=\"topic-check\"></span>Array & Slice</div>\r\n      <div class=\"topic-item\" data-topic=\"go-6\"><span class=\"topic-check\"></span>Fungsi & Multiple Return</div>\r\n      <div class=\"topic-item\" data-topic=\"go-7\"><span class=\"topic-check\"></span>Struct & Method</div>\r\n      <div class=\"topic-item\" data-topic=\"go-8\"><span class=\"topic-check\"></span>Pointer & Interface</div>\r\n      <div class=\"topic-item\" data-topic=\"go-9\"><span class=\"topic-check\"></span>Goroutine</div>\r\n      <div class=\"topic-item\" data-topic=\"go-10\"><span class=\"topic-check\"></span>Channel & Select</div>\r\n      <div class=\"topic-item\" data-topic=\"go-11\"><span class=\"topic-check\"></span>WaitGroup & Mutual Exclusion</div>\r\n      <div class=\"topic-item\" data-topic=\"go-12\"><span class=\"topic-check\"></span>Package & Module</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= GO ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"go\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 08 · BAHASA CLOUD & KONKURENSI</div>\r\n        <h1 class=\"lang-title\">Go</h1>\r\n        <p class=\"lang-desc\">Bahasa modern dari Google yang menggabungkan sintaks sederhana dengan performa tinggi dan <em>built-in concurrency</em> — populer untuk backend, cloud, dan microservices.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">GO</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"go-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu Go?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Go (atau Golang) diciptakan Google untuk mengatasi kompleksitas pengembangan di skala besar. Sintaksnya bersih seperti Python, performanya mendekati C++, dan punya <strong>goroutine</strong> untuk konkurensi bawaan — ideal untuk API server, CLI tools, dan layanan cloud.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>main.go</div>\r\n          <button class=\"run-btn\" data-run=\"go1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">package</span> <span class=\"tok-var\">main</span>\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-str\">\"fmt\"</span>\r\n<span class=\"tok-kw\">func</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-var\">nama</span> := <span class=\"tok-str\">\"LearnBase\"</span>\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Halo, \"</span> + <span class=\"tok-var\">nama</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Operator <code>:=</code> untuk deklarasi + inisialisasi singkat — tipe dideteksi otomatis. Ini fitur khas Go.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-2\">Lanjut: Variabel & Tipe →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Go punya tipe <code>int</code>, <code>float64</code>, <code>string</code>, <code>bool</code>. Semua variabel yang dideklarasikan <strong>wajib dipakai</strong> — jika tidak, kode tidak akan kompilasi. Ini desain Go untuk mencegah kode kotor.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>var.go</div>\r\n          <button class=\"run-btn\" data-run=\"go2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">var</span> <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">int</span> = <span class=\"tok-num\">87</span>\r\n<span class=\"tok-var\">nama</span> := <span class=\"tok-str\">\"Go Dasar\"</span>\r\n<span class=\"tok-var\">lulus</span> := <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>\r\n<span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Printf</span>(<span class=\"tok-str\">\"%s: %t\\\\n\"</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">lulus</span>)\r\n<span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Skor:\"</span>, <span class=\"tok-var\">skor</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Go <code>Printf</code> pakai format specifier: <code>%s</code> string, <code>%d</code> int, <code>%t</code> bool, <code>%f</code> float — mirip C.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-3\">Lanjut: Kondisi & Switch →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Switch</h2>\r\n      <div class=\"topic-body\">\r\n        <p><code>if</code> di Go tanpa kurung <code>()</code> di sekitar kondisi — tidak seperti C/Java. <code>switch</code> tidak perlu <code>break</code> — setiap case berhenti otomatis.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>kondisi.go</div>\r\n          <button class=\"run-btn\" data-run=\"go3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">if</span> <span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">80</span> {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Baik\"</span>)\r\n} <span class=\"tok-kw\">else</span> {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Cukup\"</span>)\r\n}\r\n<span class=\"tok-kw\">switch</span> <span class=\"tok-var\">nilai</span> / <span class=\"tok-num\">10</span> {\r\n    <span class=\"tok-kw\">case</span> <span class=\"tok-num\">8</span>: <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Print</span>(<span class=\"tok-str\">\"A\"</span>)\r\n    <span class=\"tok-kw\">default</span>: <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Print</span>(<span class=\"tok-str\">\"B\"</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>switch</code> di Go bisa digunakan untuk <em>if-else chain</em> dengan menulis <code>switch {}</code> tanpa expression — sangat fleksibel!</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-4\">Lanjut: Perulangan & Range →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Perulangan & Range</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Go hanya punya <code>for</code> — tidak ada <code>while</code> atau <code>do-while</code>. Tapi <code>for</code> bisa dipakai untuk semua pola perulangan. Keyword <code>range</code> untuk iterasi array, slice, map, atau string.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>loop.go</div>\r\n          <button class=\"run-btn\" data-run=\"go4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">modul</span> := []<span class=\"tok-var\">string</span>{<span class=\"tok-str\">\"HTML\"</span>, <span class=\"tok-str\">\"CSS\"</span>, <span class=\"tok-str\">\"JS\"</span>}\r\n<span class=\"tok-kw\">for</span> <span class=\"tok-var\">i</span>, <span class=\"tok-var\">m</span> := <span class=\"tok-kw\">range</span> <span class=\"tok-var\">modul</span> {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Printf</span>(<span class=\"tok-str\">\"%d. %s\\\\n\"</span>, <span class=\"tok-var\">i</span>+<span class=\"tok-num\">1</span>, <span class=\"tok-var\">m</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>range</code> mengembalikan dua nilai: indeks dan elemen. Jika hanya ingin elemen, pakai <code>_, m := range</code> (underscore untuk membuang nilai).</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-5\">Lanjut: Array & Slice →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Array & Slice</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Array</strong> di Go ukuran tetap. <strong>Slice</strong> lebih fleksibel — ukuran bisa berubah. Slice adalah tipe data yang paling umum untuk koleksi di Go.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>slice.go</div>\r\n          <button class=\"run-btn\" data-run=\"go5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">angka</span> := []<span class=\"tok-kw\">int</span>{<span class=\"tok-num\">10</span>, <span class=\"tok-num\">20</span>, <span class=\"tok-num\">30</span>}\r\n<span class=\"tok-var\">angka</span> = <span class=\"tok-fn\">append</span>(<span class=\"tok-var\">angka</span>, <span class=\"tok-num\">40</span>)\r\n<span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Panjang:\"</span>, <span class=\"tok-fn\">len</span>(<span class=\"tok-var\">angka</span>))\r\n<span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Jumlah:\"</span>, <span class=\"tok-var\">angka</span>[<span class=\"tok-num\">0</span>]+<span class=\"tok-var\">angka</span>[<span class=\"tok-num\">2</span>])</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Fungsi <code>append()</code> bisa nambah elemen ke slice. Jika kapasitas penuh, Go otomatis mengalokasikan array baru yang lebih besar.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-6\">Lanjut: Fungsi & Multiple Return →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi & Multiple Return</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Fungsi di Go bisa mengembalikan <strong>banyak nilai</strong> — fitur yang jarang dimiliki bahasa lain. Ini sangat berguna untuk mengembalikan hasil + error sekaligus, sesuai idiom Go.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>fungsi.go</div>\r\n          <button class=\"run-btn\" data-run=\"go6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">func</span> <span class=\"tok-fn\">bagi</span>(<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span> <span class=\"tok-kw\">int</span>) (<span class=\"tok-kw\">int</span>, <span class=\"tok-var\">error</span>) {\r\n    <span class=\"tok-kw\">if</span> <span class=\"tok-var\">b</span> == <span class=\"tok-num\">0</span> {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>, <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Errorf</span>(<span class=\"tok-str\">\"tidak bisa bagi nol\"</span>)\r\n    }\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> / <span class=\"tok-var\">b</span>, <span class=\"tok-kw\">nil</span>\r\n}\r\n<span class=\"tok-var\">hasil</span>, <span class=\"tok-var\">err</span> := <span class=\"tok-fn\">bagi</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">2</span>)\r\n<span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Hasil:\"</span>, <span class=\"tok-var\">hasil</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Idiom Go: fungsi yang bisa gagal selalu mengembalikan nilai + <code>error</code>. Panggil fungsi, cek error dulu, baru pakai hasilnya.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-7\">Lanjut: Struct & Method →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Struct & Method</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Struct</strong> mengelompokkan data. <strong>Method</strong> di Go didefinisikan di luar struct dengan <em>receiver</em> — parameter khusus yang menghubungkan fungsi ke struct.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>struct.go</div>\r\n          <button class=\"run-btn\" data-run=\"go7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">type</span> <span class=\"tok-var\">Siswa</span> <span class=\"tok-kw\">struct</span> {\r\n    <span class=\"tok-var\">Nama</span> <span class=\"tok-var\">string</span>\r\n    <span class=\"tok-var\">Skor</span> <span class=\"tok-kw\">int</span>\r\n}\r\n<span class=\"tok-kw\">func</span> (<span class=\"tok-var\">s</span> <span class=\"tok-var\">Siswa</span>) <span class=\"tok-fn\">cetak</span>() {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Printf</span>(<span class=\"tok-str\">\"%s: %d\\\\n\"</span>, <span class=\"tok-var\">s</span>.<span class=\"tok-var\">Nama</span>, <span class=\"tok-var\">s</span>.<span class=\"tok-var\">Skor</span>)\r\n}\r\n<span class=\"tok-var\">s</span> := <span class=\"tok-var\">Siswa</span>{<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>}\r\n<span class=\"tok-var\">s</span>.<span class=\"tok-fn\">cetak</span>()</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Go tidak punya class — struct + method adalah cara Go untuk OOP. Ini desain yang lebih sederhana tanpa inheritance kompleks.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-8\">Lanjut: Pointer & Interface →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Pointer & Interface</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Pointer</strong> di Go (<code>*</code>) seperti C, tanpa aritmetika pointer. <strong>Interface</strong> adalah kumpulan method — tipe yang mengimplementasikan semua method itu otomatis memenuhi interface. Ini dasar dari polimorfisme Go.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>iface.go</div>\r\n          <button class=\"run-btn\" data-run=\"go8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">type</span> <span class=\"tok-var\">Pengguna</span> <span class=\"tok-kw\">interface</span> {\r\n    <span class=\"tok-fn\">Login</span>() <span class=\"tok-var\">string</span>\r\n}\r\n<span class=\"tok-kw\">type</span> <span class=\"tok-var\">Siswa</span> <span class=\"tok-kw\">struct</span>{ <span class=\"tok-var\">Email</span> <span class=\"tok-var\">string</span> }\r\n<span class=\"tok-kw\">func</span> (<span class=\"tok-var\">s</span> <span class=\"tok-var\">Siswa</span>) <span class=\"tok-fn\">Login</span>() <span class=\"tok-var\">string</span> {\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-str\">\"Login: \"</span> + <span class=\"tok-var\">s</span>.<span class=\"tok-var\">Email</span>\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Fitur utama Go untuk konkurensi?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Thread</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Goroutine</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Async/Await</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-9\">Lanjut: Goroutine →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"go-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Goroutine</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Goroutine</strong> adalah thread ringan bawaan Go untuk konkurensi. Cukup tambahkan <code>go</code> sebelum pemanggilan fungsi, dan fungsi itu berjalan secara <em>concurrent</em>. Goroutine sangat murah — ribuan goroutine bisa berjalan dalam satu program tanpa masalah.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>goroutine.go</div>\r\n          <button class=\"run-btn\" data-run=\"go9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">package</span> <span class=\"tok-var\">main</span>\r\n<span class=\"tok-kw\">import</span> <span class=\"tok-str\">\"fmt\"</span>\r\n<span class=\"tok-kw\">func</span> <span class=\"tok-fn\">tampil</span>(<span class=\"tok-var\">msg</span> <span class=\"tok-var\">string</span>) {\r\n    <span class=\"tok-kw\">for</span> <span class=\"tok-var\">i</span> := <span class=\"tok-num\">1</span>; <span class=\"tok-var\">i</span> <= <span class=\"tok-num\">3</span>; <span class=\"tok-var\">i</span>++ {\r\n        <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-var\">msg</span>, <span class=\"tok-var\">i</span>)\r\n    }\r\n}\r\n<span class=\"tok-kw\">func</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">go</span> <span class=\"tok-fn\">tampil</span>(<span class=\"tok-str\">\"Halo dari goroutine\"</span>)\r\n    <span class=\"tok-fn\">tampil</span>(<span class=\"tok-str\">\"Langsung dari main\"</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Program di atas mungkin hanya menampilkan output dari <code>main</code> saja karena <code>main</code> selesai sebelum goroutine sempat jalan. Gunakan <code>time.Sleep</code> atau <strong>WaitGroup</strong> untuk menunggu goroutine selesai.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Kata kunci apa untuk menjalankan goroutine?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">go</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">async</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">spawn</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-10\">Lanjut: Channel & Select →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Go Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"go-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Channel & Select</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Channel</strong> adalah jalur komunikasi antar goroutine — mengirim dan menerima data dengan operator <code>&lt;-</code>. <strong>Select</strong> memungkinkan goroutine menunggu beberapa channel sekaligus — merespon channel yang pertama selesai. Ini adalah inti dari <em>CSP (Communicating Sequential Processes)</em> di Go.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>channel.go</div>\r\n          <button class=\"run-btn\" data-run=\"go10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">ch</span> := <span class=\"tok-fn\">make</span>(<span class=\"tok-kw\">chan</span> <span class=\"tok-var\">string</span>)\r\n<span class=\"tok-kw\">go</span> <span class=\"tok-kw\">func</span>() {\r\n    <span class=\"tok-var\">ch</span> &lt;- <span class=\"tok-str\">\"Halo dari goroutine\"</span>\r\n}()\r\n<span class=\"tok-kw\">select</span> {\r\n    <span class=\"tok-kw\">case</span> <span class=\"tok-var\">msg</span> := &lt;-<span class=\"tok-var\">ch</span>:\r\n        <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-var\">msg</span>)\r\n    <span class=\"tok-kw\">case</span> &lt;-<span class=\"tok-var\">time</span>.<span class=\"tok-fn\">After</span>(<span class=\"tok-num\">1</span> * <span class=\"tok-var\">time</span>.<span class=\"tok-var\">Second</span>):\r\n        <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Timeout\"</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Channel unbuffered (tanpa kapasitas) bersifat <em>blocking</em> — pengirim menunggu sampai penerima siap. Gunakan <code>make(chan T, N)</code> untuk buffered channel.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-11\">Lanjut: WaitGroup & Mutual Exclusion →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Go Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"go-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Error Handling</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Go tidak punya exception — error adalah <strong>nilai biasa</strong> yang dikembalikan dari fungsi. Tipe <code>error</code> adalah interface bawaan. Idiom Go: panggil fungsi, cek <code>if err != nil</code>, baru gunakan hasilnya. Pola ini menghasilkan kode eksplisit tanpa kejutan.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>error.go</div>\r\n          <button class=\"run-btn\" data-run=\"go11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">func</span> <span class=\"tok-fn\">bagi</span>(<span class=\"tok-var\">a</span>, <span class=\"tok-var\">b</span> <span class=\"tok-kw\">int</span>) (<span class=\"tok-kw\">int</span>, <span class=\"tok-var\">error</span>) {\r\n    <span class=\"tok-kw\">if</span> <span class=\"tok-var\">b</span> == <span class=\"tok-num\">0</span> {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-num\">0</span>, <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Errorf</span>(<span class=\"tok-str\">\"tidak bisa bagi nol\"</span>)\r\n    }\r\n    <span class=\"tok-kw\">return</span> <span class=\"tok-var\">a</span> / <span class=\"tok-var\">b</span>, <span class=\"tok-kw\">nil</span>\r\n}\r\n<span class=\"tok-var\">hasil</span>, <span class=\"tok-var\">err</span> := <span class=\"tok-fn\">bagi</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">0</span>)\r\n<span class=\"tok-kw\">if</span> <span class=\"tok-var\">err</span> != <span class=\"tok-kw\">nil</span> {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-str\">\"Error:\"</span>, <span class=\"tok-var\">err</span>)\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>fmt.Errorf()</code> membuat error dengan format dinamis. Jangan gunakan <code>_</code> untuk mengabaikan error — selalu cek dengan <code>if err != nil</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"go-12\">Lanjut: Package & Module →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Go Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"go-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Package & Module</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Setiap file Go adalah bagian dari sebuah <strong>package</strong>. <code>go mod init</code> memulai module baru. Fungsi yang diawali huruf besar bersifat <strong>exported</strong> (public), huruf kecil bersifat <strong>unexported</strong> (private).</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>package.go</div>\r\n          <button class=\"run-btn\" data-run=\"go12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">package</span> <span class=\"tok-var\">main</span>\r\n<span class=\"tok-kw\">import</span> (\r\n    <span class=\"tok-str\">\"fmt\"</span>\r\n    <span class=\"tok-str\">\"math\"</span>\r\n)\r\n<span class=\"tok-kw\">func</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-var\">fmt</span>.<span class=\"tok-fn\">Println</span>(<span class=\"tok-var\">math</span>.<span class=\"tok-fn\">Sqrt</span>(<span class=\"tok-num\">144</span>))\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-go12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Nama package biasanya sama dengan nama direktori. <code>go mod init nama-modul</code> untuk memulai module, lalu <code>go build</code> untuk kompilasi.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Fungsi Go yang diawali huruf kapital bersifat?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Exported (public)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Unexported (private)</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Hanya bisa dipakai di file yang sama</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"go-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'go\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\n\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'go-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#FFC93C', NULL, '2026-07-03 13:09:45', '2026-07-04 18:25:44');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(9, 'ruby', 'Ruby Programming', 'Elegant & Productive', 'beginner', 'Ruby', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>Ruby — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">Ruby</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"ruby\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">Ruby</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"ruby\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"ruby\">\r\n      <div class=\"topic-item active\" data-topic=\"ruby-1\"><span class=\"topic-check\"></span>Apa itu Ruby?</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-2\"><span class=\"topic-check\"></span>Variabel & Tipe</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-3\"><span class=\"topic-check\"></span>Kondisi & Unless</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-4\"><span class=\"topic-check\"></span>Perulangan & Each</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-5\"><span class=\"topic-check\"></span>Array & Hash</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-6\"><span class=\"topic-check\"></span>Method & Block</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-7\"><span class=\"topic-check\"></span>Class & Object</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-8\"><span class=\"topic-check\"></span>Symbol & Module</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-9\"><span class=\"topic-check\"></span>Enumerable</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-10\"><span class=\"topic-check\"></span>File I/O</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-11\"><span class=\"topic-check\"></span>Exception</div>\r\n      <div class=\"topic-item\" data-topic=\"ruby-12\"><span class=\"topic-check\"></span>Mixin & Inheritance</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= RUBY ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"ruby\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 09 · BAHASA ELEGAN & PRODUKTIF</div>\r\n        <h1 class=\"lang-title\">Ruby</h1>\r\n        <p class=\"lang-desc\">Dirancang untuk produktivitas dan kebahagiaan developer. Sintaks Ruby sangat alami dan ekspresif — populer lewat framework web Ruby on Rails.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">RB</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"ruby-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu Ruby?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby diciptakan Yukihiro Matsumoto (Matz) di Jepang dengan filosofi: <strong>\"Optimized for developer happiness\"</strong>. Sintaksnya sangat alami — hampir seperti membaca bahasa Inggris. Ruby populer berkat framework Ruby on Rails yang memperkenalkan banyak konsep yang kini jadi standar web development.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"LearnBase\"</span>\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Halo, #{nama}\"</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>puts</code> = put string — mencetak teks diikuti baris baru. <code>print</code> tanpa baris baru, <code>p</code> untuk debugging.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-2\">Lanjut: Variabel & Tipe →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel & Tipe</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby adalah <strong>dynamically typed</strong>. Tipe dasar: <code>Integer</code>, <code>Float</code>, <code>String</code>, <code>Symbol</code>, <code>Array</code>, <code>Hash</code>. Semua di Ruby adalah objek — bahkan angka!</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>var.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>\r\n<span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Ruby Dasar\"</span>\r\n<span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"#{nama}: #{lulus}, tipe: #{lulus.class}\"</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Di Ruby, <code>#{nama}</code> untuk interpolasi string (mirip f-string Python). Setiap variabel punya method <code>.class</code> untuk cek tipe.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-3\">Lanjut: Kondisi & Unless →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi & Unless</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby punya <code>if</code> dan <code>unless</code> (kebalikan if). <code>unless</code> menjalankan kode jika kondisi <strong>false</strong>. Ini membuat kode lebih alami untuk kondisi negatif.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>kondisi.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">nilai</span> = <span class=\"tok-num\">85</span>\r\n<span class=\"tok-kw\">if</span> <span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">80</span>\r\n    <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Baik\"</span>\r\n<span class=\"tok-kw\">end</span>\r\n<span class=\"tok-kw\">unless</span> <span class=\"tok-var\">nilai</span> &lt; <span class=\"tok-num\">60</span>\r\n    <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Tidak remedial\"</span>\r\n<span class=\"tok-kw\">end</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Ruby juga punya <em>modifier form</em>: <code>puts \"Lulus\" if skor >= 70</code> — kondisi ditulis di akhir baris.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-4\">Lanjut: Perulangan & Each →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Perulangan & Each</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby lebih sering pakai <code>.each</code> daripada <code>for</code>. <code>each</code> adalah method yang menerima <em>block</em> — blok kode di antara <code>do...end</code> atau <code>{ }</code>. Ini adalah pola iterasi utama Ruby.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>each.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\">[<span class=\"tok-str\">\"HTML\"</span>, <span class=\"tok-str\">\"CSS\"</span>, <span class=\"tok-str\">\"JS\"</span>].<span class=\"tok-fn\">each</span> <span class=\"tok-kw\">do</span> |<span class=\"tok-var\">m</span>|\r\n    <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Modul: #{m}\"</span>\r\n<span class=\"tok-kw\">end</span>\r\n\r\n(<span class=\"tok-num\">1</span>..<span class=\"tok-num\">3</span>).<span class=\"tok-fn\">each</span> { |<span class=\"tok-var\">i</span>| <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"#{i}. Belajar\"</span> }</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>do |var| ... end</code> dan <code>{ |var| ... }</code> adalah <em>block</em> — fitur paling khas Ruby. <code>|var|</code> adalah parameter blok.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-5\">Lanjut: Array & Hash →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Array & Hash</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Array</strong> indeks dimulai 0. <strong>Hash</strong> adalah dictionary/koleksi key-value — mirip Object JS atau dict Python. Ruby punya banyak method untuk transformasi array seperti <code>map</code>, <code>select</code>, <code>reduce</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>hash.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">pengguna</span> = { <span class=\"tok-var\">nama</span>: <span class=\"tok-str\">\"Citra\"</span>, <span class=\"tok-var\">skor</span>: <span class=\"tok-num\">92</span> }\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"#{pengguna[:nama]}: #{pengguna[:skor]}\"</span>\r\n\r\n<span class=\"tok-var\">angka</span> = [<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">3</span>]\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">map</span> { |<span class=\"tok-var\">n</span>| <span class=\"tok-var\">n</span> * <span class=\"tok-var\">n</span> }</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>{ nama: \"Citra\" }</code> adalah sintaks Ruby modern untuk hash dengan key symbol. Setara dengan <code>{ :nama => \"Citra\" }</code>.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-6\">Lanjut: Method & Block →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Method & Block</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Method</strong> didefinisikan dengan <code>def</code>. Ruby mengembalikan nilai terakhir yang dievaluasi — tidak perlu <code>return</code> eksplisit. <strong>Block</strong> bisa diterima method dengan <code>yield</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>method.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">def</span> <span class=\"tok-fn\">sapa</span>(<span class=\"tok-var\">nama</span>)\r\n    <span class=\"tok-str\">\"Halo #{nama}\"</span>\r\n<span class=\"tok-kw\">end</span>\r\n\r\n<span class=\"tok-kw\">def</span> <span class=\"tok-fn\">ulang</span>(<span class=\"tok-var\">kali</span>)\r\n    <span class=\"tok-var\">kali</span>.<span class=\"tok-fn\">times</span> { <span class=\"tok-fn\">yield</span> }\r\n<span class=\"tok-kw\">end</span>\r\n\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-fn\">sapa</span>(<span class=\"tok-str\">\"Budi\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Ruby tidak punya <code>return</code> eksplisit — nilai baris terakhir method otomatis dikembalikan. <code>yield</code> memanggil block yang diberikan.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-7\">Lanjut: Class & Object →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Class & Object</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Di Ruby, <strong>semuanya adalah objek</strong> — termasuk angka, string, bahkan <code>nil</code>. Class didefinisikan dengan <code>class</code>, dan <code>attr_accessor</code> untuk membuat getter/setter otomatis.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>class.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span>\r\n    <span class=\"tok-kw\">attr_accessor</span> :<span class=\"tok-var\">nama</span>, :<span class=\"tok-var\">skor</span>\r\n\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">initialize</span>(<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>)\r\n        @<span class=\"tok-var\">nama</span> = <span class=\"tok-var\">nama</span>\r\n        @<span class=\"tok-var\">skor</span> = <span class=\"tok-var\">skor</span>\r\n    <span class=\"tok-kw\">end</span>\r\n<span class=\"tok-kw\">end</span>\r\n<span class=\"tok-var\">s</span> = <span class=\"tok-var\">Siswa</span>.<span class=\"tok-fn\">new</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>)\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"#{s.nama}: #{s.skor}\"</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>@nama</code> = <em>instance variable</em>. <code>attr_accessor :nama</code> membuat method <code>nama</code> dan <code>nama=</code> secara otomatis.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-8\">Lanjut: Symbol & Module →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"ruby-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Symbol & Module</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Symbol</strong> (<code>:nama</code>) adalah string khusus yang dioptimalkan untuk perbandingan — lebih cepat dari string biasa. <strong>Module</strong> adalah kumpulan method yang bisa dicampurkan (<em>mixin</em>) ke class dengan <code>include</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>module.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">module</span> <span class=\"tok-var\">Export</span>\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">ke_json</span>\r\n        <span class=\"tok-str\">\"{nama: #{@nama}}\"</span>\r\n    <span class=\"tok-kw\">end</span>\r\n<span class=\"tok-kw\">end</span>\r\n\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span>\r\n    <span class=\"tok-kw\">include</span> <span class=\"tok-var\">Export</span>\r\n<span class=\"tok-kw\">end</span>\r\n\r\n<span class=\"tok-fn\">puts</span> <span class=\"tok-var\">Siswa</span>.<span class=\"tok-fn\">new</span>.<span class=\"tok-fn\">ke_json</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword output Ruby untuk cetak + baris baru?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">print</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">puts</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">echo</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-9\">Lanjut: Enumerable →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Ruby Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"ruby-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Enumerable</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Enumerable</strong> adalah modul inti Ruby dengan puluhan method untuk koleksi — <code>map</code>, <code>select</code>, <code>reduce</code>, <code>sort_by</code>, <code>each_with_index</code>. Cukup <code>include Enumerable</code> dan implementasi <code>each</code>.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>enumerable.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">angka</span> = [<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span class=\"tok-num\">3</span>, <span class=\"tok-num\">4</span>, <span class=\"tok-num\">5</span>]\r\n<span class=\"tok-var\">genap</span> = <span class=\"tok-var\">angka</span>.<span class=\"tok-fn\">select</span> { |<span class=\"tok-var\">n</span>| <span class=\"tok-var\">n</span>.<span class=\"tok-fn\">even?</span> }\r\n<span class=\"tok-var\">kuadrat</span> = <span class=\"tok-var\">genap</span>.<span class=\"tok-fn\">map</span> { |<span class=\"tok-var\">n</span>| <span class=\"tok-var\">n</span> * <span class=\"tok-var\">n</span> }\r\n<span class=\"tok-fn\">p</span> <span class=\"tok-var\">genap</span>\r\n<span class=\"tok-fn\">p</span> <span class=\"tok-var\">kuadrat</span>\r\n<span class=\"tok-fn\">p</span> <span class=\"tok-var\">kuadrat</span>.<span class=\"tok-fn\">reduce</span>(:<span class=\"tok-var\">+</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>p</code> mencetak representasi objek lebih detail daripada <code>puts</code> — berguna untuk debugging.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-10\">Lanjut: File I/O →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Ruby Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"ruby-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">File I/O</h2>\r\n      <div class=\"topic-body\">\r\n        <p>API file Ruby elegan: <code>File.read</code>, <code>File.readlines</code>, <code>File.write</code>. <code>File.open</code> dengan block otomatis menutup file.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>file.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-var\">File</span>.<span class=\"tok-fn\">write</span>(<span class=\"tok-str\">\"progres.txt\"</span>, <span class=\"tok-str\">\"Modul Ruby: 100%\"</span>)\r\n<span class=\"tok-var\">File</span>.<span class=\"tok-fn\">open</span>(<span class=\"tok-str\">\"progres.txt\"</span>, <span class=\"tok-str\">\"r\"</span>) <span class=\"tok-kw\">do</span> |<span class=\"tok-var\">f</span>|\r\n    <span class=\"tok-var\">f</span>.<span class=\"tok-fn\">each_line</span> { |<span class=\"tok-var\">line</span>| <span class=\"tok-fn\">puts</span> <span class=\"tok-var\">line</span> }\r\n<span class=\"tok-kw\">end</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>File.open</code> dengan block otomatis close — mencegah kebocoran memori.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-11\">Lanjut: Exception →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Ruby Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"ruby-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Exception</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby pakai <code>begin/rescue/end</code>. <code>ensure</code> selalu jalan. <code>raise</code> untuk melempar exception.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>exception.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">begin</span>\r\n    <span class=\"tok-var\">hasil</span> = <span class=\"tok-num\">10</span> / <span class=\"tok-num\">0</span>\r\n<span class=\"tok-kw\">rescue</span> <span class=\"tok-var\">ZeroDivisionError</span> => <span class=\"tok-var\">e</span>\r\n    <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Error: #{e.message}\"</span>\r\n<span class=\"tok-kw\">ensure</span>\r\n    <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"Selesai\"</span>\r\n<span class=\"tok-kw\">end</span></div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>raise</code> melempar exception. <code>retry</code> di rescue untuk mencoba ulang.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"ruby-12\">Lanjut: Mixin & Inheritance →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Ruby Topic 12 -->\r\n    <article class=\"topic-section\" data-topic=\"ruby-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Mixin & Inheritance</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Ruby punya single inheritance + multiple mixin. <code>include</code> untuk instance method, <code>extend</code> untuk class method.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>mixin.rb</div>\r\n          <button class=\"run-btn\" data-run=\"ruby12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">module</span> <span class=\"tok-var\">Loggable</span>\r\n    <span class=\"tok-kw\">def</span> <span class=\"tok-fn\">log</span>(<span class=\"tok-var\">msg</span>)\r\n        <span class=\"tok-fn\">puts</span> <span class=\"tok-str\">\"[LOG] #{msg}\"</span>\r\n    <span class=\"tok-kw\">end</span>\r\n<span class=\"tok-kw\">end</span>\r\n<span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span>\r\n    <span class=\"tok-kw\">include</span> <span class=\"tok-var\">Loggable</span>\r\n<span class=\"tok-kw\">end</span>\r\n<span class=\"tok-var\">Siswa</span>.<span class=\"tok-fn\">new</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Belajar Ruby mixin\"</span>)</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-ruby12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword mixin untuk instance method?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"true\">include</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">extend</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">prepend</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"ruby-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'ruby\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'ruby-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#0E6853', NULL, '2026-07-03 13:09:45', '2026-07-04 18:25:44');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(10, 'rust', 'Rust Programming', 'Safe & Fast', 'advanced', 'Rust', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>Rust — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">Rust</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"rust\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">Rust</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"rust\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"rust\">\r\n      <div class=\"topic-item active\" data-topic=\"rust-1\"><span class=\"topic-check\"></span>Apa itu Rust?</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-2\"><span class=\"topic-check\"></span>Variabel &amp; Mutability</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-3\"><span class=\"topic-check\"></span>Tipe Data</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-4\"><span class=\"topic-check\"></span>Kondisi &amp; Perulangan</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-5\"><span class=\"topic-check\"></span>Fungsi &amp; Ownership</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-6\"><span class=\"topic-check\"></span>Struct &amp; impl</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-7\"><span class=\"topic-check\"></span>Enum &amp; Pattern</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-8\"><span class=\"topic-check\"></span>Error Handling</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-9\"><span class=\"topic-check\"></span>Collection &amp; Iterator</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-10\"><span class=\"topic-check\"></span>String vs &amp;str</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-11\"><span class=\"topic-check\"></span>Generic &amp; Trait</div>\r\n      <div class=\"topic-item\" data-topic=\"rust-12\"><span class=\"topic-check\"></span>Cargo &amp; Crates</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= Rust ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"rust\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 10 · BAHASA SISTEM AMAN &AMP; CEPAT</div>\r\n        <h1 class=\"lang-title\">Rust</h1>\r\n        <p class=\"lang-desc\">Bahasa sistem yang menjamin <strong>memory safety tanpa garbage collector</strong>. Performa setara C++ dengan sistem ownership yang unik — dipakai di browser, CLI tools, dan sistem kritikal.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">RS</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"rust-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu Rust?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust dikembangkan Mozilla dengan tujuan: <strong>kecepatan C++ + keamanan memori tanpa GC</strong>. Kunci utamanya adalah <em>ownership system</em> yang diperiksa saat kompilasi — mencegah bug memori (null pointer, use-after-free) tanpa perlu garbage collector. Rust dinobatkan sebagai \"most loved language\" di Stack Overflow bertahun-turut.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>main.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">let</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n    <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"Halo, {}!\"</span>, <span class=\"tok-var\">nama</span>);\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust1\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>println!</code> dengan tanda seru adalah <strong>macro</strong>, bukan fungsi. <code>{}</code> adalah placeholder yang diisi nilai setelah koma.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-2\">Lanjut: Variabel &amp; Mutability →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">Variabel &amp; Mutability</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Di Rust, variabel <strong>immutable secara default</strong> — nilainya tidak bisa diubah setelah ditetapkan. Untuk mengubah, perlu keyword <code>mut</code>. Ini adalah fitur yang mendorong kode yang lebih aman.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>var.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">let</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">87</span>;\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-kw\">mut</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Rust Dasar\"</span>;\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">lulus</span> = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>;\r\n\r\n<span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"Rust Lanjutan\"</span>;\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}: {} (skor {})\"</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">lulus</span>, <span class=\"tok-var\">skor</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust2\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Jika kamu hapus <code>mut</code> dari kode di atas, Rust akan menolak kompilasi — \"cannot assign to immutable variable\". Ini fitur, bukan error!</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-3\">Lanjut: Tipe Data →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">Tipe Data</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust punya <code>i32</code>, <code>u32</code>, <code>f64</code>, <code>bool</code>, <code>char</code>, <code>String</code>, dan <code>&amp;str</code> (string slice). Tipe ditentukan dengan <code>:</code> setelah nama variabel, atau dibiarkan di-inference.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>tipe.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">let</span> <span class=\"tok-var\">x</span>: <span class=\"tok-kw\">i32</span> = <span class=\"tok-num\">42</span>;\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">y</span> = <span class=\"tok-num\">3.14</span>;\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">teks</span> = <span class=\"tok-str\">\"Hello\"</span>;\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">s</span> = <span class=\"tok-var\">String</span>::<span class=\"tok-fn\">from</span>(<span class=\"tok-str\">\"LearnBase\"</span>);\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{} {} {} {}\"</span>, <span class=\"tok-var\">x</span>, <span class=\"tok-var\">y</span>, <span class=\"tok-var\">teks</span>, <span class=\"tok-var\">s</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust3\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>String</code> = string yang bisa diubah-ubah (heap). <code>&amp;str</code> = string literal / slice (immutable, biasanya di stack).</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-4\">Lanjut: Kondisi &amp; Perulangan →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">Kondisi &amp; Perulangan</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust pakai <code>if/else</code> tanpa kurung, dan <code>loop</code>, <code>while</code>, <code>for</code>. <code>for</code> dengan <code>in</code> untuk iterasi range atau koleksi. <code>match</code> adalah pattern matching super kuat — mirip switch on steroids.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>loop.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">for</span> <span class=\"tok-var\">i</span> <span class=\"tok-kw\">in</span> <span class=\"tok-num\">1</span>..=<span class=\"tok-num\">3</span> {\r\n    <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"Modul {}\"</span>, <span class=\"tok-var\">i</span>);\r\n}\r\n\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">nilai</span> = <span class=\"tok-num\">85</span>;\r\n<span class=\"tok-kw\">match</span> <span class=\"tok-var\">nilai</span> {\r\n    <span class=\"tok-num\">90</span>..=<span class=\"tok-num\">100</span> => <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"A\"</span>),\r\n    <span class=\"tok-num\">80</span>..=<span class=\"tok-num\">89</span> => <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"B\"</span>),\r\n    _ => <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"C\"</span>),\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust4\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>1..=3</code> = range inklusif (1 sampai 3). <code>1..3</code> = eksklusif (1,2). <code>match</code> bersifat <em>exhaustive</em> — harus mencakup semua kemungkinan.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-5\">Lanjut: Fungsi &amp; Ownership →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">Fungsi &amp; Ownership</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Ownership</strong> adalah konsep paling penting di Rust — setiap nilai punya satu <em>owner</em>. Saat owner keluar scope, nilai dihapus. Fungsi bisa meminjam (<code>&amp;</code>) atau mengambil alih kepemilikan.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>ownership.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">hitung_panjang</span>(<span class=\"tok-var\">s</span>: &amp;<span class=\"tok-var\">String</span>) -> <span class=\"tok-kw\">usize</span> {\r\n    <span class=\"tok-var\">s</span>.<span class=\"tok-fn\">len</span>()\r\n}\r\n\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-var\">String</span>::<span class=\"tok-fn\">from</span>(<span class=\"tok-str\">\"LearnBase\"</span>);\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">panjang</span> = <span class=\"tok-fn\">hitung_panjang</span>(&amp;<span class=\"tok-var\">nama</span>);\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"\'{}\' panjang {}\"</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">panjang</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust5\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>&amp;</code> = <em>borrow</em> (pinjam) — fungsi bisa membaca tanpa mengambil alih kepemilikan. <code>&amp;mut</code> = pinjam sambil boleh diubah.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-6\">Lanjut: Struct &amp; impl →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">Struct &amp; impl</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Struct</strong> mengelompokkan data. Blok <strong>impl</strong> untuk mendefinisikan method pada struct — mirip class di bahasa lain, tapi tanpa inheritance.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>struct.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">struct</span> <span class=\"tok-var\">Siswa</span> {\r\n    <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">String</span>,\r\n    <span class=\"tok-var\">skor</span>: <span class=\"tok-kw\">i32</span>,\r\n}\r\n<span class=\"tok-kw\">impl</span> <span class=\"tok-var\">Siswa</span> {\r\n    <span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">cetak</span>(&amp;<span class=\"tok-kw\">self</span>) {\r\n        <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}: {}\"</span>, <span class=\"tok-kw\">self</span>.<span class=\"tok-var\">nama</span>, <span class=\"tok-kw\">self</span>.<span class=\"tok-var\">skor</span>);\r\n    }\r\n}\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">s</span> = <span class=\"tok-var\">Siswa</span> { <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">String</span>::<span class=\"tok-fn\">from</span>(<span class=\"tok-str\">\"Budi\"</span>), <span class=\"tok-var\">skor</span>: <span class=\"tok-num\">87</span> };\r\n<span class=\"tok-var\">s</span>.<span class=\"tok-fn\">cetak</span>();</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust6\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>&amp;self</code> = method yang meminjam struct (baca). <code>&amp;mut self</code> = bisa ubah struct. <code>self</code> = mengambil alih kepemilikan.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-7\">Lanjut: Enum &amp; Pattern →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"rust-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">Enum &amp; Pattern</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Enum</strong> di Rust sangat kuat — setiap varian bisa membawa data. <strong>Pattern matching</strong> dengan <code>match</code> digunakan untuk menangani enum. Ini lebih aman daripada null/exception karena semua kemungkinan harus ditangani.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>enum.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">enum</span> <span class=\"tok-var\">Nilai</span> {\r\n    <span class=\"tok-var\">Angka</span>(<span class=\"tok-kw\">i32</span>),\r\n    <span class=\"tok-var\">Huruf</span>(<span class=\"tok-var\">String</span>),\r\n}\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">x</span> = <span class=\"tok-var\">Nilai</span>::<span class=\"tok-var\">Angka</span>(<span class=\"tok-num\">85</span>);\r\n<span class=\"tok-kw\">match</span> <span class=\"tok-var\">x</span> {\r\n    <span class=\"tok-var\">Nilai</span>::<span class=\"tok-var\">Angka</span>(<span class=\"tok-var\">n</span>) => <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"Angka: {}\"</span>, <span class=\"tok-var\">n</span>),\r\n    <span class=\"tok-var\">Nilai</span>::<span class=\"tok-var\">Huruf</span>(<span class=\"tok-var\">h</span>) => <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"Huruf: {}\"</span>, <span class=\"tok-var\">h</span>),\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust7\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>Option&lt;T&gt;</code> dan <code>Result&lt;T, E&gt;</code> adalah enum paling sering dipakai — menggantikan null dan exception.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-8\">Lanjut: Error Handling →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Rust Topic 8 -->\r\n    <article class=\"topic-section\" data-topic=\"rust-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">Error Handling</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust tidak punya exception. Error ditangani via <code>Result&lt;T, E&gt;</code> (ok/err) dan <code>Option&lt;T&gt;</code> (some/none). Operator <code>?</code> menyebarkan error ke pemanggil — membuat kode tetap bersih.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>error.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">bagi</span>(<span class=\"tok-var\">a</span>: <span class=\"tok-kw\">i32</span>, <span class=\"tok-var\">b</span>: <span class=\"tok-kw\">i32</span>) -> <span class=\"tok-var\">Result</span>&lt;<span class=\"tok-kw\">i32</span>, <span class=\"tok-var\">String</span>&gt; {\r\n    <span class=\"tok-kw\">if</span> <span class=\"tok-var\">b</span> == <span class=\"tok-num\">0</span> {\r\n        <span class=\"tok-kw\">return</span> <span class=\"tok-var\">Err</span>(<span class=\"tok-str\">\"Tidak bisa bagi nol\"</span>.<span class=\"tok-fn\">to_string</span>());\r\n    }\r\n    <span class=\"tok-var\">Ok</span>(<span class=\"tok-var\">a</span> / <span class=\"tok-var\">b</span>)\r\n}\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{:?}\"</span>, <span class=\"tok-fn\">bagi</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">2</span>));\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{:?}\"</span>, <span class=\"tok-fn\">bagi</span>(<span class=\"tok-num\">10</span>, <span class=\"tok-num\">0</span>));</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust8\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword di Rust untuk membuat variabel bisa diubah?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">var</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">mut</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">changeable</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-9\">Lanjut: Collection &amp; Iterator →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Rust Topic 9 -->\r\n    <article class=\"topic-section\" data-topic=\"rust-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Collection &amp; Iterator</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust menyediakan <strong>collection</strong> standar seperti <code>Vec&lt;T&gt;</code> (vector), <code>HashMap&lt;K, V&gt;</code>, dan <code>HashSet&lt;T&gt;</code>. Yang membedakan Rust adalah <strong>iterator adaptor</strong> — metode seperti <code>.iter()</code>, <code>.map()</code>, <code>.filter()</code>, <code>.collect()</code> yang membentuk pipeline tanpa alokasi perantara.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>collection.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">use</span> <span class=\"tok-var\">std</span>::<span class=\"tok-var\">collections</span>::<span class=\"tok-var\">HashMap</span>;\r\n\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-kw\">mut</span> <span class=\"tok-var\">nilai</span> = <span class=\"tok-var\">HashMap</span>::<span class=\"tok-fn\">new</span>();\r\n<span class=\"tok-var\">nilai</span>.<span class=\"tok-fn\">insert</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>);\r\n<span class=\"tok-var\">nilai</span>.<span class=\"tok-fn\">insert</span>(<span class=\"tok-str\">\"Ani\"</span>, <span class=\"tok-num\">95</span>);\r\n\r\n<span class=\"tok-kw\">for</span> (<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>) <span class=\"tok-kw\">in</span> <span class=\"tok-var\">&amp;nilai</span> {\r\n    <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}: {}\"</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>);\r\n}\r\n\r\n<span class=\"tok-cm\">// Iterator pipeline</span>\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">genap</span>: <span class=\"tok-var\">Vec</span>&lt;<span class=\"tok-kw\">i32</span>&gt; = (<span class=\"tok-num\">1</span>..=<span class=\"tok-num\">6</span>)\r\n    .<span class=\"tok-fn\">filter</span>(|<span class=\"tok-var\">x</span>| <span class=\"tok-var\">x</span> % <span class=\"tok-num\">2</span> == <span class=\"tok-num\">0</span>)\r\n    .<span class=\"tok-fn\">map</span>(|<span class=\"tok-var\">x</span>| <span class=\"tok-var\">x</span> * <span class=\"tok-var\">x</span>)\r\n    .<span class=\"tok-fn\">collect</span>();\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{:?}\"</span>, <span class=\"tok-var\">genap</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust9\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Iterator di Rust <em>lazy</em> — tidak memproses apa pun sampai <code>.collect()</code> atau <code>.for_each()</code> dipanggil. Ini memungkinkan rantai operasi tanpa alokasi perantara yang boros.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-10\">Lanjut: String vs &amp;str →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Rust Topic 10 -->\r\n    <article class=\"topic-section\" data-topic=\"rust-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">String vs &amp;str</h2>\r\n      <div class=\"topic-body\">\r\n        <p>Rust punya dua tipe string: <code>String</code> (owned, heap-allocated, bisa diubah) dan <code>&amp;str</code> (string slice, read-only reference ke sebagian string). Konversi: <code>\"teks\".to_string()</code> atau <code>String::from(\"teks\")</code>. <code>&amp;str</code> lebih ringan dan tidak punya alokasi — ideal sebagai parameter fungsi.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>string.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11</div>\r\n          <div class=\"code-content\"><span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">sapa</span>(<span class=\"tok-var\">nama</span>: &amp;<span class=\"tok-kw\">str</span>) -> <span class=\"tok-var\">String</span> {\r\n    <span class=\"tok-kw\">let</span> <span class=\"tok-kw\">mut</span> <span class=\"tok-var\">hasil</span> = <span class=\"tok-var\">String</span>::<span class=\"tok-fn\">from</span>(<span class=\"tok-str\">\"Halo, \"</span>);\r\n    <span class=\"tok-var\">hasil</span>.<span class=\"tok-fn\">push_str</span>(<span class=\"tok-var\">nama</span>);\r\n    <span class=\"tok-var\">hasil</span>\r\n}\r\n\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\"LearnBase\"</span>;        <span class=\"tok-cm\">// &amp;str</span>\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">msg</span> = <span class=\"tok-fn\">sapa</span>(<span class=\"tok-var\">nama</span>);\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}\"</span>, <span class=\"tok-var\">msg</span>);\r\n\r\n<span class=\"tok-cm\">// slicing &amp;str</span>\r\n<span class=\"tok-kw\">let</span> <span class=\"tok-var\">kalimat</span> = <span class=\"tok-str\">\"Selamat belajar Rust\"</span>;\r\n<span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}\"</span>, &amp;<span class=\"tok-var\">kalimat</span>[<span class=\"tok-num\">0</span>..<span class=\"tok-num\">7</span>]);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust10\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Indexing string di Rust tidak bisa dengan <code>s[0]</code> seperti C — karena Rust menggunakan UTF-8, satu karakter bisa lebih dari 1 byte. Gunakan <code>.chars()</code> atau <code>.bytes()</code> untuk iterasi.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-11\">Lanjut: Generic &amp; Trait →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Rust Topic 11 -->\r\n    <article class=\"topic-section\" data-topic=\"rust-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">Generic &amp; Trait</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Generic</strong> memungkinkan fungsi/struct bekerja dengan banyak tipe — ditulis <code>&lt;T&gt;</code>. <strong>Trait</strong> mirip interface di bahasa lain: mendefinisikan perilaku bersama. Trait bisa memiliki implementasi default, dan tipe bisa mengimplementasikan banyak trait.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>trait.rs</div>\r\n          <button class=\"run-btn\" data-run=\"rust11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">// Definisikan trait</span>\r\n<span class=\"tok-kw\">trait</span> <span class=\"tok-var\">Nilai</span> {\r\n    <span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">skor</span>(&amp;<span class=\"tok-kw\">self</span>) -> <span class=\"tok-kw\">u32</span>;\r\n}\r\n\r\n<span class=\"tok-cm\">// Generic struct + trait bound</span>\r\n<span class=\"tok-kw\">struct</span> <span class=\"tok-var\">Siswa</span>&lt;<span class=\"tok-var\">T</span>: <span class=\"tok-var\">Nilai</span>&gt; {\r\n    <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">String</span>,\r\n    <span class=\"tok-var\">nilai</span>: <span class=\"tok-var\">T</span>,\r\n}\r\n\r\n<span class=\"tok-cm\">// Implementasi trait untuk tipe berbeda</span>\r\n<span class=\"tok-kw\">impl</span> <span class=\"tok-var\">Nilai</span> <span class=\"tok-kw\">for</span> <span class=\"tok-kw\">u32</span> {\r\n    <span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">skor</span>(&amp;<span class=\"tok-kw\">self</span>) -> <span class=\"tok-kw\">u32</span> { *<span class=\"tok-kw\">self</span> }\r\n}\r\n\r\n<span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">cetak_nilai</span>&lt;<span class=\"tok-var\">T</span>: <span class=\"tok-var\">Nilai</span>&gt;(<span class=\"tok-var\">nama</span>: &amp;<span class=\"tok-kw\">str</span>, <span class=\"tok-var\">t</span>: <span class=\"tok-var\">T</span>) {\r\n    <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"{}: {}\"</span>, <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">t</span>.<span class=\"tok-fn\">skor</span>());\r\n}\r\n\r\n<span class=\"tok-fn\">cetak_nilai</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87u32</span>);\r\n<span class=\"tok-fn\">cetak_nilai</span>(<span class=\"tok-str\">\"Ani\"</span>, <span class=\"tok-num\">95u32</span>);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust11\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Gunakan <code>impl Trait</code> sebagai singkatan parameter — <code>fn foo(x: impl Display)</code> sama dengan <code>fn foo&lt;T: Display&gt;(x: T)</code> untuk satu parameter.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"rust-12\">Lanjut: Cargo &amp; Crates →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <!-- Rust Topic 12 (Final) -->\r\n    <article class=\"topic-section\" data-topic=\"rust-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Cargo &amp; Crates</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Cargo</strong> adalah package manager dan build system Rust — seperti npm untuk JS atau pip untuk Python. File <code>Cargo.toml</code> mendefinisikan metadata proyek dan <em>dependencies</em>. <strong>Crate</strong> adalah paket kode Rust (library atau binary) yang dihosting di <strong>crates.io</strong>. Cukup tambahkan nama crate di <code>Cargo.toml</code> lalu <code>cargo build</code> — semuanya otomatis diunduh dan dikompilasi.</p>\r\n      </div>\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>Cargo.toml</div>\r\n          <button class=\"run-btn\" data-run=\"rust12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\"># Cargo.toml — file konfigurasi proyek Rust</span>\r\n[<span class=\"tok-var\">package</span>]\r\n<span class=\"tok-var\">name</span> = <span class=\"tok-str\">\"belajar-rust\"</span>\r\n<span class=\"tok-var\">version</span> = <span class=\"tok-str\">\"0.1.0\"</span>\r\n<span class=\"tok-var\">edition</span> = <span class=\"tok-str\">\"2021\"</span>\r\n\r\n<span class=\"tok-cm\"># Tambahkan dependencies dari crates.io</span>\r\n[<span class=\"tok-var\">dependencies</span>]\r\n<span class=\"tok-var\">serde</span> = { <span class=\"tok-var\">version</span> = <span class=\"tok-str\">\"1\"</span>, <span class=\"tok-var\">features</span> = [<span class=\"tok-str\">\"derive\"</span>] }\r\n<span class=\"tok-var\">reqwest</span> = { <span class=\"tok-var\">version</span> = <span class=\"tok-str\">\"0.12\"</span>, <span class=\"tok-var\">features</span> = [<span class=\"tok-str\">\"json\"</span>] }\r\n\r\n<span class=\"tok-cm\">// src/main.rs — kode utama</span>\r\n<span class=\"tok-kw\">use</span> <span class=\"tok-var\">serde</span>::{<span class=\"tok-var\">Serialize</span>, <span class=\"tok-var\">Deserialize</span>};\r\n\r\n#[<span class=\"tok-fn\">derive</span>(<span class=\"tok-var\">Serialize</span>, <span class=\"tok-var\">Deserialize</span>)]\r\n<span class=\"tok-kw\">struct</span> <span class=\"tok-var\">Modul</span> {\r\n    <span class=\"tok-var\">judul</span>: <span class=\"tok-var\">String</span>,\r\n    <span class=\"tok-var\">skor</span>: <span class=\"tok-kw\">u32</span>,\r\n}\r\n\r\n<span class=\"tok-kw\">fn</span> <span class=\"tok-fn\">main</span>() {\r\n    <span class=\"tok-kw\">let</span> <span class=\"tok-var\">m</span> = <span class=\"tok-var\">Modul</span> { <span class=\"tok-var\">judul</span>: <span class=\"tok-str\">\"Rust\"</span>.<span class=\"tok-fn\">into</span>(), <span class=\"tok-var\">skor</span>: <span class=\"tok-num\">92</span> };\r\n    <span class=\"tok-fn\">println!</span>(<span class=\"tok-str\">\"JSON: {}\"</span>, <span class=\"tok-var\">serde_json</span>::<span class=\"tok-fn\">to_string</span>(&amp;<span class=\"tok-var\">m</span>).<span class=\"tok-fn\">unwrap</span>());\r\n}</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-rust12\"></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Perintah <code>cargo init</code> langsung membuat proyek baru. <code>cargo check</code> memvalidasi kode tanpa menghasilkan binary (jauh lebih cepat dari <code>cargo build</code>). Gunakan <code>cargo add serde</code> untuk menambahkan dependency dari terminal.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: File apa yang berisi daftar dependencies di proyek Rust?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">package.json</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Cargo.toml</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Rust.toml</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"rust-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'rust\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'rust-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#3A3A3A', NULL, '2026-07-03 13:09:45', '2026-07-04 16:43:56');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(11, 'typescript', 'TypeScript', 'TypeScript Superset', 'intermediate', 'TypeScript', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>TypeScript — LearnBase</title>\r\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n  <link\r\n    href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\"\r\n    rel=\"stylesheet\">\r\n  <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n  <link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n  <style>\r\n    .content-panel .lang-eyebrow {\r\n      color: #6B4FD8;\r\n    }\r\n\r\n    .content-panel .lang-badge {\r\n      background: #6B4FD8;\r\n      color: #fff;\r\n    }\r\n\r\n    .content-panel .file-dot {\r\n      background: #6B4FD8;\r\n    }\r\n\r\n    .content-panel .nav-btn.primary {\r\n      background: #6B4FD8;\r\n      border-color: #6B4FD8;\r\n      color: #fff;\r\n    }\r\n\r\n    .progress-fill {\r\n      background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0);\r\n    }\r\n\r\n    .lang-tab .lang-dot {\r\n      background: #6B4FD8;\r\n      box-shadow: 0 0 8px 2px #6B4FD8;\r\n    }\r\n\r\n    .nav-btn,\r\n    .nav-btn:hover,\r\n    .nav-btn:visited,\r\n    .nav-btn:active,\r\n    .nav-btn:focus {\r\n      text-decoration: none;\r\n    }\r\n\r\n    .library-back-btn {\r\n      position: fixed;\r\n      top: 12px;\r\n      right: 16px;\r\n      z-index: 200;\r\n      display: inline-flex;\r\n      align-items: center;\r\n      height: 36px;\r\n      padding: 0 14px;\r\n      border-radius: 8px;\r\n      background: var(--bg-editor-soft);\r\n      border: 1px solid var(--line);\r\n      color: var(--text-bright);\r\n      font-family: \'Inter\', sans-serif;\r\n      font-size: 13px;\r\n      font-weight: 600;\r\n      text-decoration: none;\r\n      transition: background .15s;\r\n    }\r\n\r\n    .library-back-btn:hover {\r\n      background: rgba(255, 255, 255, 0.1);\r\n    }\r\n\r\n    .completion-overlay {\r\n      position: fixed;\r\n      inset: 0;\r\n      z-index: 500;\r\n      background: rgba(10, 10, 10, 0.72);\r\n      display: flex;\r\n      align-items: center;\r\n      justify-content: center;\r\n      padding: 20px;\r\n      animation: completionFadeIn .18s ease;\r\n    }\r\n\r\n    .completion-modal {\r\n      background: var(--bg-editor-soft);\r\n      border: 1px solid var(--line);\r\n      border-radius: 14px;\r\n      padding: 34px 30px;\r\n      max-width: 380px;\r\n      width: 100%;\r\n      text-align: center;\r\n      color: var(--text-bright);\r\n    }\r\n\r\n    .completion-emoji {\r\n      font-size: 44px;\r\n      line-height: 1;\r\n      margin-bottom: 10px;\r\n    }\r\n\r\n    .completion-modal h2 {\r\n      margin: 0 0 8px;\r\n      font-family: \'Space Grotesk\', sans-serif;\r\n      font-size: 22px;\r\n    }\r\n\r\n    .completion-modal p {\r\n      margin: 0 0 22px;\r\n      color: var(--text-dim);\r\n      font-size: 14px;\r\n      line-height: 1.5;\r\n    }\r\n\r\n    .completion-actions {\r\n      display: flex;\r\n      gap: 10px;\r\n      justify-content: center;\r\n      flex-wrap: wrap;\r\n    }\r\n\r\n    @keyframes completionFadeIn {\r\n      from {\r\n        opacity: 0;\r\n      }\r\n\r\n      to {\r\n        opacity: 1;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n\r\n<body>\r\n  <script>if (localStorage.getItem(\"learnbase_dark_mode\") === \"true\") document.body.classList.add(\"dark-mode\");</script>\r\n\r\n  <button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n  <a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n  <aside class=\"sidebar\" id=\"sidebar\">\r\n    <div class=\"sidebar-head\">\r\n      <div class=\"brand\">\r\n        <div class=\"brand-mark\">LB</div>\r\n        <div>\r\n          <div class=\"brand-name\">LearnBase</div>\r\n          <div class=\"brand-sub\">TypeScript</div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"sidebar-body\">\r\n      <nav class=\"lang-nav\" id=\"langNav\">\r\n        <div class=\"lang-tab active\" data-lang=\"ts\">\r\n          <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n          <span class=\"lang-tab-text\">\r\n            <div class=\"lang-tab-name\">TypeScript</div>\r\n            <div class=\"lang-tab-meta\">12 topik</div>\r\n          </span>\r\n          <span class=\"lang-tab-pct\" data-pct=\"ts\">0%</span>\r\n        </div>\r\n        <div class=\"topic-list\" data-list=\"ts\">\r\n          <div class=\"topic-item active\" data-topic=\"ts-1\"><span class=\"topic-check\"></span>Apa itu TypeScript?</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-2\"><span class=\"topic-check\"></span>Tipe Dasar</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-3\"><span class=\"topic-check\"></span>Interface &amp; Type</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-4\"><span class=\"topic-check\"></span>Class &amp; Access Modifier</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-5\"><span class=\"topic-check\"></span>Array &amp; Tuple</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-6\"><span class=\"topic-check\"></span>Generic</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-7\"><span class=\"topic-check\"></span>Enum &amp; Union</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-8\"><span class=\"topic-check\"></span>Module &amp; Import</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-9\"><span class=\"topic-check\"></span>Utility Types</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-10\"><span class=\"topic-check\"></span>Type Guard</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-11\"><span class=\"topic-check\"></span>Decorator</div>\r\n          <div class=\"topic-item\" data-topic=\"ts-12\"><span class=\"topic-check\"></span>Declaration File</div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sidebar-foot\">\r\n      <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n      <div class=\"progress-track\">\r\n        <div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div>\r\n      </div>\r\n      <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n    </div>\r\n  </aside>\r\n\r\n  <main class=\"main\">\r\n\r\n    <!-- ================= TypeScript ================= -->\r\n    <section class=\"content-panel active\" data-lang=\"ts\">\r\n      <div class=\"lang-header\">\r\n        <div>\r\n          <div class=\"lang-eyebrow\">MODUL 11 · BAHASA SUPER DARI JAVASCRIPT</div>\r\n          <h1 class=\"lang-title\">TypeScript</h1>\r\n          <p class=\"lang-desc\">JavaScript dengan tambahan <strong>tipe statis</strong>. Dibuat Microsoft untuk membantu\r\n            menulis kode JS skala besar dengan lebih aman dan terstruktur. Semua kode TypeScript dikompilasi ke\r\n            JavaScript.</p>\r\n        </div>\r\n        <div class=\"lang-badge\">TS</div>\r\n      </div>\r\n\r\n      <article class=\"topic-section active\" data-topic=\"ts-1\">\r\n        <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n        <h2 class=\"topic-title\">Apa itu TypeScript?</h2>\r\n        <div class=\"topic-body\">\r\n          <p>TypeScript adalah <strong>superset dari JavaScript</strong> — semua kode JS valid di TS, tapi TS\r\n            menambahkan <strong>static typing</strong>, interface, generic, dan fitur modern lainnya. Kode TS\r\n            dikompilasi (<em>transpile</em>) ke JS biasa. Semakin besar proyek, semakin terasa manfaat TypeScript.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts1\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">nama</span>: <span\r\n                class=\"tok-var\">string</span> = <span class=\"tok-str\">\"LearnBase\"</span>;\r\n              <span class=\"tok-kw\">function</span> <span class=\"tok-fn\">sapa</span>(<span class=\"tok-var\">n</span>:\r\n              <span class=\"tok-var\">string</span>): <span class=\"tok-var\">string</span> {\r\n              <span class=\"tok-kw\">return</span> <span class=\"tok-str\">`Halo, <span class=\"tok-fn\">${n}</span>!`</span>;\r\n              }\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-fn\">sapa</span>(<span\r\n                class=\"tok-var\">nama</span>));\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts1\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> <code>: string</code> setelah parameter adalah <em>type\r\n            annotation</em>. TypeScript akan memeriksa tipe saat kompilasi — mencegah banyak bug sebelum runtime.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-2\">Lanjut: Tipe Dasar →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-2\">\r\n        <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n        <h2 class=\"topic-title\">Tipe Dasar</h2>\r\n        <div class=\"topic-body\">\r\n          <p>TypeScript menambahkan tipe pada JavaScript: <code>string</code>, <code>number</code>,\r\n            <code>boolean</code>, <code>array</code>, <code>any</code> (opsional), <code>void</code>, <code>null</code>,\r\n            <code>undefined</code>. <code>any</code> membuat TS berperilaku seperti JS biasa — hindari sebisa mungkin.\r\n          </p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>tipe.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts2\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">let</span> <span class=\"tok-var\">skor</span>: <span\r\n                class=\"tok-var\">number</span> = <span class=\"tok-num\">87</span>;\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">namaModul</span>: <span\r\n                class=\"tok-var\">string</span> = <span class=\"tok-str\">\"TS Dasar\"</span>;\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">lulus</span>: <span class=\"tok-var\">boolean</span>\r\n              = <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">70</span>;\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">topik</span>: <span\r\n                class=\"tok-var\">string[]</span> = [<span class=\"tok-str\">\"tipe\"</span>, <span\r\n                class=\"tok-str\">\"interface\"</span>, <span class=\"tok-str\">\"generic\"</span>];\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">namaModul</span>, <span class=\"tok-var\">lulus</span>, <span\r\n                class=\"tok-var\">topik</span>.<span class=\"tok-var\">length</span>);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts2\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout note\"><strong>Catatan:</strong> <code>string[]</code> = array berisi string. Alternatif:\r\n          <code>Array&lt;string&gt;</code>. Keduanya sama.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-1\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-3\">Lanjut: Interface &amp; Type →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-3\">\r\n        <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n        <h2 class=\"topic-title\">Interface &amp; Type</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Interface</strong> mendefinisikan struktur objek. <strong>Type alias</strong> bisa dipakai untuk\r\n            tipe union, intersection, atau tipe primitif. Interface bisa di-<em>extend</em>, type alias bisa untuk\r\n            union.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>interface.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts3\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">interface</span> <span class=\"tok-var\">Pengguna</span> {\r\n              <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">string</span>;\r\n              <span class=\"tok-var\">skor</span>: <span class=\"tok-var\">number</span>;\r\n              }\r\n              <span class=\"tok-kw\">type</span> <span class=\"tok-var\">Status</span> = <span\r\n                class=\"tok-str\">\"aktif\"</span> | <span class=\"tok-str\">\"nonaktif\"</span>;\r\n\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">user</span>: <span class=\"tok-var\">Pengguna</span>\r\n              = { <span class=\"tok-var\">nama</span>: <span class=\"tok-str\">\"Budi\"</span>, <span\r\n                class=\"tok-var\">skor</span>: <span class=\"tok-num\">87</span> };\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">user</span>.<span class=\"tok-var\">nama</span>);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts3\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Pilih <code>interface</code> untuk objek/class,\r\n          <code>type</code> untuk union/intersection. Interface bisa <code>extends</code>, type bisa <code>&amp;</code>.\r\n        </div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-2\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-4\">Lanjut: Class &amp; Access Modifier →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-4\">\r\n        <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n        <h2 class=\"topic-title\">Class &amp; Access Modifier</h2>\r\n        <div class=\"topic-body\">\r\n          <p>TypeScript menambahkan <strong>access modifier</strong> ke class JavaScript: <code>public</code>,\r\n            <code>private</code>, <code>protected</code>. Juga fitur <code>readonly</code> untuk properti yang tidak\r\n            bisa diubah setelah inisialisasi.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>class.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts4\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">class</span> <span class=\"tok-var\">Siswa</span> {\r\n              <span class=\"tok-kw\">constructor</span>(\r\n              <span class=\"tok-kw\">public</span> <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">string</span>,\r\n              <span class=\"tok-kw\">private</span> <span class=\"tok-var\">skor</span>: <span class=\"tok-var\">number</span>\r\n              ) {}\r\n              <span class=\"tok-fn\">cetak</span>() {\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">`<span\r\n                  class=\"tok-fn\">${this.nama}</span>: <span class=\"tok-fn\">${this.skor}</span>`</span>);\r\n              }\r\n              }\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">s</span> = <span class=\"tok-kw\">new</span> <span\r\n                class=\"tok-var\">Siswa</span>(<span class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>);\r\n              <span class=\"tok-var\">s</span>.<span class=\"tok-fn\">cetak</span>();\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts4\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout note\"><strong>Catatan:</strong> Constructor TS bisa langsung mendeklarasikan properti dengan\r\n          access modifier — ini praktik modern yang menggantikan deklarasi properti di atas constructor.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-3\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-5\">Lanjut: Array &amp; Tuple →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-5\">\r\n        <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n        <h2 class=\"topic-title\">Array &amp; Tuple</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Array</strong> di TS: <code>number[]</code> atau <code>Array&lt;number&gt;</code>.\r\n            <strong>Tuple</strong> adalah array dengan jumlah dan tipe elemen yang tetap — fitur yang tidak dimiliki\r\n            JavaScript biasa.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>tuple.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts5\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">const</span> <span class=\"tok-var\">angka</span>: <span\r\n                class=\"tok-var\">number[]</span> = [<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>, <span\r\n                class=\"tok-num\">3</span>];\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">pengguna</span>: [<span\r\n                class=\"tok-var\">string</span>, <span class=\"tok-var\">number</span>] = [<span\r\n                class=\"tok-str\">\"Budi\"</span>, <span class=\"tok-num\">87</span>];\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">pengguna</span>[<span class=\"tok-num\">0</span>], <span\r\n                class=\"tok-var\">pengguna</span>[<span class=\"tok-num\">1</span>]);\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">angka</span>.<span class=\"tok-fn\">map</span>(<span class=\"tok-var\">n</span> => <span\r\n                class=\"tok-var\">n</span> * <span class=\"tok-var\">n</span>));\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts5\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Tuple berguna untuk fungsi yang mengembalikan banyak nilai —\r\n          seperti <code>[error, data]</code>.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-4\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-6\">Lanjut: Generic →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-6\">\r\n        <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n        <h2 class=\"topic-title\">Generic</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Generic</strong> memungkinkan fungsi, class, atau interface bekerja dengan berbagai tipe. TS akan\r\n            menentukan tipe spesifik saat dipakai — memberikan fleksibilitas tanpa kehilangan keamanan tipe.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>generic.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts6\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">function</span> <span\r\n                class=\"tok-var\">ambilPertama</span>&lt;<span class=\"tok-var\">T</span>&gt;(<span\r\n                class=\"tok-var\">arr</span>: <span class=\"tok-var\">T</span>[]): <span class=\"tok-var\">T</span> {\r\n              <span class=\"tok-kw\">return</span> <span class=\"tok-var\">arr</span>[<span class=\"tok-num\">0</span>];\r\n              }\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-fn\">ambilPertama</span>([<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>,\r\n              <span class=\"tok-num\">3</span>]));\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-fn\">ambilPertama</span>([<span class=\"tok-str\">\"a\"</span>, <span\r\n                class=\"tok-str\">\"b\"</span>]));\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts6\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout note\"><strong>Catatan:</strong> <code>&lt;T&gt;</code> adalah <em>type parameter</em> — bisa\r\n          diganti huruf lain. Convention: <code>T</code> (Type), <code>K</code> (Key), <code>V</code> (Value).</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-5\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-7\">Lanjut: Enum &amp; Union →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-7\">\r\n        <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n        <h2 class=\"topic-title\">Enum &amp; Union</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Enum</strong> mendefinisikan kumpulan nilai yang sudah ditentukan. <strong>Union type</strong>\r\n            (<code>|</code>) memungkinkan variabel memiliki lebih dari satu tipe. Keduanya membuat kode lebih ekspresif\r\n            dan aman.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>enum.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts7\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">enum</span> <span class=\"tok-var\">Level</span> { <span\r\n                class=\"tok-var\">Pemula</span>, <span class=\"tok-var\">Menengah</span>, <span class=\"tok-var\">Mahir</span>\r\n              }\r\n              <span class=\"tok-kw\">type</span> <span class=\"tok-var\">Id</span> = <span class=\"tok-var\">number</span> |\r\n              <span class=\"tok-var\">string</span>;\r\n\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">levelUser</span>: <span\r\n                class=\"tok-var\">Level</span> = <span class=\"tok-var\">Level</span>.<span class=\"tok-var\">Menengah</span>;\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">userId</span>: <span class=\"tok-var\">Id</span> =\r\n              <span class=\"tok-str\">\"usr_001\"</span>;\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">levelUser</span>, <span class=\"tok-var\">userId</span>);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts7\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Enum numeric default mulai dari 0. Bisa diubah:\r\n          <code>enum Level { Pemula = 1, Menengah, Mahir }</code>.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-6\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-8\">Lanjut: Module &amp; Import →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <article class=\"topic-section\" data-topic=\"ts-8\">\r\n        <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n        <h2 class=\"topic-title\">Module &amp; Import</h2>\r\n        <div class=\"topic-body\">\r\n          <p>TypeScript mendukung <strong>ES Module</strong> — <code>export</code> dan <code>import</code>. File TS bisa\r\n            <code>export</code> fungsi/class/type dan <code>import</code> di file lain. TypeScript juga punya\r\n            <em>declaration files</em> (<code>.d.ts</code>) untuk tipe library JS yang sudah ada.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>math.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts8\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n            <div class=\"code-content\"><span class=\"tok-cm\">// math.ts</span>\r\n              <span class=\"tok-kw\">export</span> <span class=\"tok-kw\">function</span> <span\r\n                class=\"tok-fn\">kuadrat</span>(<span class=\"tok-var\">x</span>: <span class=\"tok-var\">number</span>):\r\n              <span class=\"tok-var\">number</span> {\r\n              <span class=\"tok-kw\">return</span> <span class=\"tok-var\">x</span> * <span class=\"tok-var\">x</span>;\r\n              }\r\n              <span class=\"tok-kw\">export</span> <span class=\"tok-kw\">const</span> <span class=\"tok-var\">PI</span> =\r\n              <span class=\"tok-num\">3.14</span>;\r\n\r\n              <span class=\"tok-cm\">// main.ts</span>\r\n              <span class=\"tok-kw\">import</span> { <span class=\"tok-var\">kuadrat</span>, <span class=\"tok-var\">PI</span>\r\n              } <span class=\"tok-kw\">from</span> <span class=\"tok-str\">\"./math\"</span>;\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-fn\">kuadrat</span>(<span class=\"tok-num\">5</span>), <span class=\"tok-var\">PI</span>);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts8\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"quiz-box\">\r\n          <div class=\"quiz-q\">Quiz: TypeScript adalah superset dari bahasa apa?</div>\r\n          <div class=\"quiz-opts\">\r\n            <button class=\"quiz-opt\" data-correct=\"false\">Java</button>\r\n            <button class=\"quiz-opt\" data-correct=\"true\">JavaScript</button>\r\n            <button class=\"quiz-opt\" data-correct=\"false\">Python</button>\r\n          </div>\r\n          <div class=\"quiz-feedback\"></div>\r\n        </div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-7\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-9\">Lanjut: Utility Types →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <!-- TS Topic 9 -->\r\n      <article class=\"topic-section\" data-topic=\"ts-9\">\r\n        <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n        <h2 class=\"topic-title\">Utility Types</h2>\r\n        <div class=\"topic-body\">\r\n          <p>TypeScript menyediakan <strong>utility types</strong> bawaan — tipe bawaan yang memanipulasi tipe lain.\r\n            Utility types seperti fungsi untuk tipe: menerima satu tipe dan menghasilkan tipe baru. Ini mengurangi\r\n            boilerplate dan menjaga kode tetap <em>DRY</em>.</p>\r\n          <p>Utility types yang paling sering dipakai: <code>Partial&lt;T&gt;</code> (semua properti jadi opsional),\r\n            <code>Required&lt;T&gt;</code> (semua properti jadi wajib), <code>Pick&lt;T, K&gt;</code> (ambil properti\r\n            tertentu), <code>Omit&lt;T, K&gt;</code> (hapus properti tertentu), <code>Readonly&lt;T&gt;</code> (semua\r\n            properti readonly), dan <code>Record&lt;K, V&gt;</code> (tipe object dengan key/value tertentu).</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>utility.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts9\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16\r\n            </div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">interface</span> <span class=\"tok-var\">User</span> {\r\n              <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">string</span>;\r\n              <span class=\"tok-var\">email</span>: <span class=\"tok-var\">string</span>;\r\n              <span class=\"tok-var\">usia</span>: <span class=\"tok-var\">number</span>;\r\n              }\r\n\r\n              <span class=\"tok-cm\">// Partial — semua opsional</span>\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">update</span>: <span\r\n                class=\"tok-var\">Partial</span>&lt;<span class=\"tok-var\">User</span>&gt; = { <span\r\n                class=\"tok-var\">email</span>: <span class=\"tok-str\">\"baru@mail.com\"</span> };\r\n\r\n              <span class=\"tok-cm\">// Pick & Omit</span>\r\n              <span class=\"tok-kw\">type</span> <span class=\"tok-var\">NamaSaja</span> = <span\r\n                class=\"tok-var\">Pick</span>&lt;<span class=\"tok-var\">User</span>, <span\r\n                class=\"tok-str\">\"nama\"</span>&gt;;\r\n              <span class=\"tok-kw\">type</span> <span class=\"tok-var\">TanpaUsia</span> = <span\r\n                class=\"tok-var\">Omit</span>&lt;<span class=\"tok-var\">User</span>, <span\r\n                class=\"tok-str\">\"usia\"</span>&gt;;\r\n\r\n              <span class=\"tok-cm\">// Record — object dengan key string, value number</span>\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">nilai</span>: <span\r\n                class=\"tok-var\">Record</span>&lt;<span class=\"tok-var\">string</span>, <span\r\n                class=\"tok-var\">number</span>&gt; = {\r\n              <span class=\"tok-var\">Budi</span>: <span class=\"tok-num\">87</span>,\r\n              <span class=\"tok-var\">Sari</span>: <span class=\"tok-num\">92</span>,\r\n              };\r\n\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-var\">update</span>,\r\n              <span class=\"tok-var\">nilai</span>);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts9\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Utility types bekerja pada <em>structural type system</em> —\r\n          selama bentuk objek cocok, tipe dianggap kompatibel. <code>Pick</code> dan <code>Omit</code> paling sering\r\n          dipakai untuk membuat varian tipe tanpa mengubah interface asli.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-8\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-10\">Lanjut: Type Guard →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <!-- TS Topic 10 -->\r\n      <article class=\"topic-section\" data-topic=\"ts-10\">\r\n        <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n        <h2 class=\"topic-title\">Type Guard</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Type guard</strong> adalah mekanisme TypeScript untuk mempersempit (<em>narrowing</em>) tipe union\r\n            di dalam blok kode tertentu. Dengan type guard, kamu bisa memberi tahu TypeScript bahwa di suatu cabang,\r\n            variabel bertipe lebih spesifik. Ini membuat kode lebih aman tanpa <code>as</code> (type assertion) yang\r\n            berbahaya.</p>\r\n          <p>Teknik type guard: <code>typeof</code> untuk tipe primitif, <code>instanceof</code> untuk class,\r\n            <code>in</code> untuk properti objek, dan <strong>custom type guard</strong> dengan\r\n            <code>parameter is Type</code>. Custom type guard adalah fungsi yang mengembalikan <code>boolean</code>\r\n            dengan tipe return <code>value is TipeTertentu</code>.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>guard.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts10\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">\r\n              1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17<br>18</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">function</span> <span\r\n                class=\"tok-fn\">cetakPanjang</span>(<span class=\"tok-var\">input</span>: <span\r\n                class=\"tok-var\">string</span> | <span class=\"tok-var\">number</span>[]) {\r\n              <span class=\"tok-cm\">// typeof guard</span>\r\n              <span class=\"tok-kw\">if</span> (<span class=\"tok-kw\">typeof</span> <span class=\"tok-var\">input</span> ===\r\n              <span class=\"tok-str\">\"string\"</span>) {\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Panjang\r\n                string:\"</span>, <span class=\"tok-var\">input</span>.<span class=\"tok-var\">length</span>);\r\n              }\r\n              <span class=\"tok-kw\">if</span> (<span class=\"tok-var\">input</span> <span class=\"tok-kw\">instanceof</span>\r\n              <span class=\"tok-var\">Array</span>) {\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Panjang\r\n                array:\"</span>, <span class=\"tok-var\">input</span>.<span class=\"tok-var\">length</span>);\r\n              }\r\n              }\r\n\r\n              <span class=\"tok-kw\">interface</span> <span class=\"tok-var\">Kucing</span> { <span\r\n                class=\"tok-var\">suara</span>: <span class=\"tok-var\">string</span>; <span class=\"tok-fn\">meong</span>():\r\n              <span class=\"tok-var\">void</span>; }\r\n              <span class=\"tok-kw\">interface</span> <span class=\"tok-var\">Anjing</span> { <span\r\n                class=\"tok-var\">suara</span>: <span class=\"tok-var\">string</span>; <span class=\"tok-fn\">gukguk</span>():\r\n              <span class=\"tok-var\">void</span>; }\r\n\r\n              <span class=\"tok-cm\">// Custom type guard</span>\r\n              <span class=\"tok-kw\">function</span> <span class=\"tok-fn\">isKucing</span>(<span\r\n                class=\"tok-var\">hew</span>: <span class=\"tok-var\">Kucing</span> | <span class=\"tok-var\">Anjing</span>):\r\n              <span class=\"tok-var\">hew</span> <span class=\"tok-kw\">is</span> <span class=\"tok-var\">Kucing</span> {\r\n              <span class=\"tok-kw\">return</span> (<span class=\"tok-var\">hew</span> <span class=\"tok-kw\">as</span> <span\r\n                class=\"tok-var\">Kucing</span>).<span class=\"tok-var\">meong</span> !== <span\r\n                class=\"tok-kw\">undefined</span>;\r\n              }\r\n\r\n              <span class=\"tok-kw\">const</span> <span class=\"tok-var\">hewan</span>: <span class=\"tok-var\">Kucing</span>\r\n              | <span class=\"tok-var\">Anjing</span> = { <span class=\"tok-var\">suara</span>: <span\r\n                class=\"tok-str\">\"miaw\"</span>, <span class=\"tok-fn\">meong</span>() { <span\r\n                class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Meong!\"</span>); }\r\n              };\r\n              <span class=\"tok-kw\">if</span> (<span class=\"tok-fn\">isKucing</span>(<span class=\"tok-var\">hewan</span>))\r\n              {\r\n              <span class=\"tok-var\">hewan</span>.<span class=\"tok-fn\">meong</span>();\r\n              }\r\n              <span class=\"tok-fn\">cetakPanjang</span>(<span class=\"tok-str\">\"LearnBase\"</span>);\r\n              <span class=\"tok-fn\">cetakPanjang</span>([<span class=\"tok-num\">1</span>, <span class=\"tok-num\">2</span>,\r\n              <span class=\"tok-num\">3</span>, <span class=\"tok-num\">4</span>]);\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts10\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Custom type guard dengan <code>value is Type</code> sangat\r\n          berguna saat bekerja dengan <strong>discriminated union</strong> — union yang punya properti literal pembeda.\r\n          TypeScript akan otomatis mempersempit tipe setelah guard dipanggil.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-9\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-11\">Lanjut: Decorator →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <!-- TS Topic 11 -->\r\n      <article class=\"topic-section\" data-topic=\"ts-11\">\r\n        <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n        <h2 class=\"topic-title\">Decorator</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Decorator</strong> adalah fungsi khusus yang memodifikasi class, method, property, atau parameter\r\n            saat runtime. Ditandai dengan <code>@decorator</code> dan diaktifkan lewat\r\n            <code>experimentalDecorators</code> di tsconfig. Decorator dipakai luas di framework seperti Angular dan\r\n            NestJS.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>decorator.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts11\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n            <div class=\"code-content\"><span class=\"tok-kw\">function</span> <span class=\"tok-fn\">log</span>(<span\r\n                class=\"tok-var\">target</span>: <span class=\"tok-var\">any</span>, <span class=\"tok-var\">key</span>: <span\r\n                class=\"tok-var\">string</span>) {\r\n              <span class=\"tok-fn\">console</span>.<span class=\"tok-fn\">log</span>(<span class=\"tok-str\">`Method <span\r\n                  class=\"tok-fn\">${key}</span> dipanggil`</span>);\r\n              }\r\n              <span class=\"tok-kw\">class</span> <span class=\"tok-var\">Belajar</span> {\r\n              @<span class=\"tok-fn\">log</span>\r\n              <span class=\"tok-fn\">mulai</span>() { <span class=\"tok-fn\">console</span>.<span\r\n                class=\"tok-fn\">log</span>(<span class=\"tok-str\">\"Belajar dimulai\"</span>); }\r\n              }\r\n              <span class=\"tok-kw\">new</span> <span class=\"tok-var\">Belajar</span>().<span\r\n                class=\"tok-fn\">mulai</span>();\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts11\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout note\"><strong>Catatan:</strong> Decorator masih dalam status <em>experimental</em> di\r\n          TypeScript. Aktifkan dengan <code>\"experimentalDecorators\": true</code> di <code>tsconfig.json</code>. Ada 4\r\n          jenis: class, method, accessor, property, parameter.</div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-10\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" data-next=\"ts-12\">Lanjut: Declaration File →</button>\r\n        </div>\r\n      </article>\r\n\r\n      <!-- TS Topic 12 -->\r\n      <article class=\"topic-section\" data-topic=\"ts-12\">\r\n        <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n        <h2 class=\"topic-title\">Declaration File</h2>\r\n        <div class=\"topic-body\">\r\n          <p><strong>Declaration file</strong> (<code>.d.ts</code>) berisi definisi tipe untuk kode JavaScript yang\r\n            sudah ada. Memungkinkan TypeScript memahami tipe library JS tanpa menulis ulang kodenya. File\r\n            <code>.d.ts</code> hanya berisi deklarasi — tanpa implementasi. Banyak library populer sudah punya\r\n            <code>@types/nama-package</code> di npm.</p>\r\n        </div>\r\n        <div class=\"code-card\">\r\n          <div class=\"code-tab-bar\">\r\n            <div class=\"code-filename\"><span class=\"file-dot\"></span>halo.d.ts</div>\r\n            <button class=\"run-btn\" data-run=\"ts12\">▶ Jalankan</button>\r\n          </div>\r\n          <div class=\"code-body\">\r\n            <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8</div>\r\n            <div class=\"code-content\"><span class=\"tok-cm\">// halo.d.ts — deklarasi tipe untuk library JS</span>\r\n              <span class=\"tok-kw\">export interface</span> <span class=\"tok-var\">Pengguna</span> {\r\n              <span class=\"tok-var\">nama</span>: <span class=\"tok-var\">string</span>;\r\n              <span class=\"tok-var\">skor</span>: <span class=\"tok-var\">number</span>;\r\n              }\r\n              <span class=\"tok-kw\">export function</span> <span class=\"tok-fn\">cetakSkor</span>(<span\r\n                class=\"tok-var\">u</span>: <span class=\"tok-var\">Pengguna</span>): <span class=\"tok-kw\">void</span>;\r\n            </div>\r\n          </div>\r\n          <div class=\"output-bar\">\r\n            <div class=\"output-label\">OUTPUT (console)</div>\r\n            <div class=\"output-content\" id=\"out-ts12\"></div>\r\n          </div>\r\n        </div>\r\n        <div class=\"callout tip\"><strong>Tips:</strong> Install <code>@types/package</code> lewat npm untuk library yang\r\n          belum punya deklarasi built-in. Contoh: <code>npm install --save-dev @types/lodash</code>. Buat sendiri dengan\r\n          <code>declare module \'nama-modul\'</code>.</div>\r\n        <div class=\"quiz-box\">\r\n          <div class=\"quiz-q\">Quiz: Ekstensi file untuk deklarasi tipe TypeScript?</div>\r\n          <div class=\"quiz-opts\">\r\n            <button class=\"quiz-opt\" data-correct=\"false\">.ts</button>\r\n            <button class=\"quiz-opt\" data-correct=\"true\">.d.ts</button>\r\n            <button class=\"quiz-opt\" data-correct=\"false\">.type.ts</button>\r\n          </div>\r\n          <div class=\"quiz-feedback\"></div>\r\n        </div>\r\n        <div class=\"topic-nav\">\r\n          <button class=\"nav-btn\" data-prev=\"ts-11\">← Sebelumnya</button>\r\n          <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Selesai — Kembali ke Library 🎉</button>\r\n        </div>\r\n      </article>\r\n    </section>\r\n\r\n  </main>\r\n\r\n  <script>\r\n    (function () {\r\n      const totalTopics = 12;\r\n      const LANGUAGE = \'ts\'; // harus sama dengan key di $languages pada get_progress.php\r\n      const completed = new Set();\r\n      let celebrated = false;\r\n\r\n      const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n      const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n      function setActiveTopic(topicId) {\r\n        const lang = topicId.split(\'-\')[0];\r\n\r\n        langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n        contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n        document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n          s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n        });\r\n        document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n          t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n        });\r\n\r\n        markDone(topicId);\r\n      }\r\n\r\n      function markDone(topicId, persist = true) {\r\n        if (completed.has(topicId)) return;\r\n        completed.add(topicId);\r\n        const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n        if (item) item.classList.add(\'done\');\r\n        updateProgress();\r\n        if (persist) saveProgress(topicId);\r\n      }\r\n\r\n      async function saveProgress(topicId) {\r\n        try {\r\n          const res = await fetch(\'../save_progress.php\', {\r\n            method: \'POST\',\r\n            headers: { \'Content-Type\': \'application/json\' },\r\n            body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n          });\r\n          if (res.status === 401) {\r\n            window.location.href = \'../auth.html\';\r\n            return;\r\n          }\r\n          if (!res.ok) {\r\n            console.error(\'save_progress.php gagal, status:\', res.status);\r\n          }\r\n        } catch (err) {\r\n          console.error(\'Gagal menyimpan progres ke server:\', err);\r\n        }\r\n      }\r\n\r\n      async function loadProgress() {\r\n        try {\r\n          const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n          if (res.status === 401) {\r\n            window.location.href = \'../auth.html\';\r\n            return;\r\n          }\r\n          if (!res.ok) {\r\n            console.error(\'get_progress.php gagal, status:\', res.status);\r\n            return;\r\n          }\r\n          const data = await res.json();\r\n          (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n        } catch (err) {\r\n          console.error(\'Gagal memuat progres dari server:\', err);\r\n        }\r\n      }\r\n\r\n      function updateProgress() {\r\n        const pct = Math.round((completed.size / totalTopics) * 100);\r\n        document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n        document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n        const items = document.querySelectorAll(\'.topic-item\');\r\n        const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n        const langPct = Math.round((done / items.length) * 100);\r\n        const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n        if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n        if (!celebrated && completed.size >= totalTopics) {\r\n          celebrated = true;\r\n          showCompletionAlert();\r\n        }\r\n      }\r\n\r\n      function showCompletionAlert() {\r\n        const overlay = document.createElement(\'div\');\r\n        overlay.className = \'completion-overlay\';\r\n        overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n        document.body.appendChild(overlay);\r\n        document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n        document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n          window.location.href = \'../library.html\';\r\n        });\r\n        overlay.addEventListener(\'click\', (e) => {\r\n          if (e.target === overlay) overlay.remove();\r\n        });\r\n      }\r\n\r\n      document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n        item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n      });\r\n\r\n      document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n        btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n      });\r\n      document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n        btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n      });\r\n\r\n      const finishBtn = document.getElementById(\'finishBtn\');\r\n      if (finishBtn) {\r\n        finishBtn.addEventListener(\'click\', () => {\r\n          showCompletionAlert();\r\n        });\r\n      }\r\n\r\n\r\n      // ===== Quiz interactivity =====\r\n      document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n        const opts = box.querySelectorAll(\'.quiz-opt\');\r\n        const feedback = box.querySelector(\'.quiz-feedback\');\r\n        opts.forEach(opt => {\r\n          opt.addEventListener(\'click\', () => {\r\n            opts.forEach(o => o.disabled = true);\r\n            const correct = opt.dataset.correct === \'true\';\r\n            opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n            if (!correct) {\r\n              const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n              if (correctOpt) correctOpt.classList.add(\'correct\');\r\n              feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n              feedback.className = \'quiz-feedback wrong-text\';\r\n            } else {\r\n              feedback.textContent = \'Tepat sekali! 🎉\';\r\n              feedback.className = \'quiz-feedback correct-text\';\r\n            }\r\n          });\r\n        });\r\n      });\r\n\r\n      // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n      loadProgress().then(() => markDone(\'ts-1\'));\r\n\r\n      // ===== Sidebar toggle =====\r\n      const sidebar = document.getElementById(\'sidebar\');\r\n      const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n      const mainEl = document.querySelector(\'.main\');\r\n\r\n      // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n      toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n      toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n      toggleBtn.addEventListener(\'click\', () => {\r\n        const hidden = sidebar.classList.toggle(\'hidden\');\r\n        mainEl.classList.toggle(\'expanded\', hidden);\r\n        toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n        toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n      });\r\n    })();\r\n  </script>\r\n\r\n</body>\r\n\r\n</html>', '#FF5B35', NULL, '2026-07-03 13:09:45', '2026-07-04 19:19:23');
INSERT INTO `modules` (`id`, `slug`, `name`, `category`, `difficulty`, `language`, `content`, `icon_color`, `certificate_recipient`, `created_at`, `updated_at`) VALUES
(12, 'sqlite', 'SQLite Database', 'Database', 'beginner', 'SQLite', '<!DOCTYPE html>\r\n<html lang=\"id\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>SQLite — LearnBase</title>\r\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap\" rel=\"stylesheet\">\r\n<link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n<link rel=\"stylesheet\" href=\"<?= base_url(\"assets/css/style-modul.css\") ?>\">\r\n<style>\r\n  .content-panel .lang-eyebrow { color: #6B4FD8; }\r\n  .content-panel .lang-badge { background: #6B4FD8; color: #fff; }\r\n  .content-panel .file-dot { background: #6B4FD8; }\r\n  .content-panel .nav-btn.primary { background: #6B4FD8; border-color: #6B4FD8; color: #fff; }\r\n  .progress-fill { background: linear-gradient(90deg, #6B4FD8, #8868E0, #A98CF0); }\r\n  .lang-tab .lang-dot { background: #6B4FD8; box-shadow: 0 0 8px 2px #6B4FD8; }\r\n  .nav-btn, .nav-btn:hover, .nav-btn:visited, .nav-btn:active, .nav-btn:focus { text-decoration: none; }\r\n\r\n  .library-back-btn {\r\n    position: fixed;\r\n    top: 12px;\r\n    right: 16px;\r\n    z-index: 200;\r\n    display: inline-flex;\r\n    align-items: center;\r\n    height: 36px;\r\n    padding: 0 14px;\r\n    border-radius: 8px;\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    color: var(--text-bright);\r\n    font-family: \'Inter\', sans-serif;\r\n    font-size: 13px;\r\n    font-weight: 600;\r\n    text-decoration: none;\r\n    transition: background .15s;\r\n  }\r\n  .library-back-btn:hover { background: rgba(255,255,255,0.1); }\r\n  .completion-overlay {\r\n    position: fixed; inset: 0; z-index: 500;\r\n    background: rgba(10,10,10,0.72);\r\n    display: flex; align-items: center; justify-content: center;\r\n    padding: 20px;\r\n    animation: completionFadeIn .18s ease;\r\n  }\r\n  .completion-modal {\r\n    background: var(--bg-editor-soft);\r\n    border: 1px solid var(--line);\r\n    border-radius: 14px;\r\n    padding: 34px 30px;\r\n    max-width: 380px;\r\n    width: 100%;\r\n    text-align: center;\r\n    color: var(--text-bright);\r\n  }\r\n  .completion-emoji { font-size: 44px; line-height: 1; margin-bottom: 10px; }\r\n  .completion-modal h2 { margin: 0 0 8px; font-family: \'Space Grotesk\', sans-serif; font-size: 22px; }\r\n  .completion-modal p { margin: 0 0 22px; color: var(--text-dim); font-size: 14px; line-height: 1.5; }\r\n  .completion-actions { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; }\r\n  @keyframes completionFadeIn { from { opacity: 0; } to { opacity: 1; } }\r\n</style>\r\n</head>\r\n<body>\r\n<script>if(localStorage.getItem(\"learnbase_dark_mode\")===\"true\")document.body.classList.add(\"dark-mode\");</script>\r\n\r\n<button class=\"sidebar-toggle\" id=\"sidebarToggle\" title=\"Toggle sidebar\">☰</button>\r\n<a class=\"library-back-btn\" href=\"<?= site_url(\'library\') ?>\" title=\"Kembali ke halaman Library\">← Library</a>\r\n<aside class=\"sidebar\" id=\"sidebar\">\r\n  <div class=\"sidebar-head\">\r\n    <div class=\"brand\">\r\n      <div class=\"brand-mark\">LB</div>\r\n      <div>\r\n        <div class=\"brand-name\">LearnBase</div>\r\n        <div class=\"brand-sub\">SQLite3</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-body\">\r\n  <nav class=\"lang-nav\" id=\"langNav\">\r\n    <div class=\"lang-tab active\" data-lang=\"sql\">\r\n      <span class=\"lang-dot\" style=\"background:#6B4FD8\"></span>\r\n      <span class=\"lang-tab-text\">\r\n        <div class=\"lang-tab-name\">SQLite3</div>\r\n        <div class=\"lang-tab-meta\">12 topik</div>\r\n      </span>\r\n      <span class=\"lang-tab-pct\" data-pct=\"sql\">0%</span>\r\n    </div>\r\n    <div class=\"topic-list\" data-list=\"sql\">\r\n      <div class=\"topic-item active\" data-topic=\"sql-1\"><span class=\"topic-check\"></span>Apa itu SQLite?</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-2\"><span class=\"topic-check\"></span>CREATE TABLE</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-3\"><span class=\"topic-check\"></span>INSERT &amp; SELECT</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-4\"><span class=\"topic-check\"></span>WHERE &amp; Filter</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-5\"><span class=\"topic-check\"></span>UPDATE &amp; DELETE</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-6\"><span class=\"topic-check\"></span>ORDER &amp; LIMIT</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-7\"><span class=\"topic-check\"></span>JOIN</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-8\"><span class=\"topic-check\"></span>GROUP &amp; Aggregat</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-9\"><span class=\"topic-check\"></span>Subquery</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-10\"><span class=\"topic-check\"></span>Index</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-11\"><span class=\"topic-check\"></span>View</div>\r\n      <div class=\"topic-item\" data-topic=\"sql-12\"><span class=\"topic-check\"></span>Transaction</div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"sidebar-foot\">\r\n    <div class=\"sidebar-footer-label\">Progres modul kamu</div>\r\n    <div class=\"progress-track\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\r\n    <div class=\"sidebar-footer-num\" id=\"progressNum\">0 / 12 topik selesai</div>\r\n  </div>\r\n</aside>\r\n\r\n<main class=\"main\">\r\n\r\n  <!-- ================= SQLite3 ================= -->\r\n  <section class=\"content-panel active\" data-lang=\"sql\">\r\n    <div class=\"lang-header\">\r\n      <div>\r\n        <div class=\"lang-eyebrow\">MODUL 12 · BAHASA DATABASE RELASIONAL</div>\r\n        <h1 class=\"lang-title\">SQLite3</h1>\r\n        <p class=\"lang-desc\">SQLite adalah <strong>database relasional</strong> yang ringan dan self-contained — tidak perlu server terpisah. Menyimpan seluruh database dalam satu file. Cocok untuk aplikasi desktop, mobile, dan prototyping.</p>\r\n      </div>\r\n      <div class=\"lang-badge\">SQL</div>\r\n    </div>\r\n\r\n    <article class=\"topic-section active\" data-topic=\"sql-1\">\r\n      <div class=\"topic-eyebrow\">TOPIK 1 / 12</div>\r\n      <h2 class=\"topic-title\">Apa itu SQLite?</h2>\r\n      <div class=\"topic-body\">\r\n        <p>SQLite adalah <strong>relational database management system</strong> (RDBMS) yang paling banyak dipakai di dunia — ada di setiap ponsel, browser, dan banyak aplikasi desktop. Tidak seperti MySQL atau PostgreSQL, SQLite tidak perlu server terpisah. Database disimpan dalam satu file <code>.db</code> atau <code>.sqlite</code>.</p>\r\n        <p>SQLite menggunakan bahasa <strong>SQL</strong> (Structured Query Language) untuk memanipulasi data. Perintah SQL dijalankan langsung tanpa konfigurasi rumit.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>belajar.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql1\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">-- Membuka database</span>\r\n<span class=\"tok-var\">.open</span> <span class=\"tok-var\">learnbase.db</span>\r\n\r\n<span class=\"tok-fn\">SELECT</span> <span class=\"tok-str\">\'Halo, SQLite3!\'</span> <span class=\"tok-kw\">AS</span> <span class=\"tok-var\">pesan</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql1\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> SQLite adalah database <em>serverless</em> — file <code>.db</code> berisi seluruh data, tabel, indeks, dan skema. Tinggal copy file untuk backup!</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" disabled>← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-2\">Lanjut: CREATE TABLE →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-2\">\r\n      <div class=\"topic-eyebrow\">TOPIK 2 / 12</div>\r\n      <h2 class=\"topic-title\">CREATE TABLE</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>CREATE TABLE</strong> membuat tabel baru. Setiap kolom punya nama dan tipe data. SQLite tipenya fleksibel — <code>INTEGER</code>, <code>TEXT</code>, <code>REAL</code>, <code>BLOB</code>. Bisa menambahkan <strong>constraint</strong>: <code>PRIMARY KEY</code>, <code>NOT NULL</code>, <code>UNIQUE</code>, <code>DEFAULT</code>.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>create.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql2\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">CREATE TABLE</span> <span class=\"tok-var\">siswa</span> (\r\n    <span class=\"tok-var\">id</span> <span class=\"tok-var\">INTEGER</span> <span class=\"tok-kw\">PRIMARY KEY AUTOINCREMENT</span>,\r\n    <span class=\"tok-var\">nama</span> <span class=\"tok-var\">TEXT</span> <span class=\"tok-kw\">NOT NULL</span>,\r\n    <span class=\"tok-var\">email</span> <span class=\"tok-var\">TEXT</span> <span class=\"tok-kw\">UNIQUE</span>,\r\n    <span class=\"tok-var\">skor</span> <span class=\"tok-var\">INTEGER</span> <span class=\"tok-kw\">DEFAULT</span> <span class=\"tok-num\">0</span>\r\n);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql2\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>AUTOINCREMENT</code> membuat nilai id otomatis bertambah. <code>PRIMARY KEY</code> memastikan setiap baris punya id unik.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-1\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-3\">Lanjut: INSERT &amp; SELECT →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-3\">\r\n      <div class=\"topic-eyebrow\">TOPIK 3 / 12</div>\r\n      <h2 class=\"topic-title\">INSERT &amp; SELECT</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>INSERT</strong> menambah baris baru ke tabel. <strong>SELECT</strong> mengambil data dari tabel — bisa semua kolom (<code>*</code>) atau kolom tertentu. Ini adalah dua operasi paling dasar dalam SQL.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>insert.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql3\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">INSERT INTO</span> <span class=\"tok-var\">siswa</span> (<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">email</span>, <span class=\"tok-var\">skor</span>)\r\n<span class=\"tok-kw\">VALUES</span> (<span class=\"tok-str\">\'Budi\'</span>, <span class=\"tok-str\">\'budi@email.com\'</span>, <span class=\"tok-num\">87</span>);\r\n\r\n<span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span>;\r\n<span class=\"tok-fn\">SELECT</span> * <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql3\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> <code>SELECT *</code> praktis untuk eksplorasi, tapi di kode produksi sebaiknya sebut kolom spesifik — lebih jelas dan efisien.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-2\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-4\">Lanjut: WHERE &amp; Filter →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-4\">\r\n      <div class=\"topic-eyebrow\">TOPIK 4 / 12</div>\r\n      <h2 class=\"topic-title\">WHERE &amp; Filter</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>WHERE</strong> memfilter baris berdasarkan kondisi. Bisa dikombinasikan dengan <code>AND</code>, <code>OR</code>, <code>IN</code>, <code>LIKE</code>, <code>BETWEEN</code>. Filter adalah inti dari query SQL untuk mengambil data yang spesifik.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>filter.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql4\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">skor</span> >= <span class=\"tok-num\">80</span>\r\n<span class=\"tok-kw\">AND</span> <span class=\"tok-var\">email</span> <span class=\"tok-kw\">LIKE</span> <span class=\"tok-str\">\'%@email.com\'</span>;\r\n\r\n<span class=\"tok-fn\">SELECT</span> * <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">BETWEEN</span> <span class=\"tok-num\">70</span> <span class=\"tok-kw\">AND</span> <span class=\"tok-num\">90</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql4\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>LIKE</code> untuk pencocokan pola. <code>%</code> = karakter apapun (0 atau lebih). <code>_</code> = satu karakter.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-3\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-5\">Lanjut: UPDATE &amp; DELETE →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-5\">\r\n      <div class=\"topic-eyebrow\">TOPIK 5 / 12</div>\r\n      <h2 class=\"topic-title\">UPDATE &amp; DELETE</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>UPDATE</strong> mengubah data yang sudah ada. <strong>DELETE</strong> menghapus baris. <strong>Peringatan penting:</strong> jangan lupa <code>WHERE</code> — tanpa WHERE, semua baris akan ter-update atau terhapus!</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>update.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql5\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">-- Update data</span>\r\n<span class=\"tok-fn\">UPDATE</span> <span class=\"tok-var\">siswa</span>\r\n<span class=\"tok-kw\">SET</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">95</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">id</span> = <span class=\"tok-num\">1</span>;\r\n\r\n<span class=\"tok-cm\">-- Hapus data</span>\r\n<span class=\"tok-fn\">DELETE FROM</span> <span class=\"tok-var\">siswa</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">id</span> = <span class=\"tok-num\">2</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql5\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Biasakan <strong>SELECT dulu, baru UPDATE/DELETE</strong>. Cek dengan SELECT WHERE untuk memastikan baris yang tepat sebelum mengubah atau menghapus.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-4\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-6\">Lanjut: ORDER &amp; LIMIT →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-6\">\r\n      <div class=\"topic-eyebrow\">TOPIK 6 / 12</div>\r\n      <h2 class=\"topic-title\">ORDER &amp; LIMIT</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>ORDER BY</strong> mengurutkan hasil — <code>ASC</code> (naik) atau <code>DESC</code> (turun). <strong>LIMIT</strong> membatasi jumlah baris yang dikembalikan. <code>OFFSET</code> untuk melompati baris — berguna untuk paginasi.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>order.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql6\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span>\r\n<span class=\"tok-kw\">ORDER BY</span> <span class=\"tok-var\">skor</span> <span class=\"tok-kw\">DESC</span>\r\n<span class=\"tok-kw\">LIMIT</span> <span class=\"tok-num\">3</span> <span class=\"tok-kw\">OFFSET</span> <span class=\"tok-num\">0</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql6\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> <code>LIMIT 10 OFFSET 20</code> = ambil 10 baris, lewati 20 baris pertama. Pola ini standar untuk <em>pagination</em>: halaman 3 dengan 10 item/halaman.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-5\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-7\">Lanjut: JOIN →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-7\">\r\n      <div class=\"topic-eyebrow\">TOPIK 7 / 12</div>\r\n      <h2 class=\"topic-title\">JOIN</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>JOIN</strong> menggabungkan data dari dua tabel berdasarkan kolom yang berhubungan. <code>INNER JOIN</code> hanya mengambil data yang cocok di kedua tabel. <code>LEFT JOIN</code> mengambil semua data dari tabel kiri, meskipun tidak ada pasangan di tabel kanan.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>join.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql7\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">s</span>.<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">m</span>.<span class=\"tok-var\">judul</span>, <span class=\"tok-var\">m</span>.<span class=\"tok-var\">nilai</span>\r\n<span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span> <span class=\"tok-var\">s</span>\r\n<span class=\"tok-kw\">INNER JOIN</span> <span class=\"tok-var\">nilai_modul</span> <span class=\"tok-var\">m</span>\r\n<span class=\"tok-kw\">ON</span> <span class=\"tok-var\">s</span>.<span class=\"tok-var\">id</span> = <span class=\"tok-var\">m</span>.<span class=\"tok-var\">siswa_id</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql7\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Beri <em>alias</em> tabel (<code>siswa s</code>) untuk query yang lebih pendek dan mudah dibaca — terutama saat JOIN banyak tabel.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-6\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-8\">Lanjut: GROUP &amp; Aggregat →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-8\">\r\n      <div class=\"topic-eyebrow\">TOPIK 8 / 12</div>\r\n      <h2 class=\"topic-title\">GROUP &amp; Aggregat</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Aggregate functions</strong>: <code>COUNT()</code>, <code>SUM()</code>, <code>AVG()</code>, <code>MIN()</code>, <code>MAX()</code>. <strong>GROUP BY</strong> mengelompokkan baris untuk perhitungan agregat. <strong>HAVING</strong> memfilter hasil agregat (mirip WHERE untuk GROUP BY).</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>group.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql8\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">m</span>.<span class=\"tok-var\">judul</span>,\r\n    <span class=\"tok-fn\">COUNT</span>(*) <span class=\"tok-kw\">AS</span> <span class=\"tok-var\">peserta</span>,\r\n    <span class=\"tok-fn\">AVG</span>(<span class=\"tok-var\">m</span>.<span class=\"tok-var\">nilai</span>) <span class=\"tok-kw\">AS</span> <span class=\"tok-var\">rata2</span>\r\n<span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">nilai_modul</span> <span class=\"tok-var\">m</span>\r\n<span class=\"tok-kw\">GROUP BY</span> <span class=\"tok-var\">m</span>.<span class=\"tok-var\">judul</span>\r\n<span class=\"tok-kw\">HAVING</span> <span class=\"tok-fn\">COUNT</span>(*) > <span class=\"tok-num\">1</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql8\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Fungsi agregat untuk menghitung rata-rata?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">SUM()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">AVG()</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">COUNT()</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-7\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-9\">Lanjut: Subquery →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-9\">\r\n      <div class=\"topic-eyebrow\">TOPIK 9 / 12</div>\r\n      <h2 class=\"topic-title\">Subquery</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Subquery</strong> (atau inner query / nested query) adalah query SELECT di dalam query lain. Subquery bisa ditempatkan di dalam <code>WHERE</code>, <code>FROM</code>, atau <code>SELECT</code>. Hasil dari subquery dipakai oleh query utama (outer query).</p>\r\n        <p>Subquery di <code>WHERE</code> paling umum: cocok untuk filtering berdasarkan hasil agregat atau data dari tabel lain tanpa JOIN. Subquery harus ditulis di dalam tanda kurung <code>()</code> dan biasanya berjalan lebih dulu sebelum outer query dieksekusi.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>subquery.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql9\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7</div>\r\n          <div class=\"code-content\"><span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">nama</span>, <span class=\"tok-var\">nilai</span>\r\n<span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">nilai_modul</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">nilai</span> > (\r\n  <span class=\"tok-fn\">SELECT</span> <span class=\"tok-fn\">AVG</span>(<span class=\"tok-var\">nilai</span>)\r\n  <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">nilai_modul</span>\r\n);</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql9\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> Subquery juga bisa digunakan dengan operator <code>IN</code>, <code>NOT IN</code>, <code>EXISTS</code>, dan <code>NOT EXISTS</code>. Contoh: <code>WHERE id IN (SELECT siswa_id FROM nilai_modul WHERE nilai > 90)</code>. Hati-hati dengan performa — subquery yang tidak perlu bisa diperbaiki dengan JOIN atau CTE.</div>\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Keyword apa yang bisa dipasangkan dengan subquery untuk mengecek keberadaan baris?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">IN</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">ANY</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">EXISTS</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-8\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-10\">Lanjut: Index →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-10\">\r\n      <div class=\"topic-eyebrow\">TOPIK 10 / 12</div>\r\n      <h2 class=\"topic-title\">Index</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Index</strong> adalah struktur data khusus yang mempercepat pencarian data di tabel tanpa harus memindai seluruh baris (full table scan). Tanpa index, SQLite akan membaca setiap baris satu per satu — lambat untuk tabel besar. Dengan index di kolom yang sering di-<code>WHERE</code>, pencarian bisa berkali-kali lebih cepat.</p>\r\n        <p>Index bekerja seperti indeks buku: langsung menuju halaman yang dicari tanpa membaca seluruh buku. Trade-off: index mempercepat SELECT tetapi sedikit memperlambat INSERT/UPDATE/DELETE karena indeks harus ikut diperbarui.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>index.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql10\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">-- Buat index pada kolom email</span>\r\n<span class=\"tok-fn\">CREATE INDEX</span> <span class=\"tok-var\">idx_email</span>\r\n<span class=\"tok-kw\">ON</span> <span class=\"tok-var\">siswa</span>(<span class=\"tok-var\">email</span>);\r\n\r\n<span class=\"tok-cm\">-- Index gabungan (composite) untuk query lebih spesifik</span>\r\n<span class=\"tok-fn\">CREATE INDEX</span> <span class=\"tok-var\">idx_nama_skor</span>\r\n<span class=\"tok-kw\">ON</span> <span class=\"tok-var\">siswa</span>(<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>);\r\n\r\n<span class=\"tok-cm\">-- Cek semua index di database</span>\r\n<span class=\"tok-fn\">SELECT</span> * <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">sqlite_master</span> <span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">type</span> = <span class=\"tok-str\">\'index\'</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql10\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> Buat index pada kolom yang sering dipakai di <code>WHERE</code>, <code>JOIN</code>, atau <code>ORDER BY</code>. Jangan buat index berlebihan — setiap index menambah waktu pada operasi tulis. Gunakan <code>EXPLAIN QUERY PLAN</code> untuk melihat apakah SQLite sudah memakai index.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Kapan index paling berguna?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Saat INSERT data</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">Saat SELECT dengan WHERE</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">Saat CREATE TABLE</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-9\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-11\">Lanjut: View →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-11\">\r\n      <div class=\"topic-eyebrow\">TOPIK 11 / 12</div>\r\n      <h2 class=\"topic-title\">View</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>View</strong> adalah <em>virtual table</em> — query SELECT yang disimpan dengan nama. View tidak menyimpan data secara fisik, melainkan menyimpan definisi query. Setiap kali view dipanggil, SQLite menjalankan query tersebut dan mengembalikan hasilnya seolah-olah itu tabel biasa.</p>\r\n        <p>Kegunaan View: menyederhanakan query kompleks, menyembunyikan kolom sensitif, dan memberikan abstraksi di atas skema tabel. View dibuat dengan <code>CREATE VIEW nama_view AS SELECT ...</code>. Di SQLite, view bersifat <strong>read-only</strong> secara default — insert/update/delete hanya bisa dilakukan melalui <code>INSTEAD OF</code> trigger pada view.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>view.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql11\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">-- Membuat view untuk daftar nilai siswa</span>\r\n<span class=\"tok-fn\">CREATE VIEW</span> <span class=\"tok-var\">daftar_nilai</span> <span class=\"tok-kw\">AS</span>\r\n<span class=\"tok-fn\">SELECT</span> <span class=\"tok-var\">s</span>.<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">m</span>.<span class=\"tok-var\">judul</span>, <span class=\"tok-var\">m</span>.<span class=\"tok-var\">nilai</span>\r\n<span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">siswa</span> <span class=\"tok-var\">s</span>\r\n<span class=\"tok-kw\">JOIN</span> <span class=\"tok-var\">nilai_modul</span> <span class=\"tok-var\">m</span> <span class=\"tok-kw\">ON</span> <span class=\"tok-var\">s</span>.<span class=\"tok-var\">id</span> = <span class=\"tok-var\">m</span>.<span class=\"tok-var\">siswa_id</span>;\r\n\r\n<span class=\"tok-cm\">-- Pakai view seperti tabel biasa</span>\r\n<span class=\"tok-fn\">SELECT</span> * <span class=\"tok-kw\">FROM</span> <span class=\"tok-var\">daftar_nilai</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">nilai</span> >= <span class=\"tok-num\">85</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql11\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout note\"><strong>Catatan:</strong> View memudahkan <strong>reusability</strong> — tulis query kompleks sekali, pakai berkali-kali. Gunakan <code>DROP VIEW nama_view</code> untuk menghapus view. Beberapa database mendukung <em>materialized view</em> yang menyimpan hasil secara fisik, tapi SQLite tidak — view di SQLite selalu virtual.</div>\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-10\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" data-next=\"sql-12\">Lanjut: Transaction →</button>\r\n      </div>\r\n    </article>\r\n\r\n    <article class=\"topic-section\" data-topic=\"sql-12\">\r\n      <div class=\"topic-eyebrow\">TOPIK 12 / 12</div>\r\n      <h2 class=\"topic-title\">Transaction</h2>\r\n      <div class=\"topic-body\">\r\n        <p><strong>Transaction</strong> adalah kumpulan satu atau lebih operasi SQL yang dieksekusi sebagai satu unit kerja atomic — <em>semua berhasil atau semua batal</em>. Ini adalah fondasi integritas data dalam database relasional. SQLite mendukung transaksi dengan prinsip <strong>ACID</strong>: <strong>A</strong>tomicity (semua atau tidak sama sekali), <strong>C</strong>onsistency (data tetap valid setelah transaksi), <strong>I</strong>solation (transaksi tidak saling mengganggu), dan <strong>D</strong>urability (perubahan tersimpan permanen setelah <code>COMMIT</code>).</p>\r\n        <p>Transaksi dimulai dengan <code>BEGIN TRANSACTION</code> (atau <code>BEGIN</code> saja). Semua perubahan setelahnya hanya terlihat oleh sesi ini sampai <code>COMMIT</code> dijalankan. Jika terjadi kesalahan, <code>ROLLBACK</code> mengembalikan data ke keadaan sebelum transaksi dimulai. SQLite juga mendukung <strong>SAVEPOINT</strong> untuk titik simpan parsial — kamu bisa rollback sebagian transaksi tanpa membatalkan semuanya.</p>\r\n      </div>\r\n\r\n      <div class=\"code-card\">\r\n        <div class=\"code-tab-bar\">\r\n          <div class=\"code-filename\"><span class=\"file-dot\"></span>transaction.sql</div>\r\n          <button class=\"run-btn\" data-run=\"sql12\">▶ Jalankan</button>\r\n        </div>\r\n        <div class=\"code-body\">\r\n          <div class=\"code-lines\">1<br>2<br>3<br>4<br>5<br>6<br>7<br>8<br>9<br>10<br>11<br>12<br>13<br>14<br>15<br>16<br>17</div>\r\n          <div class=\"code-content\"><span class=\"tok-cm\">-- Transaksi 1: COMMIT berhasil</span>\r\n<span class=\"tok-fn\">BEGIN</span> <span class=\"tok-kw\">TRANSACTION</span>;\r\n<span class=\"tok-fn\">INSERT INTO</span> <span class=\"tok-var\">siswa</span>(<span class=\"tok-var\">nama</span>, <span class=\"tok-var\">skor</span>)\r\n<span class=\"tok-kw\">VALUES</span>(<span class=\"tok-str\">\'Dewi\'</span>, <span class=\"tok-num\">85</span>);\r\n<span class=\"tok-fn\">UPDATE</span> <span class=\"tok-var\">siswa</span> <span class=\"tok-kw\">SET</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">90</span>\r\n<span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">nama</span> = <span class=\"tok-str\">\'Dewi\'</span>;\r\n<span class=\"tok-fn\">COMMIT</span>;\r\n\r\n<span class=\"tok-cm\">-- Transaksi 2: ROLLBACK batal</span>\r\n<span class=\"tok-fn\">BEGIN</span>;\r\n<span class=\"tok-fn\">DELETE FROM</span> <span class=\"tok-var\">siswa</span> <span class=\"tok-kw\">WHERE</span> <span class=\"tok-var\">skor</span> < <span class=\"tok-num\">50</span>;\r\n<span class=\"tok-fn\">ROLLBACK</span>;\r\n\r\n<span class=\"tok-cm\">-- SAVEPOINT: rollback parsial</span>\r\n<span class=\"tok-fn\">SAVEPOINT</span> <span class=\"tok-var\">sp1</span>;\r\n<span class=\"tok-fn\">UPDATE</span> <span class=\"tok-var\">siswa</span> <span class=\"tok-kw\">SET</span> <span class=\"tok-var\">skor</span> = <span class=\"tok-num\">100</span>;\r\n<span class=\"tok-fn\">ROLLBACK TO</span> <span class=\"tok-var\">sp1</span>;</div>\r\n        </div>\r\n        <div class=\"output-bar\">\r\n          <div class=\"output-label\">OUTPUT (terminal)</div>\r\n          <div class=\"output-content\" id=\"out-sql12\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"callout tip\"><strong>Tips:</strong> SQLite menjalankan setiap perintah dalam mode auto-commit secara default. Untuk mengelompokkan beberapa perintah, gunakan <code>BEGIN</code> eksplisit. <code>SAVEPOINT</code> memungkinkan rollback sebagian — panggil <code>RELEASE SAVEPOINT nama</code> untuk mengonfirmasi atau <code>ROLLBACK TO SAVEPOINT nama</code> untuk membatalkan perubahan setelah titik tertentu.</div>\r\n\r\n      <div class=\"quiz-box\">\r\n        <div class=\"quiz-q\">Quiz: Perintah untuk membatalkan semua perubahan dalam transaksi?</div>\r\n        <div class=\"quiz-opts\">\r\n          <button class=\"quiz-opt\" data-correct=\"false\">COMMIT</button>\r\n          <button class=\"quiz-opt\" data-correct=\"false\">UNDO</button>\r\n          <button class=\"quiz-opt\" data-correct=\"true\">ROLLBACK</button>\r\n        </div>\r\n        <div class=\"quiz-feedback\"></div>\r\n      </div>\r\n\r\n      <div class=\"topic-nav\">\r\n        <button class=\"nav-btn\" data-prev=\"sql-11\">← Sebelumnya</button>\r\n        <button class=\"nav-btn primary\" type=\"button\" id=\"finishBtn\">Semua modul selesai — Kembali ke Library 🎉</button>\r\n      </div>\r\n    </article>\r\n  </section>\r\n\r\n</main>\r\n\r\n<script>\r\n(function() {\r\n  const totalTopics = 12;\r\n  const LANGUAGE = \'sql\'; // harus sama dengan key di $languages pada get_progress.php\r\n  const completed = new Set();\r\n  let celebrated = false;\r\n\r\n  const langTabs = document.querySelectorAll(\'.lang-tab\');\r\n  const contentPanels = document.querySelectorAll(\'.content-panel\');\r\n\r\n  function setActiveTopic(topicId) {\r\n    const lang = topicId.split(\'-\')[0];\r\n\r\n    langTabs.forEach(t => t.classList.toggle(\'active\', t.dataset.lang === lang));\r\n    contentPanels.forEach(p => p.classList.toggle(\'active\', p.dataset.lang === lang));\r\n\r\n    document.querySelectorAll(\'.topic-section\').forEach(s => {\r\n      s.classList.toggle(\'active\', s.dataset.topic === topicId);\r\n    });\r\n    document.querySelectorAll(\'.topic-item\').forEach(t => {\r\n      t.classList.toggle(\'active\', t.dataset.topic === topicId);\r\n    });\r\n\r\n    markDone(topicId);\r\n  }\r\n\r\n  function markDone(topicId, persist = true) {\r\n    if (completed.has(topicId)) return;\r\n    completed.add(topicId);\r\n    const item = document.querySelector(`.topic-item[data-topic=\"${topicId}\"]`);\r\n    if (item) item.classList.add(\'done\');\r\n    updateProgress();\r\n    if (persist) saveProgress(topicId);\r\n  }\r\n\r\n  async function saveProgress(topicId) {\r\n    try {\r\n      const res = await fetch(\'../save_progress.php\', {\r\n        method: \'POST\',\r\n        headers: { \'Content-Type\': \'application/json\' },\r\n        body: JSON.stringify({ language: LANGUAGE, topic_id: topicId })\r\n      });\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'save_progress.php gagal, status:\', res.status);\r\n      }\r\n    } catch (err) {\r\n      console.error(\'Gagal menyimpan progres ke server:\', err);\r\n    }\r\n  }\r\n\r\n  async function loadProgress() {\r\n    try {\r\n      const res = await fetch(`../get_progress.php?language=${LANGUAGE}`);\r\n      if (res.status === 401) {\r\n        window.location.href = \'../auth.html\';\r\n        return;\r\n      }\r\n      if (!res.ok) {\r\n        console.error(\'get_progress.php gagal, status:\', res.status);\r\n        return;\r\n      }\r\n      const data = await res.json();\r\n      (data.completed_topics || []).forEach(topicId => markDone(topicId, false));\r\n    } catch (err) {\r\n      console.error(\'Gagal memuat progres dari server:\', err);\r\n    }\r\n  }\r\n\r\n  function updateProgress() {\r\n    const pct = Math.round((completed.size / totalTopics) * 100);\r\n    document.getElementById(\'progressFill\').style.width = pct + \'%\';\r\n    document.getElementById(\'progressNum\').textContent = `${completed.size} / ${totalTopics} topik selesai`;\r\n\r\n    const items = document.querySelectorAll(\'.topic-item\');\r\n    const done = [...items].filter(i => i.classList.contains(\'done\')).length;\r\n    const langPct = Math.round((done / items.length) * 100);\r\n    const pctEl = document.querySelector(\'.lang-tab-pct\');\r\n    if (pctEl) pctEl.textContent = langPct + \'%\';\r\n\r\n    if (!celebrated && completed.size >= totalTopics) {\r\n      celebrated = true;\r\n      showCompletionAlert();\r\n    }\r\n  }\r\n\r\n  function showCompletionAlert() {\r\n    const overlay = document.createElement(\'div\');\r\n    overlay.className = \'completion-overlay\';\r\n    overlay.innerHTML = `\r\n      <div class=\"completion-modal\">\r\n        <div class=\"completion-emoji\">🎉</div>\r\n        <h2>Selamat!</h2>\r\n        <p>Kamu sudah menyelesaikan semua topik di modul ini. Progres kamu sudah tersimpan.</p>\r\n        <div class=\"completion-actions\">\r\n          <button class=\"nav-btn\" id=\"completionStayBtn\" type=\"button\">Tinjau lagi materinya</button>\r\n          <button class=\"nav-btn primary\" id=\"completionLibraryBtn\" type=\"button\">Kembali ke Library</button>\r\n        </div>\r\n      </div>`;\r\n    document.body.appendChild(overlay);\r\n    document.getElementById(\'completionStayBtn\').addEventListener(\'click\', () => overlay.remove());\r\n    document.getElementById(\'completionLibraryBtn\').addEventListener(\'click\', () => {\r\n      window.location.href = \'../library.html\';\r\n    });\r\n    overlay.addEventListener(\'click\', (e) => {\r\n      if (e.target === overlay) overlay.remove();\r\n    });\r\n  }\r\n\r\n  document.querySelectorAll(\'.topic-item\').forEach(item => {\r\n    item.addEventListener(\'click\', () => setActiveTopic(item.dataset.topic));\r\n  });\r\n\r\n  document.querySelectorAll(\'[data-next]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.next));\r\n  });\r\n  document.querySelectorAll(\'[data-prev]\').forEach(btn => {\r\n    btn.addEventListener(\'click\', () => setActiveTopic(btn.dataset.prev));\r\n  });\r\n\r\n  const finishBtn = document.getElementById(\'finishBtn\');\r\n  if (finishBtn) {\r\n    finishBtn.addEventListener(\'click\', () => {\r\n      showCompletionAlert();\r\n    });\r\n  }\r\n\r\n\r\n  // ===== Quiz interactivity =====\r\n  document.querySelectorAll(\'.quiz-box\').forEach(box => {\r\n    const opts = box.querySelectorAll(\'.quiz-opt\');\r\n    const feedback = box.querySelector(\'.quiz-feedback\');\r\n    opts.forEach(opt => {\r\n      opt.addEventListener(\'click\', () => {\r\n        opts.forEach(o => o.disabled = true);\r\n        const correct = opt.dataset.correct === \'true\';\r\n        opt.classList.add(correct ? \'correct\' : \'wrong\');\r\n        if (!correct) {\r\n          const correctOpt = [...opts].find(o => o.dataset.correct === \'true\');\r\n          if (correctOpt) correctOpt.classList.add(\'correct\');\r\n          feedback.textContent = \'Belum tepat — jawaban yang benar sudah ditandai hijau di atas.\';\r\n          feedback.className = \'quiz-feedback wrong-text\';\r\n        } else {\r\n          feedback.textContent = \'Tepat sekali! 🎉\';\r\n          feedback.className = \'quiz-feedback correct-text\';\r\n        }\r\n      });\r\n    });\r\n  });\r\n\r\n  // Muat progres yang sudah tersimpan di server, baru tandai topik pertama sebagai \"dikunjungi\"\r\n  loadProgress().then(() => markDone(\'sql-1\'));\r\n\r\n  // ===== Sidebar toggle =====\r\n  const sidebar = document.getElementById(\'sidebar\');\r\n  const toggleBtn = document.getElementById(\'sidebarToggle\');\r\n  const mainEl = document.querySelector(\'.main\');\r\n\r\n  // Sinkronkan ikon/posisi tombol dengan kondisi sidebar saat halaman dimuat\r\n  toggleBtn.classList.toggle(\'pushed\', !sidebar.classList.contains(\'hidden\'));\r\n  toggleBtn.textContent = sidebar.classList.contains(\'hidden\') ? \'☰\' : \'✕\';\r\n\r\n  toggleBtn.addEventListener(\'click\', () => {\r\n    const hidden = sidebar.classList.toggle(\'hidden\');\r\n    mainEl.classList.toggle(\'expanded\', hidden);\r\n    toggleBtn.classList.toggle(\'pushed\', !hidden);\r\n    toggleBtn.textContent = hidden ? \'☰\' : \'✕\';\r\n  });\r\n})();\r\n</script>\r\n\r\n</body>\r\n</html>', '#264DE4', NULL, '2026-07-03 13:09:45', '2026-07-04 18:25:44');

